window.ADRIVE_THEME_DATA=window.ADRIVE_THEME_DATA||{};window.ADRIVE_THEME_DATA[1]=[{"id":100100101,"themeId":1,"group":1001001,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «автопоезд»?","a":["Колёсный трактор, буксирующий прицеп.","Эвакуатор, буксирующий на жёсткой сцепке неисправный автомобиль.","Велосипед, буксирующий велосипедный прицеп промышленного производства."],"c":0,"e":"<p>Автопоездом является состав транспортных средств, состоящий из автомобиля или колёсного трактора и буксируемого прицепа.</p>","image":null},{"id":100100102,"themeId":1,"group":1001001,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного не соответствует термину «автопоезд»?","a":["Колёсный трактор, буксирующий полуприцеп.","Грузовой автомобиль, буксирующий прицеп-роспуск.","Легковой автомобиль, буксирующий одноосный прицеп.","Мопед, буксирующий велосипедный прицеп промышленного производства."],"c":3,"e":"<p>Мопед, буксирующий прицеп, не является автопоездом, потому что тягачом в составе автопоезда может быть либо автомобиль, либо колёсный трактор.</p>","image":null},{"id":100100103,"themeId":1,"group":1001001,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного не соответствует термину «автопоезд»?","a":["Грузовой автомобиль, буксирующий одноосный прицеп.","Легковой автомобиль, буксирующий прицеп массой более 550 килограммов.","Легковой автомобиль, буксирующий прицеп массой не более 550 килограммов.","Велосипед, буксирующий велосипедный прицеп промышленного производства."],"c":3,"e":"<p>Велосипед, буксирующий прицеп, не является автопоездом, потому что тягачом в составе автопоезда может быть либо автомобиль, либо колёсный трактор.</p>","image":null},{"id":100100201,"themeId":1,"group":1001002,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «велосипед»?","a":["Средство персональной мобильности.","Мопед с выключенным двигателем, который пешеход ведёт по дороге.","Инвалидная коляска, приводимая в движение мускульной силой человека, находящегося в ней.","Трёхколёсное транспортное средство, приводимое в движение с помощью педалей мускульной силой человека, находящегося на (в) нём."],"c":3,"e":"<p>Трёхколёсное транспортное средство, приводимое в движение с помощью педалей мускульной силой человека, находящегося на (в) нём, соответствует термину «велосипед», в отличие от остальных предложенных вариантов.</p>","image":null},{"id":100100202,"themeId":1,"group":1001002,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного не соответствует термину «велосипед»?","a":["Роликовые коньки.","Инвалидная коляска, приводимая в движение электродвигателем.","Не соответствует всё перечисленное."],"c":2,"e":"<p>Велосипед — это транспортное средство, которое приводится в движение мускульной силой человека (людей), находящегося на (в) нём, в частности при помощи педалей или рукояток.<br> К велосипеду приравниваются аналогичные по конструкции транспортные средства, имеющие электродвигатель номинальной максимальной мощностью в режиме длительной нагрузки, не превышающей 0.25 кВт, и (или) максимальную конструктивную скорость движения, определённую его технической характеристикой, не более 25 км/ч либо иной двигатель с аналогичной характеристикой.</p> <p>Роликовые коньки и инвалидная коляска не являются транспортными средствами, а лица, передвигающиеся с помощью перечисленных устройств, являются пешеходами.</p>","image":null},{"id":100100203,"themeId":1,"group":1001002,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «велосипед»?","a":["Двухколёсное транспортное средство, приводимое в движение мускульной силой человека, находящегося на нём.","Трёхколёсное двухместное транспортное средство, приводимое в движение мускульной силой одного человека, находящегося в нём.","Соответствуют оба варианта ответа."],"c":2,"e":"<p> Велосипед — транспортное средство, за исключением инвалидных колясок, которое имеет не менее двух (точное количество не оговаривается) колёс и приводится в движение мускульной силой человека (людей), находящегося на (в) нём, в частности при помощи педалей или рукояток.</p>","image":null},{"id":100100301,"themeId":1,"group":1001003,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «видимость дороги»?","a":["Максимальное расстояние, на котором с места водителя можно распознать пешехода.","Минимальное расстояние, на котором с места водителя можно увидеть «стоп-линию».","Максимальное расстояние в направлении движения, на котором с места водителя можно распознать количество проезжих частей на дороге.","Максимальное расстояние вправо от направления движения, на котором можно распознать транспортные средства, приближающиеся к перекрёстку по главной дороге."],"c":2,"e":"<p>Видимость дороги — это максимальное расстояние в направлении движения, на котором с места водителя можно распознать элементы дороги и технические средства организации дорожного движения, а минимальное расстояние видимости «стоп-линии» обусловлено обзорностью с места водителя вперёд–вниз, ограниченной конструкцией автомобиля.</p>","image":null},{"id":100100401,"themeId":1,"group":1001004,"chapter":1,"chapters":[1],"q":"Кто из перечисленных лиц является водителем?","a":["Физическое лицо, обучаемое управлению транспортным средством в момент сдачи квалификационного практического экзамена на автодроме.","Физическое лицо, управляющее транспортным средством, включая лицо, обучаемое управлению механическим транспортным средством (сдающее квалификационный практический экзамен на право управления механическим транспортным средством).","Физическое лицо, управляющее транспортным средством, за исключением лица, обучаемого управлению механическим транспортным средством (сдающего квалификационный практический экзамен на право управления механическим транспортным средством)."],"c":2,"e":"<p>Лицо, обучаемое управлению механическим транспортным средством, не является водителем даже при управлении транспортным средством. В таких случаях водителем является лицо, обучающее управлению механическим транспортным средством, и при этом находящееся в нём.</p>","image":"assets/adrive-questions/q100100401.jpg"},{"id":100100402,"themeId":1,"group":1001004,"chapter":1,"chapters":[1],"q":"Кто из перечисленных лиц не является водителем?","a":["Всадник.","Велосипедист.","Лицо, управляющее гужевым транспортным средством.","Лицо, передвигающееся в инвалидной коляске."],"c":3,"e":"<p>Лицо, передвигающееся в инвалидной коляске, является пешеходом, а не водителем. В остальных вариантах ответов перечислены лица, управляющие транспортными средствами, и лицо, приравненное к водителю (всадник).</p>","image":null},{"id":100100403,"themeId":1,"group":1001004,"chapter":1,"chapters":[1],"q":"Следует ли считать водителем лицо, обучающее управлению механическим транспортным средством?","a":["Да, при его нахождении в транспортном средстве.","Да, при его нахождении вне транспортного средства на автодроме.","Да, в обоих случаях."],"c":0,"e":"<p>Лицо, обучающее управлению механическим транспортным средством, считается водителем только при нахождении в транспортном средстве.</p>","image":null},{"id":100100404,"themeId":1,"group":1001004,"chapter":1,"chapters":[1],"q":"Кого следует считать водителем?","a":["Лицо, обучаемое управлению механическим транспортным средством.","Лицо, обучающее управлению механическим транспортным средством и при этом находящееся в нём.","Лицо, обучающее управлению механическим транспортным средством и при этом не находящееся в нём.","Лицо, сдающее квалификационный практический экзамен на право управления механическим транспортным средством.","Все перечисленные считаются водителями."],"c":1,"e":"<p>Лицо, обучающее управлению механическим транспортным средством, считается водителем только при нахождении в транспортном средстве. Лицо, обучаемое управлению механическим транспортным средством, водителем не является.</p>","image":null},{"id":100100501,"themeId":1,"group":1001005,"chapter":1,"chapters":[1],"q":"В каком случае лицо, обучаемое управлению механическим транспортным средством, является водителем?","a":["При обучении управлению колёсным трактором.","При проведении администрацией учебной организации контроля за обучением управлению механическим транспортным средством.","При сдаче квалификационного практического экзамена на право управления механическим транспортным средством.","Не является в любом из перечисленных случаев."],"c":3,"e":"<p>Лицо, обучаемое управлению механическим транспортным средством, водителем не является.</p>","image":null},{"id":100100502,"themeId":1,"group":1001005,"chapter":1,"chapters":[1],"q":"Является ли лицо, обучаемое управлению механическим транспортным средством, водителем?","a":["Да, при обучении вождению по дорогам общего пользования.","Да, когда обучаемое лицо причастно к управлению механическим транспортным средством.","Не является в любом из перечисленных случаев."],"c":2,"e":"<p>Лицо, обучаемое управлению механическим транспортным средством, самоходной машиной (сдающее квалификационный практический экзамен на право управления механическим транспортным средством, самоходной машиной), согласно Правилам дорожного движения не является водителем.</p>","image":"assets/adrive-questions/q100100502.jpg"},{"id":100100503,"themeId":1,"group":1001005,"chapter":1,"chapters":[1],"q":"К какому участнику дорожного движения приравнивается физическое лицо, ведущее лошадь?","a":["К водителю.","К пешеходу."],"c":0,"e":"<p>К водителю приравниваются всадник, погонщик скота.</p>","image":"assets/adrive-questions/q100100503.jpg"},{"id":100100541,"themeId":1,"group":1001005,"chapter":1,"chapters":[1],"q":"Пешеход станет водителем, если воспользуется для дальнейшего передвижения:","a":["Велосипедом.","Средством персональной мобильности (электросамокатом).","Любым из представленных устройств."],"c":2,"e":"<p>Водитель — это физическое лицо, управляющее транспортным средством.</p> <p>И велосипед, и средство персональной мобильности являются транспортными средствами.</p>","image":"assets/adrive-questions/q100100541.jpg"},{"id":100100601,"themeId":1,"group":1001006,"chapter":1,"chapters":[1],"q":"Какие из показанных транспортных средств являются автомобилями?","a":["А и Б.","Б и В.","Только А.","Только Б.","Все изображённые транспортные средства."],"c":0,"e":"<p>Грузовой автомобиль и автобус являются автомобилями, а мотоцикл даже с боковым прицепом автомобилем не является. Автомобиль имеет не менее четырёх колёс, расположенных не менее чем на двух осях.</p>","image":"assets/adrive-questions/q100100601.jpg"},{"id":100100602,"themeId":1,"group":1001006,"chapter":1,"chapters":[1],"q":"Является ли автомобиль с числом мест для сидения равным десяти (включая место водителя) автобусом?","a":["Да, является.","Нет, не является."],"c":0,"e":"<p>Автомобиль с числом мест более девяти, включая место водителя, является автобусом. Для управления таким транспортным средством необходимо водительское удостоверение категории «D».</p>","image":null},{"id":100100603,"themeId":1,"group":1001006,"chapter":1,"chapters":[1],"q":"В каком случае квадрициклы (мотоколяски) приравниваются к автомобилям?","a":["Если имеют четыре колеса.","Если имеют приводы управления автомобильного типа.","Если имеют массу в снаряжённом состоянии не более 550 килограммов.","Только если выполняются все перечисленные условия."],"c":3,"e":"<p>К автомобилям приравниваются квадрициклы (мотоколяски) — четырёхколёсные механические транспортные средства, имеющие приводы управления автомобильного типа и массу в снаряжённом состоянии не более 550 килограммов.</p>","image":"assets/adrive-questions/q100100603.jpg"},{"id":100100604,"themeId":1,"group":1001006,"chapter":1,"chapters":[1],"q":"Какие из показанных транспортных средств являются автомобилями?","a":["Только транспортное средство, обозначенное буквой «А».","Только транспортное средство, обозначенное буквой «Б».","Все показанные транспортные средства.","Все показанные транспортные средства не являются автомобилями."],"c":2,"e":"<p>Автомобилем считается любое механическое транспортное средство, имеющее не менее четырёх колёс, расположенных не менее чем на двух осях, за исключением колёсных тракторов и самоходных машин.</p> <p>Поэтому оба изображённых транспортных средства являются автомобилями.</p>","image":"assets/adrive-questions/q100100604.jpg"},{"id":100100701,"themeId":1,"group":1001007,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного является велосипедной дорожкой согласно Правилам дорожного движения?","a":["Только элемент дороги, выделенный конструктивно, предназначенный для движения велосипедистов и водителей средств персональной мобильности, обозначенный дорожным знаком «Велосипедная и пешеходная дорожка».","Только элемент дороги, выделенный с помощью линий горизонтальной дорожной разметки, предназначенный для движения велосипедистов и водителей средств персональной мобильности, обозначенный дорожным знаком «Велосипедная дорожка».","Только обособленная дорога, предназначенная для движения велосипедистов и водителей средств персональной мобильности, обозначенная дорожным знаком «Велосипедная дорожка».","Всё перечисленное."],"c":3,"e":"<p>Велосипедная дорожка может быть как обособленной дорогой, так и элементом дороги, который может быть выделен конструктивно либо при помощи линий горизонтальной дорожной разметки.</p> <p>Если велосипедная дорожка отделена от проезжей части дороги только при помощи линий горизонтальной дорожной разметки, водители механических транспортных средств на таком участке дороги должны быть очень внимательны и принимать все меры, обеспечивающие безопасные условия движения велосипедистов и пешеходов.</p>","image":null},{"id":100100703,"themeId":1,"group":1001007,"chapter":1,"chapters":[1],"q":"Является ли показанная территория жилой зоной?","a":["Да, является.","Является только при наличии знака «Жилая зона».","Нет, не является."],"c":0,"e":"<p>Жилой зоной является не только территория, обозначенная соответствующими дорожными знаками, но и любая дворовая территория, прилегающая к жилой застройке.</p>","image":"assets/adrive-questions/q100100703.jpg"},{"id":100100741,"themeId":1,"group":1001007,"chapter":1,"chapters":[1],"q":"Показанная велосипедная дорожка предназначена для движения:","a":["Только велосипедистов.","Велосипедистов и водителей средств персональной мобильности."],"c":1,"e":"<p>Велосипедная дорожка предназначена для движения водителей велосипедов и средств персональной мобильности.</p>","image":"assets/adrive-questions/q100100741.jpg"},{"id":100100772,"themeId":1,"group":1001007,"chapter":1,"chapters":[1],"q":"Какая из перечисленных территорий соответствует определению «жилая зона»?","a":["Территория дачного кооператива.","Территория сельскохозяйственного кооператива.","Все перечисленные территории соответствуют."],"c":0,"e":"<p><strong>Территория дачного кооператива считается жилой зоной</strong> ввиду отсутствия элементов для движения пешеходов (тротуаров, пешеходных дорожек, обочин) и из-за узких проездов для транспортных средств между дачными участками.</p>","image":null},{"id":100100773,"themeId":1,"group":1001007,"chapter":1,"chapters":[1],"q":"Какие из перечисленных территорий соответствуют определению «жилая зона»?","a":["Территория дачного кооператива.","Территория садоводческого товарищества.","Все перечисленные территории соответствуют."],"c":2,"e":"<p><strong>Территории дачного кооператива и садового товарищества считаются жилой зоной</strong> ввиду отсутствия элементов для движения пешеходов (тротуаров, пешеходных дорожек, обочин) и из-за узких проездов для транспортных средств между дачными и садовыми участками.</p>","image":null},{"id":100100801,"themeId":1,"group":1001008,"chapter":1,"chapters":[1],"q":"Кто из нижеперечисленных лиц является водителем?","a":["Физическое лицо, обучаемое управлению самоходной машиной.","Физическое лицо, принимающее квалификационный практический экзамен на право управления механическим транспортным средством и при этом находящееся в нём.","Физическое лицо, принимающее квалификационный практический экзамен на право управления механическим транспортным средством и при этом не находящееся в нём."],"c":1,"e":"<p>Физическое лицо, принимающее квалификационный практический экзамен на право управления механическим транспортным средством, приравнивается к водителю только при нахождении в транспортном средстве, а лицо, обучаемое управлению, водителем не является.</p>","image":null},{"id":100100802,"themeId":1,"group":1001008,"chapter":1,"chapters":[1],"q":"Кто из нижеперечисленных лиц является водителем?","a":["Физическое лицо, обучаемое управлению механическим транспортным средством.","Физическое лицо, обучающее управлению механическим транспортным средством и при этом находящееся в нём.","Физическое лицо, обучающее управлению механическим транспортным средством и при этом не находящееся в нём.","Физическое лицо, принимающее квалификационный практический экзамен на право управления механическим транспортным средством и при этом не находящееся в нём."],"c":1,"e":"<p>Физическое лицо, обучающее управлению механическим транспортным средством или принимающее квалификационный практический экзамен на право управления таким средством, приравнивается к водителю только при нахождении в транспортном средстве, а лицо, обучаемое управлению, водителем не является.</p>","image":null},{"id":100100803,"themeId":1,"group":1001008,"chapter":1,"chapters":[1],"q":"Какие из нижеперечисленных лиц являются водителями?","a":["Погонщик скота.","Физическое лицо, управляющее самоходной машиной.","Физическое лицо, принимающее квалификационный практический экзамен на право управления механическим транспортным средством и при этом находящееся в нём.","Все вышеперечисленные."],"c":3,"e":"<p>Физическое лицо, обучающее управлению механическим транспортным средством или принимающее квалификационный практический экзамен на право управления таким средством, приравнивается к водителю при нахождении в транспортном средстве, также к водителям приравниваются всадники и погонщики скота.</p>","image":"assets/adrive-questions/q100100803.jpg"},{"id":100100901,"themeId":1,"group":1001009,"chapter":1,"chapters":[1],"q":"В каком из перечисленных случаев водитель совершил вынужденную остановку?","a":["Остановился на обочине из-за прокола колеса.","Остановился у тротуара при появившемся стуке в подвеске правого колеса.","Остановился в полосе движения из-за ослепления фарами встречного автомобиля.","Во всех перечисленных случаях."],"c":3,"e":"<p>Любое прекращение движения, вызванное технической неисправностью, а также опасностью для движения (в том числе из-за состояния водителя), является вынужденной остановкой транспортного средства.</p>","image":null},{"id":100100902,"themeId":1,"group":1001009,"chapter":1,"chapters":[1],"q":"В каком из перечисленных случаев водитель совершил вынужденную остановку?","a":["Остановился у тротуара для того, чтобы купить газету.","Остановился у тротуара для того, чтобы уточнить дорогу у прохожих.","Остановился у тротуара, чтобы устранить опасное для движения смещение перевозимого груза.","Водитель не совершил вынужденную остановку ни в одном из перечисленных случаев."],"c":2,"e":"<p>В перечисленных вариантах ответов опасность для движения появилась только в случае смещения перевозимого груза, в остальных случаях ни опасности для движения, ни препятствия для движения нет, следовательно — остальные перечисленные случае не являются вынужденной остановкой.</p>","image":null},{"id":100100903,"themeId":1,"group":1001009,"chapter":1,"chapters":[1],"q":"Водитель прекратил движение из-за того, что его ослепило заходящее солнце. Совершил ли он при этом вынужденную остановку?","a":["Да.","Нет."],"c":0,"e":"<p>Прекращение движения из-за опасности для движения, создаваемой состоянием водителя, является вынужденной остановкой транспортного средства.</p>","image":null},{"id":100101001,"themeId":1,"group":1001010,"chapter":1,"chapters":[1],"q":"Какому из нижеперечисленных условий соответствует термин «вынужденная остановка транспортного средства»?","a":["Прекращение движения водителем такси для посадки пассажира.","Прекращение движения ввиду того, что пассажир потерял сознание.","Преднамеренное прекращение движения с целью высадки пассажиров.","Преднамеренное прекращение движения с целью разгрузки транспортного средства."],"c":1,"e":"<p>Прекращение движения из-за опасности, создаваемой состоянием пассажира, является вынужденной остановкой транспортного средства.</p>","image":null},{"id":100101002,"themeId":1,"group":1001010,"chapter":1,"chapters":[1],"q":"Какому из нижеперечисленных условий соответствует термин «вынужденная остановка транспортного средства»?","a":["Прекращение движения из-за перегрева двигателя.","Прекращение движения по требованию сотрудника ГАИ.","Прекращение движения в соответствии с требованием «уступить дорогу».","Прекращение движения из-за закрытого шлагбаума на железнодорожном переезде."],"c":0,"e":"<p>Любое прекращение движения, вызванное технической неисправностью, является вынужденной остановкой транспортного средства. В остальных перечисленных случаях опасность для движения отсутствует, а прекращение движения обусловлено выполнением требований Правил дорожного движения.</p>","image":null},{"id":100101003,"themeId":1,"group":1001010,"chapter":1,"chapters":[1],"q":"Какому из нижеперечисленных условий соответствует термин «вынужденная остановка транспортного средства»?","a":["Прекращение движения по требованию регулировщика.","Прекращение движения на запрещающий сигнал светофора.","Прекращение движения из-за лежащего на проезжей части дороги пешехода.","Прекращение движения перед пешеходным переходом, чтобы предоставить преимущество пешеходам."],"c":2,"e":"<p>Лежащий на проезжей части пешеход создаёт опасность для движения и является препятствием для движения. В остальных перечисленных случаях опасность для движения отсутствует, а прекращение движения обусловлено выполнением требований Правил дорожного движения.</p>","image":null},{"id":100101101,"themeId":1,"group":1001011,"chapter":1,"chapters":[1],"q":"Какие транспортные средства находятся на главной дороге?","a":["Только автобус.","Только грузовой автомобиль.","Легковой автомобиль и автобус.","Транспортные средства находятся перед перекрёстком равнозначных дорог."],"c":3,"e":"<p>Перед перекрёстком отсутствуют дорожные знаки приоритета, покрытие дорог — одинаковое, следовательно, такой перекрёсток считается перекрёстком равнозначных дорог. Наличие на одной из дорог трамвайных путей или большего количества полос движения не делает такую дорогу главной по отношению к другим дорогам.</p>","image":"assets/adrive-questions/q100101101.jpg"},{"id":100101102,"themeId":1,"group":1001011,"chapter":1,"chapters":[1],"q":"Какие транспортные средства находятся на главной дороге?","a":["Только грузовой автомобиль.","Только легковой автомобиль.","Грузовой автомобиль и автобус.","Легковой и грузовой автомобили."],"c":2,"e":"<p>Дорога, на которой находятся грузовой автомобиль и автобус, обозначена дорожным знаком 2.1 «Главная дорога» , поэтому перечисленные транспортные средства находятся на главной дороге.</p>","image":"assets/adrive-questions/q100101102.jpg"},{"id":100101103,"themeId":1,"group":1001011,"chapter":1,"chapters":[1],"q":"Какие транспортные средства находятся на главной дороге?","a":["Только автобус.","Только легковой автомобиль.","Легковой автомобиль и автобус.","Легковой и грузовой автомобили."],"c":2,"e":"<p>Дорога, на которой находятся легковой автомобиль и автобус, обозначена дорожным знаком 2.1 «Главная дорога» , поэтому перечисленные транспортные средства находятся на главной дороге.</p>","image":"assets/adrive-questions/q100101103.jpg"},{"id":100101161,"themeId":1,"group":1001011,"chapter":1,"chapters":[1],"q":"В показанной ситуации Вы:","a":["Находитесь на главной дороге.","Находитесь на второстепенной дороге.","Подъехали к перекрёстку равнозначных дорог."],"c":0,"e":"<p>Перед перекрёстком с показанного направления установлен дорожный знак \"Главная дорога\", следовательно Вы находитесь на главной дороге.</p>","image":"assets/adrive-questions/q100101161.jpg"},{"id":100101201,"themeId":1,"group":1001012,"chapter":1,"chapters":[1],"q":"Какая из перечисленных ситуаций соответствует термину «дорожно-транспортное происшествие»?","a":["Столкновение двух велосипедов, в результате которого один велосипед был повреждён.","Наезд гужевой повозки на пешехода, в результате которого пешеход получил лёгкие телесные повреждения.","Наезд велосипеда на гужевую повозку, в результате которого велосипедист получил лёгкие телесные повреждения.","Наезд мопеда на пешехода, в результате которого пешеход получил менее тяжкие телесные повреждения."],"c":3,"e":"<p>ДТП — происшествие, совершённое с участием хотя бы одного находившегося в движении механического транспортного средства…<br> Велосипед и гужевое транспортное средство <strong>не являются механическими</strong>, а мопед — это механическое транспортное средство.</p>","image":null},{"id":100101202,"themeId":1,"group":1001012,"chapter":1,"chapters":[1],"q":"Какая из перечисленных ситуаций не соответствует термину «дорожно-транспортное происшествие»?","a":["Опрокидывание легкового автомобиля, в результате которого автомобиль был повреждён.","Наезд легкового автомобиля на препятствие, в результате которого водитель получил лёгкие телесные повреждения.","Наезд велосипеда на стоящий автомобиль, в результате которого велосипедист получил лёгкие телесные повреждения.","Наезд на препятствие в результате заноса грузового автомобиля, в результате которого было повреждено ограждение дворовой территории в частном секторе."],"c":2,"e":"<p>ДТП — происшествие, совершённое с участием хотя бы одного находившегося в движении механического транспортного средства…<br> <strong>Велосипед не является механическим транспортным средством</strong>, а автомобиль на момент совершения происшествия не находился в движении.</p>","image":null},{"id":100101204,"themeId":1,"group":1001012,"chapter":1,"chapters":[1],"q":"Дорожно-транспортное происшествие — это:","a":["Столкновение двух автомобилей на перекрёстке, в результате которого оба автомобиля были повреждены.","Наезд движущегося автомобиля при парковке на стоящий автомобиль, в результате которого повреждения получил только стоящий автомобиль.","Оба перечисленных случая."],"c":2,"e":"<p>ДТП — происшествие, совершённое с участием хотя бы одного находившегося в движении механического транспортного средства, поэтому оба перечисленных случая являются дорожно-транспортным происшествием.</p>","image":null},{"id":100101301,"themeId":1,"group":1001013,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «автомобиль»?","a":["Механическое транспортное средство, имеющее не менее четырёх колёс, расположенных не менее чем на двух осях, включая колёсные тракторы и самоходные машины.","Механическое транспортное средство, имеющее не менее четырёх колёс, расположенных не менее чем на двух осях, за исключением колёсных тракторов и самоходных машин."],"c":1,"e":"<p>Автомобилем является любое механическое транспортное средство, имеющее не менее четырёх колёс, расположенных не менее чем на двух осях, за исключением колёсных тракторов и самоходных машин.</p>","image":"assets/adrive-questions/q100101301.jpg"},{"id":100101302,"themeId":1,"group":1001013,"chapter":1,"chapters":[1],"q":"Соответствуют ли колёсные тракторы термину «автомобиль»?","a":["Соответствуют при участии в дорожном движении.","Не соответствуют."],"c":1,"e":"<p>Автомобилем является любое механическое транспортное средство, имеющее не менее четырёх колёс, расположенных не менее чем на двух осях, за исключением колёсных тракторов и самоходных машин.</p>","image":"assets/adrive-questions/q100101302.jpg"},{"id":100101303,"themeId":1,"group":1001013,"chapter":1,"chapters":[1],"q":"Соответствуют ли самоходные машины термину «автомобиль»?","a":["Соответствуют при участии в дорожном движении.","Не соответствуют."],"c":1,"e":"<p>Автомобилем является любое механическое транспортное средство, имеющее не менее четырёх колёс, расположенных не менее чем на двух осях, за исключением колёсных тракторов и самоходных машин.</p>","image":"assets/adrive-questions/q100101303.jpg"},{"id":100101304,"themeId":1,"group":1001013,"chapter":1,"chapters":[1],"q":"Приравнивается ли самоходная машина к транспортным средствам при её участии в дорожном движении?","a":["Да, приравнивается.","Нет, не приравнивается."],"c":0,"e":"<p>При участии в дорожном движении самоходные машины приравниваются к транспортным средствам, а их движение по дорогам должно осуществляться в соответствии с требованиями настоящих Правил, предъявляемыми к транспортным средствам.</p>","image":"assets/adrive-questions/q100101304.jpg"},{"id":100101401,"themeId":1,"group":1001014,"chapter":1,"chapters":[1],"q":"Какое из нижеперечисленных определений соответствует термину «железнодорожный переезд»?","a":["Пересечение дороги с трамвайными путями на одном уровне.","Пересечение дороги с трамвайными путями на разных уровнях.","Пересечение дороги с железнодорожными путями на одном уровне.","Пересечение дороги с железнодорожными путями на разных уровнях."],"c":2,"e":"<p>Железнодорожным переездом является пересечение дороги с железнодорожными путями на одном уровне. Пересечение с трамвайными путями железнодорожным переездом не является.</p>","image":null},{"id":100101402,"themeId":1,"group":1001014,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «железнодорожный переезд»?","a":["Пересечение дороги с железнодорожными путями на одном уровне, обозначенное соответствующими дорожными знаками.","Пересечение дороги с железнодорожными путями на одном уровне, не обозначенное дорожными знаками.","Пересечение дороги на одном уровне с железнодорожными путями, которые временно не используются для движения поездов.","Соответствует всё перечисленное."],"c":3,"e":"<p>Любое пересечение дороги с железнодорожными путями на одном уровне является железнодорожным переездом вне зависимости от наличия технических средств организации дорожного движения и интенсивности движения железнодорожных транспортных средств.</p>","image":null},{"id":100101403,"themeId":1,"group":1001014,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного наиболее полно соответствует термину «железнодорожный переезд»?","a":["Любое пересечение дороги с железнодорожными путями.","Пересечение дороги с железнодорожными путями на одном уровне.","Только пересечение дороги с железнодорожными путями на одном уровне, оборудованное сигнализацией и (или) шлагбаумом.","Только пересечение дороги с железнодорожными путями на одном уровне, обозначенное соответствующими дорожными знаками."],"c":1,"e":"<p>Любое пересечение дороги с железнодорожными путями на одном уровне является железнодорожным переездом вне зависимости от наличия технических средств организации дорожного движения.</p>","image":null},{"id":100101501,"themeId":1,"group":1001015,"chapter":1,"chapters":[1],"q":"Соответствует ли пересечение проезжей части дороги с трамвайными путями термину «железнодорожный переезд»?","a":["Да, если это пересечение с линией скоростного трамвая на одном уровне.","Да, если это пересечение обозначено дорожным знаком «Пересечение с трамвайной линией».","Нет, не соответствует."],"c":2,"e":"<p>Пересечение дороги или проезжей части дороги с трамвайными путями не является железнодорожным переездом. Железнодорожным переездом является только пересечение дороги с железнодорожными путями на одном уровне.</p>","image":"assets/adrive-questions/q100101501.jpg"},{"id":100101502,"themeId":1,"group":1001015,"chapter":1,"chapters":[1],"q":"Является ли железнодорожным переездом показанное пересечение?","a":["Да, является.","Нет, не является."],"c":1,"e":"<p>Пересечение проезжей части дороги с трамвайными путями не является железнодорожным переездом. Железнодорожным переездом является только пересечение дороги с железнодорожными путями на одном уровне.</p>","image":"assets/adrive-questions/q100101502.jpg"},{"id":100101503,"themeId":1,"group":1001015,"chapter":1,"chapters":[1],"q":"Является ли трамвай железнодорожным транспортным средством?","a":["Да, является.","Нет, не является."],"c":1,"e":"<p>Трамвай — это механическое транспортное средство, предназначенное для движения по рельсам, участвующее в дорожном движении и не являющееся железнодорожным транспортным средством.</p>","image":"assets/adrive-questions/q100101503.jpg"},{"id":100101601,"themeId":1,"group":1001016,"chapter":1,"chapters":[1],"q":"В каком из перечисленных случаев водитель совершил маневрирование?","a":["Съехал на обочину для замены колеса.","Остановился перед светофором с запрещающим сигналом.","Объехал препятствие, не выезжая за пределы полосы движения.","Не перестраиваясь, опередил попутно двигавшееся в соседней полосе транспортное средство."],"c":0,"e":"<p>Из всего перечисленного маневрированием является лишь съезд с проезжей части дороги на обочину. Все остальные случаи не соответствуют термину «маневрирование».</p>","image":null},{"id":100101602,"themeId":1,"group":1001016,"chapter":1,"chapters":[1],"q":"Какое из перечисленных действий относится к термину «маневрирование»?","a":["Движение задним ходом.","Прекращение движения перед «стоп-линией».","Возобновление движения после включения разрешающего сигнала светофора.","Все вышеперечисленные."],"c":0,"e":"<p>Из всего перечисленного маневрированием является лишь движение задним ходом, в остальных случаях действия водителя не соответствуют термину «маневрирование».</p>","image":null},{"id":100101603,"themeId":1,"group":1001016,"chapter":1,"chapters":[1],"q":"Какое из перечисленных действий относится к термину «маневрирование»?","a":["Начало движения.","Движение задним ходом.","Перестроение из одной полосы движения в другую для объезда препятствия.","Все перечисленные."],"c":3,"e":"<p>Все перечисленные случаи: начало движения, движение задним ходом и перестроение из одной полосы движения в другую являются маневрированием.</p>","image":null},{"id":100101641,"themeId":1,"group":1001016,"chapter":1,"chapters":[1],"q":"Соответствует ли термину «маневрирование» выезд на трамвайные пути перед дальнейшим поворотом налево на перекрёстке?","a":["Да, соответствует.","Нет, термину соответствует непосредственно только поворот налево на перекрёстке."],"c":0,"e":"<p>К маневрированию относятся: начало движения, перестроение транспортного средства в движении из одной полосы движения в другую, выезд транспортного средства на трамвайные пути, съезд с них, а также его поворот направо или налево, разворот, съезд с проезжей части дороги, движение задним ходом.</p>","image":"assets/adrive-questions/q100101641.jpg"},{"id":100101741,"themeId":1,"group":1001017,"chapter":1,"chapters":[1],"q":"К велосипеду приравнивается транспортное средство, аналогичное по конструкции, имеющее электродвигатель с максимальной конструктивной скоростью движения, определённой его технической характеристикой:","a":["Не более 25 км/ч.","Не более 30 км/ч.","Не более 50 км/ч."],"c":0,"e":"<p>К велосипеду приравниваются транспортные средства, имеющие электродвигатель номинальной максимальной мощностью в режиме длительной нагрузки, не превышающей 0.25 кВт, и (или) максимальную конструктивную скорость движения, определённую его технической характеристикой, не более 25 км/ч либо иной двигатель с аналогичной характеристикой.</p>","image":null},{"id":100101742,"themeId":1,"group":1001017,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «велосипед»?","a":["Средство персональной мобильности, имеющее рулевое управление.","Двухколёсное транспортное средство, приводимое в движение мускульной силой человека, находящегося на нём, в частности при помощи рукояток.","Двухколёсное транспортное средство, приводимое в движение с помощью педалей и с помощью электродвигателя, и имеющее максимальную конструктивную скорость движения, определённую его технической характеристикой, более 25 км/ч.","Соответствуют все варианты ответов."],"c":1,"e":"<p>Велосипед — это транспортное средство (а средство персональной мобильности таковым не является), которое имеет не менее двух колёс и приводится в движение мускульной силой человека (людей), находящегося на (в) нём, в частности при помощи педалей или рукояток.<br> <strong>К велосипеду приравниваются аналогичные по конструкции транспортные средства, имеющие</strong> электродвигатель номинальной максимальной мощностью в режиме длительной нагрузки, не превышающей 0.25 кВт, и (или) <strong>максимальную конструктивную скорость движения, определённую его технической характеристикой, не более 25 км/ч</strong> либо иной двигатель с аналогичной характеристикой.</p>","image":null},{"id":100101743,"themeId":1,"group":1001017,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «велосипед»?","a":["Двухколёсное транспортное средство, приводимое в движение при помощи рукояток мускульной силой человека, находящегося в нём.","Двухколёсное транспортное средство, приводимое в движение электродвигателем номинальной максимальной мощностью в режиме длительной нагрузки, превышающей 0.4 кВт, и имеющее максимальную конструктивную скорость движения, определённую его технической характеристикой, более 25 км/ч, а также массой, не превышающей 25 кг.","Соответствуют оба варианта ответа."],"c":0,"e":"<p>Велосипед — это транспортное средство, которое имеет не менее двух колёс и приводится в движение мускульной силой человека (людей), находящегося на (в) нём, в частности при помощи педалей или рукояток.<br> К велосипеду приравниваются аналогичные по конструкции транспортные средства, имеющие электродвигатель номинальной максимальной мощностью в режиме длительной нагрузки, не превышающей 0.25 кВт, и (или) максимальную конструктивную скорость движения, определённую его технической характеристикой, не более 25 км/ч либо иной двигатель с аналогичной характеристикой.</p> <p>Вес велосипеда Правилами дорожного движения не регламентируется.</p>","image":null},{"id":100101801,"themeId":1,"group":1001018,"chapter":1,"chapters":[1],"q":"Какая из перечисленных ситуаций соответствует термину «дорожно-транспортное происшествие»?","a":["Происшествие, в результате которого произошло возгорание автомобиля, не находившегося в движении.","Происшествие, в результате которого были похищены стеклоочистители с автомобиля, находившегося на неохраняемой стоянке.","Происшествие, в результате которого произошёл наезд автомобиля на пешехода с велосипедом, в результате которого был причинён вред здоровью пешехода.","Происшествие, совершённое с участием находившегося в движении велосипеда, в результате которого был повреждён автомобиль, не находившийся в движении."],"c":2,"e":"<p>ДТП — это происшествие, совершённое с участием хотя бы одного находившегося в движении механического транспортного средства, в данном случае — автомобиля. Не считаются дорожно-транспортными происшествия с находящимися на стоянке транспортными средствами (возгорание, хищения и прочее).</p>","image":null},{"id":100101802,"themeId":1,"group":1001018,"chapter":1,"chapters":[1],"q":"Соответствует ли термину «дорожно-транспортное происшествие» ситуация, в которой был повреждён не находившийся в движении автомобиль?","a":["Да.","Нет.","Да, если происшествие совершено с участием другого находившегося в движении механического транспортного средства."],"c":2,"e":"<p>Не считаются дорожно-транспортными происшествия с находящимися на стоянке транспортными средствами, но если при этом участвовало находящееся в движении другое механическое транспортное средство, то такое происшествие является дорожно-транспортным.</p>","image":null},{"id":100101803,"themeId":1,"group":1001018,"chapter":1,"chapters":[1],"q":"Какая из перечисленных ситуаций соответствует термину «дорожно-транспортное происшествие»?","a":["Происшествие, совершённое с участием находившегося в движении колёсного трактора, в результате которого был повреждён не находившийся в движении автомобиль.","Происшествие, совершённое с участием находившегося в движении мопеда, в результате которого был совершён наезд на растущее дерево и повреждён мопед.","Происшествие, совершённое с участием находившегося в движении мотоцикла, в результате которого был совершён наезд на пешехода, получившего тяжкие телесные повреждения.","Соответствуют все перечисленные."],"c":3,"e":"<p>Все перечисленные варианты соответствуют термину «дорожно-транспортное происшествие», потому что каждое было совершено с участием хотя бы одного находившегося в движении механического транспортного средства, и в результате был причинён вред здоровью физического лица (пешехода) или причинён вред имуществу.</p>","image":null},{"id":100101902,"themeId":1,"group":1001019,"chapter":1,"chapters":[1],"q":"Какое из перечисленных транспортных средств является механическим?","a":["Прицеп.","Автобус.","Велосипед.","Гужевое транспортное средство."],"c":1,"e":"<p>Автобус по определению является автомобилем, а автомобиль в свою очередь — механическим транспортным средством. Остальные перечисленные транспортные средства не являются механическими.</p>","image":"assets/adrive-questions/q100101902.jpg"},{"id":100101903,"themeId":1,"group":1001019,"chapter":1,"chapters":[1],"q":"Какие из перечисленных транспортных средств являются механическими?","a":["Трамвай.","Мотоцикл.","Троллейбус.","Колёсный трактор.","Все перечисленные."],"c":4,"e":"<p>Все перечисленные транспортные средства приводятся в движение двигателями: трамвай и троллейбус — электродвигателями, мотоциклы — бензиновыми или электрическими двигателями, а колёсные тракторы, как правило, — дизельными или комбинированными силовыми установками; следовательно, все они являются механическими транспортными средствами.</p>","image":"assets/adrive-questions/q100101903.jpg"},{"id":100102001,"themeId":1,"group":1001020,"chapter":1,"chapters":[1],"q":"Какое из перечисленных транспортных средств не относится к механическим?","a":["Мопед.","Трамвай.","Велосипед.","Все перечисленные."],"c":2,"e":"<p>Велосипед не относится к механическим транспортным средствам.</p>","image":"assets/adrive-questions/q100102001.jpg"},{"id":100102002,"themeId":1,"group":1001020,"chapter":1,"chapters":[1],"q":"Какое из перечисленных транспортных средств относится к термину «механическое транспортное средство»?","a":["Прицеп.","Велосипед.","Прицеп-роспуск.","Колёсный трактор.","Гужевое транспортное средство."],"c":3,"e":"<p>Из перечисленных транспортных средств только колёсный трактор приводится в движение двигателем и является механическим транспортным средством.</p>","image":null},{"id":100102003,"themeId":1,"group":1001020,"chapter":1,"chapters":[1],"q":"Какое из перечисленных транспортных средств не относится к термину «механическое транспортное средство»?","a":["Автобус.","Трамвай.","Троллейбус.","Прицеп-роспуск.","Седельный тягач."],"c":3,"e":"<p>Прицеп-роспуск является разновидностью прицепа и предназначен только для движения в составе с механическим транспортным средством, но механическим транспортным средством не является.</p>","image":null},{"id":100102101,"themeId":1,"group":1001021,"chapter":1,"chapters":[1],"q":"Какое транспортное средство из перечисленных ниже соответствует термину «мотоцикл»?","a":["Двухколёсное механическое транспортное средство, приводимое в движение двигателем с рабочим объёмом до 50 куб. сантиметров, имеющее максимальную конструктивную скорость движения, определённую его технической характеристикой, более 50 км/ч.","Двухколёсное механическое транспортное средство, приводимое в движение двигателем с рабочим объёмом до 50 куб. сантиметров, имеющее максимальную конструктивную скорость движения, определённую его технической характеристикой, не более 50 км/ч.","Трёхколёсное механическое транспортное средство с приводами управления мотоциклетного типа, имеющие массу в снаряжённом состоянии более 550 килограммов (без учёта массы аккумуляторов электрических транспортных средств) и максимальную эффективную мощность двигателя, превышающую 15 кВт.","Соответствуют все перечисленные."],"c":0,"e":"<p>Мотоцикл — это двухколёсное механическое транспортное средство с боковым прицепом или без него, приводимое в движение двигателем с рабочим объёмом 50 куб. сантиметров и более (в случае двигателя внутреннего сгорания) или максимальная конструктивная скорость которого (при любом двигателе) превышает 50 км/ч. К мотоциклам приравниваются трёх- и четырёхколёсные механические транспортные средства с приводами управления мотоциклетного типа, имеющие массу в снаряжённом состоянии не более 550 килограммов (без учёта массы аккумуляторов электрических транспортных средств) и максимальную эффективную мощность двигателя, не превышающую 15 кВт.</p>","image":null},{"id":100102102,"themeId":1,"group":1001021,"chapter":1,"chapters":[1],"q":"Какое транспортное средство из перечисленных ниже соответствует термину «мотоцикл»?","a":["Любое двухколёсное механическое транспортное средство с боковым прицепом.","Двухколёсное механическое транспортное средство с боковым прицепом или без него, приводимое в движение двигателем с рабочим объёмом 50 куб. сантиметров и более.","Двухколёсное механическое транспортное средство без бокового прицепа, приводимое в движение двигателем с рабочим объёмом до 50 куб. сантиметров, имеющее максимальную конструктивную скорость движения, определённую его технической характеристикой, не более 50 км/ч.","Соответствуют все перечисленные."],"c":1,"e":"<p>Мотоцикл — это двухколёсное механическое транспортное средство с боковым прицепом или без него, приводимое в движение двигателем с рабочим объёмом 50 куб. сантиметров и более (в случае двигателя внутреннего сгорания) или максимальная конструктивная скорость которого (при любом двигателе) превышает 50 км/ч. К мотоциклам приравниваются трёх- и четырёхколёсные механические транспортные средства с приводами управления мотоциклетного типа, имеющие массу в снаряжённом состоянии не более 550 килограммов (без учёта массы аккумуляторов электрических транспортных средств) и максимальную эффективную мощность двигателя, не превышающую 15 кВт.</p>","image":null},{"id":100102241,"themeId":1,"group":1001022,"chapter":1,"chapters":[1],"q":"Приравнивается ли к мотоциклу трёхколёсное механическое транспортное средство с приводами управления мотоциклетного типа?","a":["Да, если оно имеет массу в снаряжённом состоянии не более 550 килограммов (без учёта массы аккумуляторов электрического транспортного средства) и максимальную эффективную мощность двигателя, не превышающую 15 кВт.","Нет, не приравнивается."],"c":0,"e":"<p>К мотоциклам приравниваются трёх- и четырёхколёсные механические транспортные средства с приводами управления мотоциклетного типа, имеющие массу в снаряжённом состоянии не более 550 килограммов (без учёта массы аккумуляторов электрических транспортных средств) и максимальную эффективную мощность двигателя, не превышающую 15 кВт.</p>","image":"assets/adrive-questions/q100102241.jpg"},{"id":100102271,"themeId":1,"group":1001022,"chapter":1,"chapters":[1],"q":"Если максимальная конструктивная скорость электровелосипеда составляет 55 км/ч, а номинальная мощность в режиме длительной нагрузки составляет 0.5 Вт, такое транспортное средство следует считать:","a":["Мопедом.","Мотоциклом.","Велосипедом.","Средством персональной мобильности."],"c":1,"e":"<p>Показанное транспортное средство с перечисленными характеристиками следует считать <strong>мотоциклом</strong> согласно Правил дорожного движения, т.к. его <strong>максимальная скорость превышает 50 км/ч</strong>.</p>","image":"assets/adrive-questions/q100102271.jpg"},{"id":100102301,"themeId":1,"group":1001023,"chapter":1,"chapters":[1],"q":"Является ли населённым пунктом объект, обозначенный таким дорожным знаком?","a":["Да, является.","Нет, не является."],"c":1,"e":"<p>На рисунке изображён дорожный знак «5.26.1 Наименование объекта» — наименование объекта, не являющегося населённым пунктом (река, озеро, достопримечательности и тому подобное), а также обозначение административно-территориальных и территориальных единиц.</p>","image":"assets/adrive-questions/q100102301.jpg"},{"id":100102302,"themeId":1,"group":1001023,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «населённый пункт»?","a":["Территория, въезды на которую и выезды с которой обозначены дорожными знаками «Начало населённого пункта» и «Конец населённого пункта».","Территория, въезды на которую и выезды с которой обозначены дорожными знаками «Начало границы населённого пункта» и «Конец границы населённого пункта».","Соответствуют все перечисленные."],"c":2,"e":"<p>Территория, которая в Правилах дорожного движения называется населённым пунктом, действительно может обозначаться двумя видами дорожных знаков: с белым или синим фоном (знак «Начало границы населённого пункта», установленный на автомагистрали, имеет зелёный фон). Разница состоит в том, что при установке знака «Начало границы населённого пункта» на данную дорогу (только на неё) не действуют правила, установленные для движения в населённом пункте.</p>","image":null},{"id":100102303,"themeId":1,"group":1001023,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «населённый пункт»?","a":["Территория, въезды на которую и выезды с которой обозначены знаками «Пешеходная зона» и «Конец пешеходной зоны».","Территория, въезды на которую и выезды с которой обозначены дорожными знаками «Начало границы населённого пункта» и «Конец границы населённого пункта».","Любая застроенная территория, въезды на которую обозначены дорожными знаками «Ограничение максимальной скорости» с обозначенной скоростью на знаке 60 км/ч.","Соответствуют все перечисленные."],"c":1,"e":"<p>Населённым пунктом считается территория, въезды на которую и выезды с которой обозначены дорожными знаками «Начало населённого пункта» и «Конец населённого пункта» или дорожными знаками «Начало границы населённого пункта» и «Конец границы населённого пункта».</p>","image":null},{"id":100102401,"themeId":1,"group":1001024,"chapter":1,"chapters":[1],"q":"Является ли населённым пунктом территория, въезд на которую обозначен таким дорожным знаком?","a":["Да.","Нет."],"c":0,"e":"<p>В показанной ситуации изображён въезд на территорию, обозначенную дорожным знаком «5.22.1 Начало населённого пункта», следовательно, эта территория является населённым пунктом.</p>","image":"assets/adrive-questions/q100102401.jpg"},{"id":100102402,"themeId":1,"group":1001024,"chapter":1,"chapters":[1],"q":"Где обозначено начало территории, соответствующей термину «населённый пункт»?","a":["В точке «А».","В точке «Б»."],"c":0,"e":"<p>В точке «А» установлен дорожный знак 5.24 «Начало границы населённого пункта» , а это значит, что территория, соответствующая термину «населённый пункт», начинается уже в точке «А», а специальные требования Правил, устанавливающие порядок дорожного движения в населённых пунктах, начинают действовать на показанной дороге после проезда точки «Б», места установки дорожного знака 5.22.1 «Начало населённого пункта» .</p>","image":"assets/adrive-questions/q100102402.jpg"},{"id":100102403,"themeId":1,"group":1001024,"chapter":1,"chapters":[1],"q":"Водитель какого автомобиля движется по территории населённого пункта?","a":["Водитель автобуса, находящегося на дороге после знака «Начало границы населённого пункта».","Водитель легкового автомобиля, находящийся на дороге до знака «Начало границы населённого пункта».","Оба водителя осуществляют движение по дороге вне населённого пункта."],"c":0,"e":"<p>Водитель автобуса проехал место установки дорожного знака 5.24 «Начало границы населённого пункта» , а это значит, что он уже движется по территории населённого пункта, а водитель легкового автомобиля — нет.</p>","image":"assets/adrive-questions/q100102403.jpg"},{"id":100102501,"themeId":1,"group":1001025,"chapter":1,"chapters":[1],"q":"Какие из перечисленных дорожных условий соответствуют термину «недостаточная видимость»?","a":["Видимость дороги в направлении движения менее 300 метров в условиях сильного дождя.","Видимость дороги в направлении движения менее 300 метров, ограниченная поворотом дороги.","Видимость дороги в направлении движения менее 300 метров, ограниченная транспортными средствами, движущимися впереди.","Соответствуют все перечисленные."],"c":0,"e":"<p>Если видимость дороги в направлении движения составляет менее 300 метров ввиду обильных осадков — то такие условия соответствуют термину «недостаточная видимость дороги», в остальных перечисленных случаях речь идёт о возможной ограниченной обзорности дороги.</p>","image":null},{"id":100102502,"themeId":1,"group":1001025,"chapter":1,"chapters":[1],"q":"Какие из перечисленных дорожных условий соответствуют термину «недостаточная видимость»?","a":["Видимость дороги в направлении движения менее 300 метров, обусловленная снегопадом.","Видимость дороги в направлении движения менее 300 метров, обусловленная туманом вблизи водоёма.","Видимость дороги в направлении движения менее 300 метров, обусловленная сильной задымлённостью.","Соответствуют все перечисленные."],"c":3,"e":"<p>Если видимость дороги в направлении движения составляет менее 300 метров ввиду снижения прозрачности атмосферы из-за погодных, метеорологических условий или иных факторов (дым, туман, смог и прочее), то такие условия соответствуют термину «недостаточная видимость дороги».</p>","image":null},{"id":100102503,"themeId":1,"group":1001025,"chapter":1,"chapters":[1],"q":"Какие из перечисленных дорожных условий соответствуют термину «недостаточная видимость»?","a":["Видимость дороги в направлении движения в тёмное время суток, обусловленная освещённостью дороги фарами автомобиля.","Видимость дороги в направлении движения менее 300 метров, обусловленная погодными (метеорологическими) условиями и другими факторами, снижающими прозрачность атмосферы.","Обзорность дороги, ограниченная её геометрическими параметрами, придорожными инженерными сооружениями, насаждениями и прочими объектами, а также транспортными средствами.","Соответствуют все перечисленные."],"c":1,"e":"<p>Если видимость дороги в направлении движения составляет менее 300 метров ввиду снижения прозрачности атмосферы из-за погодных условий или иных факторов (дым, туман, смог и прочее), то такие условия соответствуют термину «недостаточная видимость дороги».</p>","image":null},{"id":100102601,"themeId":1,"group":1001026,"chapter":1,"chapters":[1],"q":"При каком минимальном расстоянии видимости в направлении движения, обусловленной выпадением осадков, видимость дороги не будет считаться недостаточной?","a":["50 метров.","100 метров.","150 метров.","300 метров.","500 метров."],"c":3,"e":"<p>Недостаточной видимостью дороги считается видимость в направлении движения менее 300 метров, обусловленная погодными условиями или иными факторами, снижающими прозрачность атмосферы.<br> Предельная величина расстояния 300 метров принята как минимальная расчётная с учётом возможности остановки при экстренном торможении транспортного средства в случае движения навстречу друг другу транспортных средств при скорости каждого из них 90 км/ч. Поэтому видимость дороги на меньшем расстоянии считается недостаточной.</p>","image":"assets/adrive-questions/q100102601.jpg"},{"id":100102602,"themeId":1,"group":1001026,"chapter":1,"chapters":[1],"q":"Видимость дороги в направлении движения, обусловленная погодными (метеорологическими) условиями, считается недостаточной, если составляет менее:","a":["300 метров.","500 метров.","Величины безопасной дистанции.","Величины предполагаемого тормозного пути.","Величины предполагаемого остановочного пути."],"c":0,"e":"<p>Если в описанных условиях видимость дороги в направлении движения составляет менее 300 метров, и это обусловлено погодными условиями, снижающими прозрачность атмосферы, то такие условия соответствуют термину «недостаточная видимость дороги».</p>","image":"assets/adrive-questions/q100102602.jpg"},{"id":100102681,"themeId":1,"group":1001026,"chapter":1,"chapters":[1],"q":"В показанной ситуации Вы, двигаясь за рулём легкового автомобиля, находитесь:","a":["Только в условиях ограниченной обзорности дороги.","Только в условиях недостаточной видимости дороги.","В условиях ограниченной обзорности и недостаточной видимости дороги."],"c":2,"e":"<p>Показанные дорожные условия характеризуются видимостью в направлении движения менее 300 метров в условиях снегопада, так что они соответствуют недостаточной видимости. При этом грузовой автопоезд справа ограничивает обзорность вперёд вправо в сторону съезда с транспортной развязки и въезда на путепровод. Поэтому такие условия соответствуют также ограниченной обзорности дороги.</p>","image":"assets/adrive-questions/q100102681.jpg"},{"id":100102801,"themeId":1,"group":1001028,"chapter":1,"chapters":[1],"q":"Является ли с данного направления перекрёсток обозначенным, если перед ним установлен этот дорожный знак?","a":["Да, является.","Нет, не является."],"c":0,"e":"<p>Обозначенный перекрёсток — это перекрёсток, перед которым на данной дороге установлен дорожный знак (знаки) приоритета.</p> <p>В данном случае перед перекрёстком установлен дорожный знак 2.4 «Уступить дорогу» , который входит в группу знаков приоритета.</p>","image":"assets/adrive-questions/q100102801.jpg"},{"id":100102803,"themeId":1,"group":1001028,"chapter":1,"chapters":[1],"q":"Является ли с данного направления перекрёсток обозначенным, если Вы приближаетесь к нему в населённом пункте?","a":["Да, является.","Нет, не является."],"c":1,"e":"<p>Обозначенный перекрёсток — это перекрёсток, перед которым на данной дороге установлен дорожный знак (знаки) приоритета.</p> <p>В данном случае перед перекрёстком отсутствуют дорожные знаки, и он не будет считаться обозначенным.</p>","image":"assets/adrive-questions/q100102803.jpg"},{"id":100102832,"themeId":1,"group":1001028,"chapter":1,"chapters":[1],"q":"Является ли с данного направления перекрёсток обозначенным, если перед ним установлены такие дорожные знаки в населённом пункте?","a":["Да, является.","Нет, не является."],"c":1,"e":"<p>Обозначенный перекрёсток — это перекрёсток, перед которым на данной дороге установлен дорожный знак (знаки) приоритета.</p> <p>В показанном случае перед перекрёстком с данного направления отсутствуют дорожные знаки, входящие в группу знаков приоритета.</p> <p>Дорожный знак приоритета 2.4 «Уступить дорогу» , установленный справа, делает перекрёсток обозначенным для водителей, приближающихся к нему справа.</p>","image":"assets/adrive-questions/q100102832.jpg"},{"id":100102871,"themeId":1,"group":1001028,"chapter":1,"chapters":[1],"q":"Через 60 метров Вы, управляя автомобилем, подъедете:","a":["К обозначенному перекрёстку.","К необозначенному перекрёстку."],"c":0,"e":"<p>Перед перекрёстком с данного направления установлен дорожный знак приоритета «Примыкание второстепенной дороги». Табличка под знаком указывает расстояние до перекрёстка. Следовательно, этот перекрёсток является обозначенным.</p>","image":"assets/adrive-questions/q100102871.jpg"},{"id":100102872,"themeId":1,"group":1001028,"chapter":1,"chapters":[1],"q":"Какие фрагменты рисунка соответствуют определению «обозначенный перекрёсток»?","a":["Только фрагмент «А».","Только фрагмент «Б».","Оба соответствуют.","Оба не соответствуют."],"c":2,"e":"<p>Согласно определению, обозначенным перекрёстком является любой перекрёсток, перед которым с данного направления установлены знаки приоритета.</p>","image":"assets/adrive-questions/q100102872.jpg"},{"id":100102901,"themeId":1,"group":1001029,"chapter":1,"chapters":[1],"q":"Что в показанной ситуации собирается выполнить водитель легкового автомобиля?","a":["Обгон.","Опережение, не связанное с выполнением обгона."],"c":0,"e":"<p>При отсутствии дорожных знаков половина ширины проезжей части дороги, расположенная слева, считается её встречной стороной, поэтому водитель при опережении грузового автомобиля будет производить обгон (опережение, связанное с выездом на встречную полосу движения).</p>","image":"assets/adrive-questions/q100102901.jpg"},{"id":100102903,"themeId":1,"group":1001029,"chapter":1,"chapters":[1],"q":"Что в показанной ситуации намерен выполнить водитель синего легкового автомобиля?","a":["Обгон.","Опережение."],"c":1,"e":"<p>Двойная сплошная линия горизонтальной дорожной разметки разделяет транспортные потоки противоположных направлений, водитель синего легкового автомобиля при совершении опережения её не пересекает, следовательно, выполняя опережение жёлтого автомобиля, обгон он не выполняет.</p>","image":"assets/adrive-questions/q100102903.jpg"},{"id":100103001,"themeId":1,"group":1001030,"chapter":1,"chapters":[1],"q":"Является ли обгоном действие, которое Вы намереваетесь выполнить в показанной ситуации?","a":["Да, является.","Нет, не является."],"c":1,"e":"<p>Выезжая на встречную полосу движения, Вы не совершаете обгон, так как автобус стоит, а объезд неподвижного транспортного средства не является по определению опережением. Обгон является опережением, связанным с выездом на встречную сторону дороги (полосу движения).</p>","image":"assets/adrive-questions/q100103001.jpg"},{"id":100103032,"themeId":1,"group":1001030,"chapter":1,"chapters":[1],"q":"Является ли обгоном действие, выполняемое в показанной ситуации водителем красного легкового автомобиля?","a":["Да, является.","Нет, не является."],"c":1,"e":"<p>Объезд неподвижного транспортного средства не является опережением, следовательно, не является и обгоном, так как обгон — это опережение, связанное с выездом на встречную сторону дороги (полосу движения).</p>","image":"assets/adrive-questions/q100103032.jpg"},{"id":100103102,"themeId":1,"group":1001031,"chapter":1,"chapters":[1],"q":"Какое из перечисленных действий соответствует термину «обгон»?","a":["Опережение движущегося транспортного средства, не связанное с перестроением на встречную полосу движения.","Опережение движущегося транспортного средства, связанное с выездом на встречную сторону проезжей части дороги.","Опережение движущегося транспортного средства, не связанное с выездом из занимаемой полосы движения попутного направления.","Все соответствуют."],"c":1,"e":"<p>Только опережение, связанное с выездом (перестроением) на встречную полосу движения (встречную сторону проезжей части дороги), согласно ПДД является обгоном.</p>","image":null},{"id":100103201,"themeId":1,"group":1001032,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного наиболее полно соответствует термину «обзорность дороги»?","a":["Объективная возможность видеть дорожную обстановку с места водителя.","Видимость дороги в направлении движения менее 300 метров, обусловленная сильным туманом.","Максимальное расстояние в направлении движения, на котором с места водителя можно распознать элементы дороги и технические средства организации дорожного движения перед транспортным средством и правильно ориентироваться при управлении им."],"c":0,"e":"<p>В Правилах дорожного движения под обзорностью дороги понимается объективная возможность видеть дорожную обстановку с места водителя. Обусловлена обзорность дороги элементами конструкции транспортного средства, количеством, конструкцией и размерами зеркал заднего вида, а также геометрическими параметрами дороги, расположением других транспортных средств, сооружений, и прочих объектов, находящихся на дороге и в непосредственной близости от неё.</p>","image":null},{"id":100103301,"themeId":1,"group":1001033,"chapter":1,"chapters":[1],"q":"Дорожный знак (дорожные знаки) какой группы должен быть установлен перед перекрёстком, чтобы он считался обозначенным?","a":["Приоритета.","Запрещающие.","Предписывающие.","Предупреждающие.","Информационно-указательные."],"c":0,"e":"<p>Перекрёсток считается обозначенным, если перед ним на данной дороге непосредственно или на установленном Правилами дорожного движения расстоянии установлены дорожные знаки приоритета.</p>","image":null},{"id":100103302,"themeId":1,"group":1001033,"chapter":1,"chapters":[1],"q":"Перед перекрёстком установлены только дорожные знаки приоритета совместно с информационно-указательными. Считается ли этот перекрёсток обозначенным?","a":["Да.","Нет."],"c":0,"e":"<p>Если перед перекрёстком установлены дорожные знаки приоритета, то такой перекрёсток считается обозначенным. Знаки приоритета могут быть установлены как самостоятельно, так и с дорожными знаками других групп, а также с дорожными светофорами.</p>","image":null},{"id":100103303,"themeId":1,"group":1001033,"chapter":1,"chapters":[1],"q":"Перед перекрёстком установлены только дорожные знаки сервиса совместно с информационно-указательными. Считается ли этот перекрёсток обозначенным?","a":["Да.","Нет."],"c":1,"e":"<p>Перекрёсток не считается обозначенным, если перед ним на данной дороге не установлены дорожные знаки приоритета, не смотря на применение других технических средств организации дорожного движения.</p>","image":null},{"id":100103401,"themeId":1,"group":1001034,"chapter":1,"chapters":[1],"q":"Выберите один из вариантов ответа, при котором перекрёсток будет считаться обозначенным:","a":["Перед перекрёстком установлены знаки сервиса.","Перед перекрёстком установлен указатель направлений с названиями улиц.","Перед перекрёстком установлены светофоры совместно со знаками приоритета.","Перед перекрёстком установлены светофоры совместно с информационно-указательными знаками."],"c":2,"e":"<p>Если перед перекрёстком установлены дорожные знаки приоритета, то такой перекрёсток считается обозначенным. Знаки приоритета могут быть установлены как самостоятельно, так и с дорожными знаками других групп, а также с дорожными светофорами.</p>","image":null},{"id":100103402,"themeId":1,"group":1001034,"chapter":1,"chapters":[1],"q":"Перекрёсток считается обозначенным, если перед ним установлены:","a":["Светофоры.","Дорожные знаки приоритета.","Светофоры или дорожные знаки приоритета."],"c":1,"e":"<p>Перекрёсток считается обозначенным, если перед ним на данной дороге непосредственно или на установленном Правилами дорожного движения расстоянии установлены дорожные знаки приоритета. Установки только дорожных светофоров недостаточно для того, чтобы перекрёсток считался обозначенным.</p>","image":null},{"id":100103403,"themeId":1,"group":1001034,"chapter":1,"chapters":[1],"q":"Является ли перекрёсток обозначенным, если перед ним установлен этот дорожный знак?","a":["Да.","Нет."],"c":0,"e":"<p>Перед перекрёстком установлен дорожный знак «2.5 Движение без остановки запрещено», который относится к группе знаков приоритета, следовательно, показанный на рисунке перекрёсток является обозначенным.</p>","image":"assets/adrive-questions/q100103403.jpg"},{"id":100103501,"themeId":1,"group":1001035,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «ограниченная обзорность дороги»?","a":["Обзорность дороги, ограниченная величиной и регулировкой зеркал заднего вида.","Обзорность дороги, ограниченная автомобильным противосолнечным козырьком, повернутым вниз.","Обзорность дороги, ограниченная транспортными средствами, движущимися в попутном направлении.","Соответствуют все перечисленные."],"c":2,"e":"<p>Ограниченной обзорностью дороги считаются условия, когда обзорность с места водителя ограничивается не конструкцией управляемого транспортного средства, а другими транспортными средствами или прочими объектами, находящимися на дороге или в непосредственной близости от неё.</p>","image":null},{"id":100103502,"themeId":1,"group":1001035,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «ограниченная обзорность дороги»?","a":["Обзорность дороги, ограниченная объектами придорожного сервиса.","Обзорность дороги, ограниченная переломом продольного профиля дороги.","Обзорность дороги, ограниченная транспортными средствами, припаркованными перед перекрёстком.","Соответствуют все перечисленные."],"c":3,"e":"<p>Ограниченной обзорностью дороги считаются условия, когда обзорность с места водителя ограничена геометрическими параметрами дороги (поворот, конец подъёма и проч.), придорожными инженерными сооружениями, насаждениями, прочими объектами и транспортными средствами.</p>","image":null},{"id":100103503,"themeId":1,"group":1001035,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «ограниченная обзорность дороги»?","a":["Обзорность дороги, ограниченная придорожными насаждениями.","Объективная возможность видеть дорожную обстановку с места водителя.","Видимость дороги в направлении движения менее 300 метров, обусловленная погодными и метеорологическими условиями.","Соответствуют все перечисленные."],"c":0,"e":"<p>Ограниченной обзорностью дороги считаются условия, когда обзорность с места водителя ограничена геометрическими параметрами дороги (поворот, конец подъёма и проч.), придорожными инженерными сооружениями, насаждениями, прочими объектами и транспортными средствами без учёта погодных условий и других факторов, снижающих прозрачность атмосферы.</p>","image":null},{"id":100103601,"themeId":1,"group":1001036,"chapter":1,"chapters":[1],"q":"В показанной ситуации, подъезжая к повороту дороги, Вы находитесь в условиях, соответствующих термину:","a":["«Ограниченная обзорность дороги».","«Недостаточная видимость дороги»."],"c":0,"e":"<p>Если обзорность дороги ограничена геометрическими параметрами дороги и насаждениями, как в показанной ситуации, то такие условия соответствуют термину «ограниченная обзорность дороги».</p>","image":"assets/adrive-questions/q100103601.jpg"},{"id":100103602,"themeId":1,"group":1001036,"chapter":1,"chapters":[1],"q":"К какому термину относится движение по дороге, которая просматривается в направлении движения менее чем на 150 метров с места водителя в условиях сильного снегопада?","a":["«Ограниченная обзорность дороги».","«Недостаточная видимость дороги».","«Препятствие для дорожного движения»."],"c":1,"e":"<p>Если видимость дороги, обусловленная снегопадом, в направлении движения составляет менее 300 метров, такие условия соответствуют термину «недостаточная видимость дороги».</p>","image":null},{"id":100103603,"themeId":1,"group":1001036,"chapter":1,"chapters":[1],"q":"В показанной ситуации, двигаясь по дороге, Вы находитесь в условиях, соответствующих термину:","a":["«Ограниченная обзорность дороги».","«Недостаточная видимость дороги»."],"c":0,"e":"<p>Ограниченная обзорность дороги — это обзорность дороги, ограниченная геометрическими параметрами дороги, придорожными инженерными сооружениями, насаждениями и прочими объектами, а также транспортными средствами.</p> <p>В данной ситуации обзорность ограничена выпуклым переломом продольного профиля дороги, образованным мостовым сооружением.</p>","image":"assets/adrive-questions/q100103603.jpg"},{"id":100103661,"themeId":1,"group":1001036,"chapter":1,"chapters":[1],"q":"В показанной ситуации Вы, управляя легковым автомобилем, находитесь:","a":["В условиях ограниченной обзорности дороги.","В условиях недостаточной видимости дороги."],"c":0,"e":"<p>В показанной ситуации обзорность дороги ограничена придорожными насаждениями, сооружениями и геометрическими параметрами дороги. Такие условия называются ограниченной обзорностью.</p>","image":"assets/adrive-questions/q100103661.jpg"},{"id":100103702,"themeId":1,"group":1001037,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «полоса движения»?","a":["Любая из продольных полос проезжей части дороги, не обозначенная горизонтальной разметкой и имеющая ширину, достаточную для движения велосипедов в один ряд.","Любая из продольных полос проезжей части дороги, не обозначенная горизонтальной дорожной разметкой и имеющая ширину, достаточную для движения мопедов в один ряд.","Любая из продольных полос проезжей части дороги, не обозначенная горизонтальной дорожной разметкой и имеющая ширину, достаточную для движения автомобилей в один ряд.","Соответствует всё перечисленное."],"c":2,"e":"<p>Если полоса движения не обозначена линиями горизонтальной дорожной разметки, то её ширина определяется самими водителями с учётом ширины, достаточной для движения транспортных средств, кроме одноколейных, в один ряд.</p>","image":null},{"id":100103703,"themeId":1,"group":1001037,"chapter":1,"chapters":[1],"q":"Какой буквой на рисунке обозначена ширина полосы движения?","a":["Буквой «А».","Буквой «Б».","Буквой «В»."],"c":2,"e":"<p>Буквой «А» обозначена ширина проезжей части дороги, буквой «Б» — ширина попутной стороны проезжей части дороги, буквой «В» — ширина первой (крайней правой) полосы движения.</p>","image":"assets/adrive-questions/q100103703.jpg"},{"id":100103704,"themeId":1,"group":1001037,"chapter":1,"chapters":[1],"q":"Сколько полос движения имеет показанная проезжая часть дороги?","a":["Одну.","Две.","Три.","Четыре.","Шесть."],"c":1,"e":"<p>Полоса движения — это любая из продольных полос проезжей части дороги, обозначенная или не обозначенная горизонтальной дорожной разметкой и имеющая ширину, достаточную для движения транспортных средств (за исключением одноколейных) в один ряд.</p> <p>В данном случае количество полос движения определено линиями горизонтальной дорожной разметки. Проезжая часть дороги имеет две полосы движения.</p>","image":"assets/adrive-questions/q100103704.jpg"},{"id":100103801,"themeId":1,"group":1001038,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного не соответствует термину «опасность для движения»?","a":["Изменение условий дорожного движения, угрожающее безопасности участников дорожного движения, вынуждающее водителя остановиться.","Изменение условий дорожного движения, угрожающее безопасности участников дорожного движения, вынуждающее водителя увеличить скорость.","Изменение технического состояния транспортного средства, угрожающее безопасности участников дорожного движения, вынуждающее водителя снизить скорость движения.","Все соответствуют."],"c":1,"e":"<p>Как ни странно, но согласно Правилам дорожного движения изменение условий дорожного движения, угрожающее безопасности участников дорожного движения, вынуждающее водителя увеличить скорость, не соответствует термину «опасность для движения», например, увеличение скорости, чтобы избежать столкновения или для вывода переднеприводного автомобиля или прицепа из бокового заноса.</p>","image":null},{"id":100103802,"themeId":1,"group":1001038,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «опасность для движения»?","a":["Появление объекта, препятствующего движению, вынуждающего водителя совершить объезд, не изменяя скорость движения.","Изменение условий дорожного движения, угрожающее безопасности участников дорожного движения, вынуждающее водителя остановиться.","Изменение технического состояния транспортного средства, не угрожающее безопасности участников дорожного движения, вынуждающее водителя снизить скорость движения.","Все соответствуют."],"c":1,"e":"<p>Изменения условий движения, соответствующие термину «опасность для движения», характеризуются наличием угрозы безопасности участников дорожного движения, которая вынудила водителя снизить скорость движения или остановиться.</p>","image":null},{"id":100103803,"themeId":1,"group":1001038,"chapter":1,"chapters":[1],"q":"Какому термину соответствует состояние дорожного движения, обеспечивающее минимальную вероятность возникновения опасности для движения и дорожно-транспортного происшествия?","a":["Преимущество.","Опасность для движения.","Безопасность дорожного движения."],"c":2,"e":"<p>Состояние дорожного движения, обеспечивающее минимальную вероятность возникновения опасности для движения и дорожно-транспортного происшествия, соответствует термину «Безопасность дорожного движения».</p>","image":"assets/adrive-questions/q100103803.jpg"},{"id":100103901,"themeId":1,"group":1001039,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «опережение»?","a":["Объезд стоящего транспортного средства, связанный с выездом на встречную полосу движения.","Движение транспортного средства со скоростью, превышающей скорость движущегося навстречу транспортного средства.","Движение транспортного средства со скоростью, превышающей скорость попутно двигающегося транспортного средства."],"c":2,"e":"<p>Опережение — это движение транспортного средства слева или справа со скоростью, превышающей скорость попутно движущегося транспортного средства. Опережение может осуществляться как после перестроения или смещения в пределах полосы движения, так и без изменения положения на проезжей части дороги.</p>","image":null},{"id":100103902,"themeId":1,"group":1001039,"chapter":1,"chapters":[1],"q":"Совершает ли водитель легкового автомобиля опережение в показанной ситуации?","a":["Да, совершает.","Нет, не совершает."],"c":1,"e":"<p>Водитель легкового автомобиля не осуществляет опережение, так как проезжает мимо остановившегося, а не находящегося в движении, автобуса.</p>","image":"assets/adrive-questions/q100103902.jpg"},{"id":100103903,"themeId":1,"group":1001039,"chapter":1,"chapters":[1],"q":"Совершает ли водитель легкового автомобиля опережение в показанной ситуации?","a":["Да, совершает.","Нет, не совершает."],"c":0,"e":"<p>Водитель легкового автомобиля осуществляет опережение, так как проезжает с более высокой скоростью мимо начавшего движение автобуса.</p>","image":"assets/adrive-questions/q100103903.jpg"},{"id":100103971,"themeId":1,"group":1001039,"chapter":1,"chapters":[1],"q":"Соответствует ли термину «опережение» движение автомобиля со скоростью, превышающей скорость движения попутного велосипедиста?","a":["Да, соответствует.","Нет, не соответствует."],"c":0,"e":"<p>Движение со скоростью, превышающей скорость движения попутного транспортного средства (в том числе велосипеда), считается опережением.</p>","image":"assets/adrive-questions/q100103971.jpg"},{"id":100104001,"themeId":1,"group":1001040,"chapter":1,"chapters":[1],"q":"Является ли показанная группа транспортных средств организованной транспортной колонной?","a":["Да, является.","Нет, не является."],"c":0,"e":"<p>Если транспортная колонна движется в сопровождении транспортного средства оперативного назначения с включёнными проблесковыми сигналами (маячками), то она является согласно Правилам дорожного движения организованной транспортной колонной.</p>","image":"assets/adrive-questions/q100104001.jpg"},{"id":100104002,"themeId":1,"group":1001040,"chapter":1,"chapters":[1],"q":"Является ли группа транспортных средств, состоящая только из трёх автобусов, изображённая на рисунке, организованной транспортной колонной?","a":["Да, является.","Нет, не является."],"c":1,"e":"<p>В показанной ситуации транспортная колонна из трёх автобусов движется без сопровождения транспортного средства (транспортных средств) оперативного назначения, следовательно, она не является организованной транспортной колонной.</p>","image":"assets/adrive-questions/q100104002.jpg"},{"id":100104003,"themeId":1,"group":1001040,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «организованная транспортная колонна»?","a":["Транспортная колонна, движущаяся в сопровождении транспортного средства с включённым маячком оранжевого цвета.","Транспортное средство, движущееся с постоянно включённым ближним светом фар в сопровождении транспортного средства оперативного назначения с включёнными проблесковыми сигналами синего цвета.","Все варианты соответствуют."],"c":1,"e":"<p>В организованной транспортной колонне сопровождением транспортного средства или транспортной колонны может быть только транспортное средство (транспортные средства) оперативного назначения с включёнными проблесковыми сигналами (маячками) синего или синего и красного цветов.</p>","image":null},{"id":100104101,"themeId":1,"group":1001041,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «организованная транспортная колонна»?","a":["Транспортное средство, движущееся с постоянно включённым ближним светом фар в сопровождении транспортных средств оперативного назначения с включёнными проблесковыми сигналами синего цвета.","Транспортная колонна из десяти грузовых автомобилей, движущихся с постоянно включённым ближним светом фар в сопровождении транспортного средства оперативного назначения с включёнными проблесковыми сигналами синего и красного цвета.","Соответствует всё перечисленное."],"c":2,"e":"<p>В организованной транспортной колонне в сопровождении транспортного средства или транспортных средств оперативного назначения может осуществлять движение как одно транспортное средство, так и транспортная колонна.</p>","image":null},{"id":100104132,"themeId":1,"group":1001041,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «организованная транспортная колонна»?","a":["Группа велосипедистов, движущаяся в сопровождении транспортного средства с включёнными проблесковыми сигналами оранжевого цвета.","Группа из трёх автобусов, следующих друг за другом по одной полосе движения с постоянно включённым ближним светом фар, обозначенная опознавательными знаками «Колонна».","Два автобуса, следующие друг за другом по одной полосе движения с постоянно включённым ближним светом фар, обозначенные опознавательными знаками «Колонна», в сопровождении транспортных средств оперативного назначения с включёнными проблесковыми сигналами синего или синего и красного цветов.","Соответствуют все перечисленные."],"c":2,"e":"<p>В организованной транспортной колонне в сопровождении транспортного средства или транспортных средств оперативного назначения могут осуществлять движение только механические транспортные средства. Кроме того, колонна, сопровождаемая транспортным средством с включённым маячком оранжевого цвета, не будет соответствовать согласно Правилам дорожного движения термину «организованная транспортная колонна».</p>","image":null},{"id":100104201,"themeId":1,"group":1001042,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «остановка транспортного средства»?","a":["Прекращение движения транспортного средства на время до 5 минут, связанное с проверкой документов сотрудником ДПС ГАИ.","Преднамеренное прекращение движения транспортного средства на время до 5 минут, связанное с осмотром перевозимого груза.","Непреднамеренное прекращение движения транспортного средства на время до 5 минут, связанное с заменой вышедшей из строя лампочки внешнего светового прибора.","Все соответствуют."],"c":1,"e":"<p>Остановкой является только преднамеренное прекращение движения. Если транспортное средство остановлено должностным лицом, имеющим право остановки транспортного средства, или прекращение движения вызвано технической неисправностью, то такое прекращение движения не является остановкой.</p>","image":null},{"id":100104202,"themeId":1,"group":1001042,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «остановка транспортного средства»?","a":["Преднамеренное прекращение движения транспортного средства на время до 5 минут для телефонного разговора.","Преднамеренное прекращение движения транспортного средства на время более 5 минут для высадки пассажиров.","Преднамеренное прекращение движения электромобиля на время более 5 минут для зарядки.","Все соответствуют."],"c":3,"e":"<p>Любое преднамеренное прекращение движения на время до пяти минут является остановкой, а также более пяти минут, если это связано с посадкой (высадкой) пассажиров, или загрузкой (разгрузкой) транспортного средства, или зарядкой электромобиля.</p>","image":null},{"id":100104203,"themeId":1,"group":1001042,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «остановка транспортного средства»?","a":["Преднамеренное прекращение движения транспортного средства на время более 5 минут для загрузки транспортного средства.","Преднамеренное прекращение движения транспортного средства на время более 5 минут для проверки крепления перевозимого груза.","Преднамеренное прекращение движения транспортного средства на время более 5 минут для проверки состояния перевозимого груза.","Все соответствуют."],"c":0,"e":"<p>Преднамеренное прекращение движения на время более пяти минут является остановкой только если это необходимо для посадки (высадки) пассажиров либо загрузки (разгрузки) транспортного средства.</p>","image":null},{"id":100104204,"themeId":1,"group":1001042,"chapter":1,"chapters":[1],"q":"Соответствует ли термину «остановка транспортного средства» преднамеренное прекращение движения для разгрузки транспортного средства?","a":["Да, только если на время до пяти минут.","Да, независимо от затраченного времени на разгрузку.","Нет, не соответствует."],"c":1,"e":"<p>Остановка транспортного средства — это преднамеренное прекращение движения транспортного средства на время до 5 минут, а также более чем на 5 минут, если это необходимо для посадки (высадки) пассажиров либо загрузки (разгрузки) транспортного средства.<br> Иными словами, совершенно неважно, сколько продлиться процесс разгрузки, — всё равно такое прекращение движения будет считаться остановкой.</p>","image":"assets/adrive-questions/q100104204.jpg"},{"id":100104241,"themeId":1,"group":1001042,"chapter":1,"chapters":[1],"q":"Поставив электромобиль на длительную (многочасовую) зарядку, водитель:","a":["Совершит остановку.","Поставит автомобиль на стоянку."],"c":0,"e":"<p>Преднамеренное прекращение движения, если это необходимо для зарядки электромобиля, является остановкой.</p>","image":"assets/adrive-questions/q100104241.jpg"},{"id":100104302,"themeId":1,"group":1001043,"chapter":1,"chapters":[1],"q":"Кто из перечисленных лиц является очевидцем дорожно-транспортного происшествия?","a":["Пешеход, непосредственно наблюдавший дорожно-транспортное происшествие, который располагает соответствующей информацией и может её предоставить.","Пассажир транспортного средства, непосредственно наблюдавший ДТП, который располагает соответствующей информацией и может её предоставить.","Работник коммунальной службы, выполнявший в установленном порядке на дороге ремонтные работы, непосредственно наблюдавший дорожно-транспортное происшествие, который располагает соответствующей информацией и может её предоставить.","Все являются очевидцами дорожно-транспортного происшествия."],"c":3,"e":"<p>Очевидцем ДТП является лицо, непосредственно наблюдавшее ДТП, которое располагает соответствующей информацией и может её предоставить. Поэтому все перечисленные лица — очевидцы ДТП.</p>","image":null},{"id":100104303,"themeId":1,"group":1001043,"chapter":1,"chapters":[1],"q":"Можно ли считать очевидцем дорожно-транспортного происшествия пешехода, который не видел непосредственно момента совершения ДТП, но слышал звук удара и зафиксировал в памяти положение транспортных средств на проезжей части дороги после совершения ДТП?","a":["Да.","Нет."],"c":1,"e":"<p>Очевидцем ДТП является только лицо, непосредственно наблюдавшее ДТП, поэтому указанное в вопросе лицо не является очевидцем ДТП.</p>","image":"assets/adrive-questions/q100104303.jpg"},{"id":100104401,"themeId":1,"group":1001044,"chapter":1,"chapters":[1],"q":"Является ли перекрёстком показанное на рисунке место примыкания к дороге выезда с прилегающей территории?","a":["Да, является.","Нет, не является."],"c":0,"e":"<p>В месте выезда с прилегающей территории образуется примыкание на одном уровне, которое, согласно термину, является перекрёстком.</p>","image":"assets/adrive-questions/q100104401.jpg"},{"id":100104402,"themeId":1,"group":1001044,"chapter":1,"chapters":[1],"q":"Является ли перекрёстком участок дороги, показанный на рисунке?","a":["Да, является.","Нет, не является."],"c":1,"e":"<p>В показанном месте отсутствует выезд с остановочных мест, имеющий проезжую часть и оборудованный как примыкание одной дороги к другой.</p> <p>Перекрёстком является только место пересечения, примыкания или разветвления дорог.</p>","image":"assets/adrive-questions/q100104402.jpg"},{"id":100104403,"themeId":1,"group":1001044,"chapter":1,"chapters":[1],"q":"В каком случае правильно указаны границы перекрёстка?","a":["На рисунке «А».","На рисунке «Б»."],"c":0,"e":"<p>Границы перекрёстка определяются воображаемыми линиями, соединяющими наиболее удалённые от центра перекрёстка начала закруглений проезжих частей дорог.</p> <p>Такие линии изображены на первом рисунке, обозначенном буквой «А».</p>","image":"assets/adrive-questions/q100104403.jpg"},{"id":100104501,"themeId":1,"group":1001045,"chapter":1,"chapters":[1],"q":"Является ли перекрёстком пересечение (примыкание, разветвление) дорог, на котором организовано круговое движение?","a":["Да, является.","Нет, не является."],"c":0,"e":"<p>В показанной ситуации изображён въезд на перекрёсток с круговым движением.</p>","image":"assets/adrive-questions/q100104501.jpg"},{"id":100104502,"themeId":1,"group":1001045,"chapter":1,"chapters":[1],"q":"Является ли перекрёстком участок дороги, показанный на изображении?","a":["Да, является.","Нет, не является."],"c":1,"e":"<p>На показанном участке дороги перекрёстка нет, так как имеется не разветвление дороги, а разделение проезжих частей из-за установленного фонтана.</p>","image":"assets/adrive-questions/q100104502.jpg"},{"id":100104503,"themeId":1,"group":1001045,"chapter":1,"chapters":[1],"q":"Является ли перекрёстком показанное на рисунке примыкание?","a":["Да, является.","Нет, не является."],"c":0,"e":"<p>На рисунке показан Т-образный перекрёсток (место примыкания одной дороги к другой).</p>","image":"assets/adrive-questions/q100104503.jpg"},{"id":100104504,"themeId":1,"group":1001045,"chapter":1,"chapters":[1],"q":"Является ли показанное пересечение дороги с железнодорожными путями железнодорожным переездом?","a":["Да, является.","Нет, не является."],"c":1,"e":"<p>Железнодорожным переездом является только пересечение дороги с железнодорожными путями на одном уровне.</p>","image":"assets/adrive-questions/q100104504.jpg"},{"id":100104601,"themeId":1,"group":1001046,"chapter":1,"chapters":[1],"q":"Какое из перечисленных пересечений (примыканий) является перекрёстком неравнозначных дорог?","a":["Пересечение дороги с дорожкой для всадников.","Пересечение проезжей части дороги с велосипедной дорожкой.","Выезд на дорогу с дворовой территории при отсутствии дорожных знаков приоритета.","Пересечение дороги с асфальтобетонным покрытием с дорогой, имеющей булыжное покрытие, при отсутствии дорожных знаков приоритета."],"c":2,"e":"<p>Согласно термину «перекрёсток» не считаются перекрёстками пересечения дороги с пешеходными и велосипедными дорожками, а также с дорожками для всадников. Кроме того, в определении «главная дорога» сказано, что любая дорога является главной по отношению к выездам с прилегающей территории. Что касается дорог с асфальтобетонным и булыжным покрытием, то обе они имеют усовершенствованное покрытие, и при отсутствии дорожных знаков приоритета будут считаться равнозначными.</p>","image":null},{"id":100104602,"themeId":1,"group":1001046,"chapter":1,"chapters":[1],"q":"Какое из перечисленных пересечений (примыканий) является перекрёстком равнозначных дорог при отсутствии дорожных знаков приоритета?","a":["Выезд на дорогу из жилой зоны.","Пересечение дороги с дорожкой для всадников.","Пересечение дороги, имеющей асфальтобетонное покрытие, с дорогой, имеющей гравийное покрытие, обработанное органическими или минеральными вяжущими материалами.","Пересечение дороги, имеющей асфальтобетонное покрытие, с дорогой, имеющей гравийное покрытие, не обработанное органическими или минеральными вяжущими материалами."],"c":2,"e":"<p>Согласно термину «перекрёсток» не считаются перекрёстками пересечения дороги с дорожками для всадников, а согласно термину «главная дорога» выезд с прилегающей территории, а также пересечение дороги с усовершенствованным покрытием с дорогой без усовершенствованного покрытия не будут считаться равнозначными, так как есть дорога, являющаяся главной. В случае пересечения двух дорог с усовершенствованным покрытием и отсутствии дорожных знаков приоритета принято считать такой перекрёсток равнозначным.</p>","image":null},{"id":100104603,"themeId":1,"group":1001046,"chapter":1,"chapters":[1],"q":"Какое из перечисленных примыканий является перекрёстком?","a":["Выезд на дорогу со двора.","Выезд на дорогу со строительной площадки.","Выезд на дорогу с автозаправочной станции.","Выезд на дорогу со специальной площадки, предназначенной для стоянки транспортных средств.","Все являются перекрёстками."],"c":4,"e":"<p>Перекрёстками являются пересечения, примыкания и разветвления дорог. Если выезд с прилегающей территории оборудован как участок дороги (имеет выраженные границы проезжей части дороги), то такое примыкание или пересечение является перекрёстком.</p>","image":null},{"id":100104604,"themeId":1,"group":1001046,"chapter":1,"chapters":[1],"q":"Что такое перекрёсток?","a":["Место пересечения дороги с железнодорожными путями на одном уровне.","Место пересечения, примыкания или разветвления дорог на одном уровне."],"c":1,"e":"<p>Перекрёстками являются пересечения, примыкания и разветвления дорог, а пересечение дороги с железнодорожными путями на одном уровне является железнодорожным переездом.</p>","image":null},{"id":100104701,"themeId":1,"group":1001047,"chapter":1,"chapters":[1],"q":"Является ли участок разделительной полосы, через которую проходит пешеходный переход, островком безопасности?","a":["Да, является.","Нет, не является."],"c":0,"e":"<p>Пешеход при переходе проезжих частей дорог находится в относительной безопасности на участке разделительной полосы, через которую проходит пешеходный переход, поэтому такой участок разделительной полосы относится к островку безопасности.</p>","image":"assets/adrive-questions/q100104701.jpg"},{"id":100104732,"themeId":1,"group":1001047,"chapter":1,"chapters":[1],"q":"Является ли показанный участок разделительной зоны, ограниченный сплошной линией горизонтальной разметки, через который проходит пешеходный переход, островком безопасности?","a":["Да, является.","Нет, не является."],"c":0,"e":"<p>Островки безопасности на пешеходных переходах, защитные элементы которых обеспечивают конструктивное выделение, предназначены для безопасной остановки пешеходов при переходе проезжей части дороги.<br> В показанной ситуации на участке разделительной зоны, через которую проходит пешеходный переход, оборудованы защитные элементы. Следовательно, на показанном участке разделительной зоны оборудован островок безопасности.</p>","image":"assets/adrive-questions/q100104732.jpg"},{"id":100104741,"themeId":1,"group":1001047,"chapter":1,"chapters":[1],"q":"Является ли участок пешеходного перехода, на котором остановился пешеход, островком безопасности?","a":["Да, является.","Нет, не является."],"c":1,"e":"<p>Островок безопасности — это техническое средство организации дорожного движения на наземных пешеходных переходах, защитные элементы которого обеспечивают конструктивное выделение места для безопасной остановки пешеходов при переходе проезжей части дороги.</p> <p>В показанном месте защитные элементы отсутствуют, поэтому показанный участок пешеходного перехода не является островком безопасности.</p>","image":"assets/adrive-questions/q100104741.jpg"},{"id":100104841,"themeId":1,"group":1001048,"chapter":1,"chapters":[1],"q":"Является ли показанное мостовое сооружение путепроводом?","a":["Да, является.","Нет, не является."],"c":1,"e":"<p>Путепровод — это инженерное сооружение, устраиваемое в местах пересечения дорог или дороги с железнодорожными путями для обеспечения беспрепятственного движения в разных уровнях.</p> <p>Мостовое сооружение над водной преградой путепроводом не является.</p>","image":"assets/adrive-questions/q100104841.jpg"},{"id":100104901,"themeId":1,"group":1001049,"chapter":1,"chapters":[1],"q":"Кто из перечисленных лиц является пешеходом?","a":["Физическое лицо, ведущее по дороге мопед.","Физическое лицо, ведущее по дороге средство персональной мобильности.","Физическое лицо, передвигающееся по дороге в инвалидной коляске.","Все перечисленные."],"c":3,"e":"<p>Все перечисленные участники дорожного движения являются пешеходами, так как они осуществляют движение по дороге вне транспортных средств (инвалидная коляска не является транспортным средством).</p>","image":null},{"id":100104902,"themeId":1,"group":1001049,"chapter":1,"chapters":[1],"q":"Кто из перечисленных лиц является пешеходом?","a":["Физическое лицо, ведущее по дороге мотоцикл.","Физическое лицо, сходящее с транспортного средства.","Физическое лицо, перегоняющее через дорогу стадо коров.","Физическое лицо, выполняющее в установленном порядке работы на дороге.","Все перечисленные."],"c":0,"e":"<p>Из перечисленных лиц пешеходом является только лицо, ведущее мотоцикл. Лицо, выполняющее на дороге работы, не является участником дорожного движения, лицо, сходящее с транспортного средства, является в этот момент ещё пассажиром, а погонщик скота приравнен к водителю.</p>","image":null},{"id":100104903,"themeId":1,"group":1001049,"chapter":1,"chapters":[1],"q":"Кто из перечисленных лиц является пешеходом?","a":["Физическое лицо, везущее по дороге санки.","Физическое лицо, двигающееся вне транспортного средства по обочине.","Физическое лицо, пересекающее проезжую часть дороги по кратчайшей траектории при отсутствии в пределах видимости пешеходных переходов и перекрёстков.","Все перечисленные."],"c":3,"e":"<p>Лица, передвигающиеся по дороге вне транспортного средства и при этом не выполняющие на дороге в установленном порядке работы, являются пешеходами.</p>","image":null},{"id":100105001,"themeId":1,"group":1001050,"chapter":1,"chapters":[1],"q":"Кто из перечисленных лиц является пешеходом?","a":["Физическое лицо, ведущее велосипед по пешеходному переходу.","Ребёнок, перебегающий проезжую часть дороги вне пешеходного перехода.","Физическое лицо, передвигающееся по краю проезжей части в инвалидной коляске при наличии обочины.","Все перечисленные являются пешеходами."],"c":3,"e":"<p>Лица, передвигающиеся по дороге вне транспортного средства (инвалидная коляска не является транспортным средством) и при этом не выполняющие на дороге в установленном порядке работы, являются пешеходами.</p>","image":null},{"id":100105002,"themeId":1,"group":1001050,"chapter":1,"chapters":[1],"q":"Кто из перечисленных лиц не является пешеходом?","a":["Физическое лицо, передвигающееся в салоне стоящего на остановке автобуса.","Физическое лицо, передвигающееся по велосипедной дорожке на роликовых коньках.","Физическое лицо, участвующее в дорожном движении вне транспортного средства и не выполняющее в установленном порядке на дороге ремонтные и другие работы.","Физическое лицо, ведущее по дороге средство персональной мобильности.","Все перечисленные не являются пешеходами."],"c":0,"e":"<p>Лицо, находящееся в транспортном средстве, не является пешеходом, даже если транспортное средство остановилось.</p>","image":null},{"id":100105041,"themeId":1,"group":1001050,"chapter":1,"chapters":[1],"q":"Каким участником дорожного движения является лицо, передвигающееся на электросамокате?","a":["Водителем.","Пешеходом."],"c":0,"e":"<p>Средство персональной мобильности является транспортным средством, а управляющее им лицо — водителем.</p>","image":"assets/adrive-questions/q100105041.jpg"},{"id":100105071,"themeId":1,"group":1001050,"chapter":1,"chapters":[1],"q":"К каким участникам дорожного движения приравниваются лица, передвигающиеся на средствах персональной мобильности?","a":["К пешеходам.","К велосипедистам.","К водителям мопедов."],"c":1,"e":"<p>Лица, передвигающиеся на средствах персональной мобильности, <strong>приравниваются к велосипедистам</strong> в силу того, что условия и правила передвижения для них и водителей велосипедов чаще всего совпадают.</p>","image":"assets/adrive-questions/q100105071.jpg"},{"id":100105202,"themeId":1,"group":1001052,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «пешеходный переход»?","a":["Элемент дороги, примыкающий к проезжей части дороги или отделённый от неё газоном, предназначенный для движения пешеходов и велосипедистов.","Участок проезжей части, предназначенный для движения пешеходов через проезжую часть дороги и обозначенный горизонтальной дорожной разметкой.","Выделенный конструктивно или с помощью линий горизонтальной дорожной разметки элемент дороги, предназначенный для движения пешеходов, обозначенный дорожным знаком «Пешеходная дорожка».","Соответствуют все перечисленные."],"c":1,"e":"<p>Пешеходным переходом является участок проезжей части дороги, предназначенный для её пересечения пешеходами в установленном порядке. В остальных вариантах ответов указаны элементы дороги, специально предназначенные для движения пешеходов.</p>","image":null},{"id":100105241,"themeId":1,"group":1001052,"chapter":1,"chapters":[1],"q":"Является ли пешеходной дорожкой элемент дороги, обозначенный показанной дорожной разметкой?","a":["Да, является.","Нет, не является."],"c":0,"e":"<p>Велосипедная дорожка обозначается дорожными знаками «4.5.1 Велосипедная дорожка» , «4.11.1 Велосипедная и пешеходная дорожка» и (или) дорожной разметкой 1.29 либо 1.31 соответственно.</p> <p>Показанная горизонтальная дорожная разметка — 1.31.</p>","image":"assets/adrive-questions/q100105241.jpg"},{"id":100105301,"themeId":1,"group":1001053,"chapter":1,"chapters":[1],"q":"Сколько полос движения имеет показанная проезжая часть дороги?","a":["Одну.","Две.","Три."],"c":1,"e":"<p>Показанная проезжая часть дороги имеет две полосы движения, обозначенные соответствующей дорожной разметкой. Элемент дороги, над которым установлен дорожный знак 4.5.1 «Велосипедная дорожка», не является полосой движения.</p>","image":"assets/adrive-questions/q100105301.jpg"},{"id":100105302,"themeId":1,"group":1001053,"chapter":1,"chapters":[1],"q":"Сколько полос движения имеет показанная проезжая часть дороги?","a":["Одну.","Две.","Три.","Четыре.","Шесть."],"c":3,"e":"<p>Показанная проезжая часть дороги имеет четыре полосы движения, обозначенные соответствующей дорожной разметкой. Крайние элементы дороги, отделённые от проезжей части дороги широкими сплошными линиями горизонтальной дорожной разметки — это обочины.</p>","image":"assets/adrive-questions/q100105302.jpg"},{"id":100105303,"themeId":1,"group":1001053,"chapter":1,"chapters":[1],"q":"Сколько полос движения имеет проезжая часть дороги, изображённая на рисунке?","a":["Одну.","Три.","Четыре.","Пять.","Шесть."],"c":2,"e":"<p>Показанная проезжая часть дороги имеет четыре полосы движения. Их количество и их границы определяются при отсутствии линий разметки самими водителями, исходя из габаритов транспортных средств и необходимых боковых интервалов. Трамвайный путь не является полосой движения — это отдельный элемент дороги, по которому может быть разрешено движение безрельсовых транспортных средств только в определённых случаях.</p>","image":"assets/adrive-questions/q100105303.jpg"},{"id":100105331,"themeId":1,"group":1001053,"chapter":1,"chapters":[1],"q":"Как называется расстояние по ширине дороги от крайних габаритных точек транспортных средств, движущихся попутно или во встречных направлениях?","a":["Дистанция.","Боковой интервал.","Габаритная ширина.","Дорожный просвет."],"c":1,"e":"<p>Показанная проезжая часть позволяет осуществлять встречное движение транспортных средств по двум полосам движения (попутная и встречная).</p> <p>Расстояние между транспортными средствами при их встречном разъезде в показанной ситуации обеспечивает безопасные условия движения и называется боковым интервалом.</p>","image":"assets/adrive-questions/q100105331.jpg"},{"id":100105401,"themeId":1,"group":1001054,"chapter":1,"chapters":[1],"q":"Что означает термин «преимущество»?","a":["Право на первоочередное движение в намеченном направлении по отношению к другим участникам дорожного движения.","Требование, означающее не возобновлять или не продолжать движение или не осуществлять какой-либо манёвр, если это может вынудить другого участника дорожного движения изменить направление или скорость движения.","Положение транспортного средства на проезжей части дороги, предназначенной для движения в данном направлении, не дающее возможности движения даже одноколейных транспортных средств соответственно правее (левее) в попутном направлении."],"c":0,"e":"<p>Преимуществом или приоритетом в Правилах дорожного движения считается право на первоочередное движение в намеченном направлении, если пути движения участников дорожного движения пересекаются.</p>","image":null},{"id":100105402,"themeId":1,"group":1001054,"chapter":1,"chapters":[1],"q":"Выберите из перечисленных вариантов наиболее полное определение термина «преимущество»:","a":["Право на движение в намеченном направлении после включения разрешающего сигнала светофора.","Право на первоочередное движение в намеченном направлении по отношению к другим участникам дорожного движения.","Расположение транспортного средства справа по отношению к другим транспортным средствам на равнозначном перекрёстке.","Движение транспортного средства по главной дороге по отношению к транспортным средствам, находящимся на второстепенной дороге."],"c":1,"e":"<p>Преимуществом или приоритетом в Правилах дорожного движения считается право на первоочередное движение в намеченном направлении. В предложенных вариантах ответов это право не очевидно, так как мы не видим всей дорожной обстановки. К примеру, по второстепенной дороге движется транспортное средство оперативного назначения с включёнными проблесковыми сигналами и тому подобное.</p>","image":null},{"id":100105501,"themeId":1,"group":1001055,"chapter":1,"chapters":[1],"q":"Соответствует ли буксируемый автомобиль термину «прицеп»?","a":["Нет, не соответствует.","Соответствует в любом случае.","Соответствует, только если у него выключен двигатель."],"c":0,"e":"<p>Буксируемый автомобиль не является прицепом, так как прицеп — это транспортное средство, предназначенное для движения в составе с механическим транспортным средством.</p>","image":"assets/adrive-questions/q100105501.jpg"},{"id":100105502,"themeId":1,"group":1001055,"chapter":1,"chapters":[1],"q":"Соответствует ли транспортное средство «Б» термину «прицеп»?","a":["Да, соответствует.","Нет, не соответствует."],"c":0,"e":"<p>В показанной ситуации буквой «Б» обозначен полуприцеп, который согласно термину «автопоезд» является прицепом.</p>","image":"assets/adrive-questions/q100105502.jpg"},{"id":100105601,"themeId":1,"group":1001056,"chapter":1,"chapters":[1],"q":"Сколько проезжих частей имеет показанная дорога?","a":["Одну.","Две.","Три.","Шесть."],"c":1,"e":"<p>В показанной ситуации изображена дорога с двумя проезжими частями, разделенными конструктивно выделенным элементом — разделительной полосой. Двойная сплошная линия горизонтальной дорожной разметки не является элементом, разделяющим смежные проезжие части дороги.</p>","image":"assets/adrive-questions/q100105601.jpg"},{"id":100105602,"themeId":1,"group":1001056,"chapter":1,"chapters":[1],"q":"Сколько проезжих частей имеет показанная дорога?","a":["Одну.","Две.","Четыре."],"c":0,"e":"<p>В показанной ситуации изображена дорога с одной проезжей частью, так как двойная сплошная линия горизонтальной дорожной разметки (линия 1.3) не является элементом, разделяющим смежные проезжие части дороги.</p>","image":"assets/adrive-questions/q100105602.jpg"},{"id":100105603,"themeId":1,"group":1001056,"chapter":1,"chapters":[1],"q":"Сколько проезжих частей имеет дорога, изображённая на рисунке?","a":["Одну.","Две.","Три.","Четыре."],"c":0,"e":"<p>На рисунке изображена дорога с одной проезжей частью. Трамвайный путь не является проезжей частью дороги, равно как и пешеходная дорожка.</p>","image":"assets/adrive-questions/q100105603.jpg"},{"id":100105701,"themeId":1,"group":1001057,"chapter":1,"chapters":[1],"q":"Сколько проезжих частей имеет дорога, изображённая на рисунке?","a":["Одну.","Две.","Три.","Четыре."],"c":0,"e":"<p>На рисунке изображена дорога с одной проезжей частью. Пешеходная дорожка не является проезжей частью дороги.</p>","image":"assets/adrive-questions/q100105701.jpg"},{"id":100105801,"themeId":1,"group":1001058,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного наиболее полно соответствует термину «проезжая часть дороги»?","a":["Полоса земли, на которой размещается дорога и все её сооружения.","Часть дороги, предназначенная для движения только безрельсовых транспортных средств.","Элемент дороги, предназначенный для движения транспортных средств и в случаях, предусмотренных Правилами дорожного движения, — для движения пешеходов.","Выделенный конструктивно или с помощью линий горизонтальной дорожной разметки элемент дороги, предназначенный для движения водителей велосипедов, обозначенный дорожным знаком «Велосипедная дорожка»."],"c":2,"e":"<p>Проезжая часть дороги — это элемент, предназначенный для движения транспортных средств. При этом движение пешеходов по ней может быть тоже разрешено в определённых Правилами дорожного движения случаях (жилая зона, пешеходная зона, движение по краю проезжей части дороги и тому подобное).</p>","image":null},{"id":100105802,"themeId":1,"group":1001058,"chapter":1,"chapters":[1],"q":"Укажите правильное обозначение ширины проезжей части дороги, изображённой на рисунке, если обочина имеет асфальтобетонное покрытие:","a":["«А».","«Б».","«В»."],"c":1,"e":"<p>Проезжая часть дороги обозначена буквой «Б». Буквой «А» обозначена вся ширина дороги, а буквой «В» — ширина полосы движения.</p>","image":"assets/adrive-questions/q100105802.jpg"},{"id":100105901,"themeId":1,"group":1001059,"chapter":1,"chapters":[1],"q":"Чем является элемент дороги, обозначенный на изображении?","a":["Разделительной зоной.","Разделительной полосой."],"c":1,"e":"<p>Обозначенный элемент дороги выделен конструктивно и разделяет смежные проезжие части дороги, следовательно, — это разделительная полоса.</p>","image":"assets/adrive-questions/q100105901.jpg"},{"id":100105902,"themeId":1,"group":1001059,"chapter":1,"chapters":[1],"q":"Чем является элемент дороги, обозначенный на изображении?","a":["Разделительной зоной.","Разделительной полосой."],"c":0,"e":"<p>Обозначенный элемент дороги выделен при помощи линий горизонтальной дорожной разметки и разделяет смежные проезжие части дороги, следовательно, — это разделительная зона.</p>","image":"assets/adrive-questions/q100105902.jpg"},{"id":100106041,"themeId":1,"group":1001060,"chapter":1,"chapters":[1],"q":"Предоставил ли преимущество водитель легкового автомобиля пешеходу, проезжая безостановочно пешеходный переход в показанной ситуации (светофор выключен)?","a":["Нет, не предоставил.","Да, предоставил."],"c":0,"e":"<p>При подъезде к нерегулируемому пешеходному переходу водитель должен предоставить преимущество пешеходу. Преимущество пешеходу считается предоставленным, если расстояние между транспортным средством и приближающимся пешеходом (в момент пересечения транспортным средством траектории движения пешехода) составило не менее двух полос движения транспортного средства (в том числе одну полосу и трамвайные пути попутного направления).</p> <p>Поэтому в показанной ситуации водитель не предоставил преимущество, так как между транспортным средством и пешеходом — одна полоса движения.</p>","image":"assets/adrive-questions/q100106041.jpg"},{"id":100106042,"themeId":1,"group":1001060,"chapter":1,"chapters":[1],"q":"Предоставил ли преимущество водитель легкового автомобиля пешеходу, проезжая безостановочно пешеходный переход в показанной ситуации?","a":["Нет, не предоставил.","Да, предоставил."],"c":1,"e":"<p>При подъезде к нерегулируемому пешеходному переходу водитель должен предоставить преимущество пешеходу. Преимущество пешеходу считается предоставленным, если расстояние между транспортным средством и приближающимся пешеходом (в момент пересечения транспортным средством траектории движения пешехода) составило не менее двух полос движения транспортного средства (в том числе одну полосу и трамвайные пути попутного направления).</p> <p>Трамвайный путь попутного направления по ширине равен трамвайному пути встречного направления. Учитывая, что в термине приведён не исключительный список («в том числе...»), два трамвайных пути приравнены к двум полосам движения транспортного средства.</p> <p>Поэтому в показанной ситуации водитель предоставил преимущество пешеходу.</p>","image":"assets/adrive-questions/q100106042.jpg"},{"id":100106140,"themeId":1,"group":1001061,"chapter":1,"chapters":[1],"q":"Предоставил ли преимущество пешеходу в показанной ситуации водитель жёлтого легкового автомобиля?","a":["Да, предоставил.","Нет, не предоставил."],"c":0,"e":"<p>Преимущество пешеходу считается предоставленным, если расстояние между транспортным средством и приближающимся пешеходом (в момент пересечения транспортным средством траектории движения пешехода) составило не менее двух полос движения транспортного средства (в том числе одну полосу и трамвайные пути попутного направления).</p> <p>Трамвайный путь попутного направления по ширине равен трамвайному пути встречного направления. Учитывая, что в термине приведён не исключительный список («в том числе...»), два трамвайных пути приравнены к двум полосам движения транспортного средства.</p> <p>Поэтому в показанной ситуации водитель предоставил преимущество пешеходу.</p>","image":"assets/adrive-questions/q100106140.jpg"},{"id":100106141,"themeId":1,"group":1001061,"chapter":1,"chapters":[1],"q":"Кто из показанных участников дорожного движения передвигается на средстве персональной мобильности?","a":["Участник дорожного движения, передвигающийся на электросамокате.","Участник дорожного движения, передвигающийся на электрическом велосипеде.","Оба участника дорожного движения передвигаются на средствах персональной мобильности."],"c":0,"e":"<p>Электросамокат, имеющий максимальную конструктивную скорость не более 25 км/ч, является средством персональной мобильности.</p>","image":"assets/adrive-questions/q100106141.jpg"},{"id":100106171,"themeId":1,"group":1001061,"chapter":1,"chapters":[1],"q":"Предоставил ли преимущество пешеходу в показанной ситуации водитель жёлтого легкового автомобиля?","a":["Да, предоставил.","Нет, не предоставил."],"c":0,"e":"<p>Преимущество пешеходу считается предоставленным, так как расстояние между жёлтым автомобилем и приближающимся пешеходом (в момент пересечения транспортным средством траектории движения пешехода) составило не менее двух полос движения транспортного средства.</p>","image":"assets/adrive-questions/q100106171.jpg"},{"id":100106202,"themeId":1,"group":1001062,"chapter":1,"chapters":[1],"q":"Кто из перечисленных лиц соответствует термину «регулировщик»?","a":["Сотрудник ГАИ, осуществляющий регулирование дорожного движения в форменной одежде повышенной видимости с элементами из световозвращающего материала, с жезлом и свистком.","Должностное лицо Транспортной инспекции Министерства транспорта и коммуникаций в жилете повышенной видимости с элементами из световозвращающего материала с диском с красным сигналом (световозвращателем).","Все перечисленные лица."],"c":0,"e":"<p>Регулировщиком является сотрудник ГАИ, регулирующий движение в форменной одежде с жезлом и свистком. Должностное лицо Транспортной инспекции Министерства транспорта и коммуникаций имеет в определённых случаях право остановки транспортного средства, однако согласно Правилам дорожного движения к регулировщику не приравнено.</p>","image":null},{"id":100106231,"themeId":1,"group":1001062,"chapter":1,"chapters":[1],"q":"Кто из перечисленных лиц соответствует термину «регулировщик»?","a":["Работник дорожно-строительной организации в одежде из световозвращающего материала, с диском с красным сигналом (световозвращателем) при исполнении своих служебных обязанностей.","Дежурный на железнодорожном переезде в одежде из световозвращающего материала, с диском с красным сигналом (световозвращателем) при исполнении ими своих служебных обязанностей.","Сотрудник Военной автомобильной инспекции Вооружённых Сил в форменной одежде повышенной видимости с элементами из световозвращающего материала, с диском с красным сигналом (световозвращателем) и свистком при обеспечении движения организованных транспортных колонн, в состав которых входят транспортные средства, принадлежащие воинским формированиям.","Все перечисленные лица."],"c":3,"e":"<p>Все перечисленные лица при исполнении ими служебных обязанностей соответствуют термину «регулировщик».</p>","image":null},{"id":100106233,"themeId":1,"group":1001062,"chapter":1,"chapters":[1],"q":"Кто из перечисленных лиц соответствует термину «регулировщик»?","a":["Сотрудник ГАИ, осуществляющий регулирование дорожного движения в соответствующей экипировке на перекрёстке при работающих светофорах.","Сотрудник Военной автомобильной инспекции Вооружённых Сил в соответствующей экипировке при обеспечении движения организованной транспортной колонны, в состав которой входят транспортные средства, принадлежащие Министерству обороны.","Сотрудник органов пограничной службы в соответствующей экипировке при обеспечении движения организованной транспортной колонны, в состав которой входят транспортные средства, принадлежащие Государственному пограничному комитету.","Все перечисленные лица."],"c":3,"e":"<p>Все перечисленные лица соответствуют термину «регулировщик». Причём Сотрудники Военной автомобильной инспекции и органов пограничной службы приравнены к регулировщику только в определённых Правилами дорожного движения случаях.</p>","image":null},{"id":100106241,"themeId":1,"group":1001062,"chapter":1,"chapters":[1],"q":"Приравниваются ли к регулировщику дежурные на железнодорожных переездах и паромных переправах в одежде из световозвращающего материала, с диском с красным сигналом (световозвращателем)?","a":["Да, при исполнении ими своих служебных обязанностей.","Нет, не приравниваются."],"c":0,"e":"<p>К регулировщику приравниваются работники дорожно-строительных и эксплуатационных организаций, дежурные на железнодорожных переездах и паромных переправах в одежде из световозвращающего материала, с диском с красным сигналом (световозвращателем) при исполнении ими своих служебных обязанностей.</p>","image":null},{"id":100106301,"themeId":1,"group":1001063,"chapter":1,"chapters":[1],"q":"В каком из перечисленных случаев водитель поставил автомобиль на стоянку?","a":["Преднамеренно прекратил движение на время более 5 минут, чтобы пообедать.","Преднамеренно прекратил движение на время более 5 минут для посадки пассажиров.","Преднамеренно прекратил движение на время более 5 минут для разгрузки транспортного средства.","Непреднамеренно прекратил движение на время более 5 минут из-за появившейся опасности для дорожного движения."],"c":0,"e":"<p>Стоянка — это преднамеренное прекращение движения на время более 5 минут, не связанное с посадкой (высадкой) пассажиров или загрузкой (разгрузкой) транспортного средства или зарядкой электромобиля.</p>","image":null},{"id":100106302,"themeId":1,"group":1001063,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного не соответствует термину «стоянка транспортного средства»?","a":["Преднамеренное прекращение движения транспортного средства более чем на 5 минут для отдыха водителя.","Преднамеренное прекращение движения транспортного средства более чем на 5 минут для проверки крепления и состояния груза.","Прекращение движения транспортного средства более чем на 5 минут для поиска причины неисправности транспортного средства.","Все соответствует."],"c":2,"e":"<p>Стоянка — это преднамеренное прекращение движения на время более 5 минут, не связанное с посадкой (высадкой) пассажиров, или загрузкой (разгрузкой) транспортного средства, или зарядкой электромобиля. А прекращение движения с целью поиска причины неисправности транспортного средства относится к термину «вынужденная остановка транспортного средства».</p>","image":null},{"id":100106303,"themeId":1,"group":1001063,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «стоянка транспортного средства»?","a":["Преднамеренное прекращение движения транспортного средства более чем на 5 минут для высадки пассажиров.","Преднамеренное прекращение движения электромобиля более чем на 5 минут для зарядки.","Прекращение движения транспортного средства более чем на 5 минут для устранения выявленной в пути технической неисправности.","Преднамеренное прекращение движения транспортного средства более чем на 5 минут для проверки технического состояния транспортного средства."],"c":3,"e":"<p>Стоянка — это преднамеренное прекращение движения на время более 5 минут, не связанное с посадкой (высадкой) пассажиров, или загрузкой (разгрузкой) транспортного средства, или зарядкой электромобиля. Прекращение движения с целью устранения причины неисправности транспортного средства относится к термину «вынужденная остановка транспортного средства». В случае проверки технического состояния транспортного средства в пути следования мы не говорим о том, что прекращение движения вызвано технической неисправностью, это может быть обусловлено, в том числе, пройденным расстоянием.</p>","image":null},{"id":100106501,"themeId":1,"group":1001065,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «тёмное время суток»?","a":["Промежуток времени, который начинается после захода солнца и заканчивается с восходом солнца.","Промежуток времени, который начинается с начала вечерних сумерек и заканчивается после восхода солнца.","Промежуток времени, который начинается через 30 минут после захода солнца и заканчивается за 30 минут до восхода солнца."],"c":0,"e":"<p>Тёмное время суток — это промежуток времени, начинающийся после захода солнца и заканчивающийся с восходом солнца. Если видимость дороги ухудшилась до захода солнца или остается плохой после восхода — водитель сам вправе решать, включать ли ему ближний свет фар, ходовые огни или противотуманные фары. Однако если видимость дороги ухудшилась до недостаточной, фары дальнего или ближнего света следует включить обязательно! </p>","image":"assets/adrive-questions/q100106501.jpg"},{"id":100106502,"themeId":1,"group":1001065,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «тёмное время суток»?","a":["Промежуток времени, который начинается до захода солнца и заканчивается после восхода солнца.","Промежуток времени, который начинается после захода солнца и заканчивается с восходом солнца.","Промежуток времени, который начинается, когда видимость дороги в направлении движения уменьшается до 300 метров, и заканчивается, когда видимость дороги в направлении движения становится более 300 метров."],"c":1,"e":"<p>Тёмное время суток — это промежуток времени, начинающийся после захода солнца и заканчивающийся с восходом солнца.</p>","image":null},{"id":100106503,"themeId":1,"group":1001065,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «тёмное время суток»?","a":["Промежуток времени, который начинается после захода солнца и заканчивается с восходом солнца.","Промежуток времени, который начинается через 30 минут после начала вечерних сумерек и заканчивается через 30 минут после начала утренних сумерек.","Промежуток времени, который начинается с момента, когда водитель вынужден включить фары ближнего или дальнего света, и заканчивается с момента, когда водитель может выключить фары без ущерба для безопасности дорожного движения."],"c":0,"e":"<p>Тёмное время суток — это промежуток времени, начинающийся после захода солнца и заканчивающийся с восходом солнца.</p>","image":null},{"id":100106601,"themeId":1,"group":1001066,"chapter":1,"chapters":[1],"q":"Как называется термин, характеризующий максимальную массу транспортного средства, установленную изготовителем (с грузом, водителем и пассажирами)?","a":["Технически допустимая общая масса.","Фактическая масса.","Масса в снаряжённом состоянии."],"c":0,"e":"<p>Технически допустимая общая масса — это максимальная масса транспортного средства, установленная изготовителем (с грузом, водителем и пассажирами).</p>","image":"assets/adrive-questions/q100106601.jpg"},{"id":100106602,"themeId":1,"group":1001066,"chapter":1,"chapters":[1],"q":"Из предложенных вариантов выберите наиболее полное и правильное определение термина «технически допустимая общая масса»:","a":["Максимальная масса транспортного средства, установленная изготовителем (с грузом, водителем и пассажирами).","Масса транспортного средства без груза, водителя и пассажиров.","Максимальная масса груза, перевозимого транспортным средством, установленная изготовителем."],"c":0,"e":"<p>Технически допустимая общая масса — это максимальная масса транспортного средства, установленная изготовителем (с грузом, водителем и пассажирами).</p> <p>Водителю запрещается участвовать в дорожном движении на транспортном средстве, у которого фактическая масса превышает технически допустимую общую массу.</p>","image":"assets/adrive-questions/q100106602.jpg"},{"id":100106701,"themeId":1,"group":1001067,"chapter":1,"chapters":[1],"q":"Из предложенных вариантов выберите наиболее полное и правильное определение термина «Транспортная колонна»:","a":["Группа из двух или более транспортных средств, следующих друг за другом по одной полосе движения.","Группа из двух или более автомобилей, следующих друг за другом по одной полосе движения с постоянно включённым ближним светом фар.","Группа из двух или более механических транспортных средств, следующих друг за другом по одной полосе движения с постоянно включённым ближним светом фар, обозначенная опознавательными знаками «Колонна»."],"c":2,"e":"<p>Термин «Транспортная колонна» складывается из четырёх составляющих: два и более механических транспортных средств, движение осуществляется по одной полосе движения с постоянно включённым ближним светом фар, транспортные средства обозначены опознавательными знаками «Колонна» .</p>","image":null},{"id":100106702,"themeId":1,"group":1001067,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «Транспортная колонна»?","a":["Группа из двух или более механических транспортных средств, следующих друг за другом по одной полосе движения с постоянно включённым ближним светом фар, обозначенная опознавательными знаками «Колонна».","Транспортное средство, движущееся с постоянно включённым ближним светом фар в сопровождении транспортных средств оперативного назначения с включёнными проблесковыми сигналами (маячками) синего или синего и красного цветов.","Группа из двух или более транспортных средств оперативного назначения, следующих друг за другом по одной полосе движения с постоянно включённым ближним светом фар и включёнными проблесковыми сигналами (маячками) синего цвета."],"c":0,"e":"<p>Термин «Транспортная колонна» складывается из четырёх составляющих: два и более механических транспортных средств, движение осуществляется по одной полосе движения с постоянно включённым ближним светом фар, транспортные средства обозначены опознавательными знаками «Колонна» .</p>","image":null},{"id":100106703,"themeId":1,"group":1001067,"chapter":1,"chapters":[1],"q":"Является ли показанная группа велосипедистов транспортной колонной?","a":["Не является.","Является в любом случае.","Является при условии включения фар (фонарей) белого цвета спереди и фонарей красного цвета сзади."],"c":0,"e":"<p>Транспортной колонной согласно Правилам дорожного движения является только колонна, состоящая из механических транспортных средств, а велосипеды не являются механическими транспортными средствами.</p>","image":"assets/adrive-questions/q100106703.jpg"},{"id":100106801,"themeId":1,"group":1001068,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «Транспортное средство оперативного назначения»?","a":["Транспортное средство, не имеющее специальной цветографической окраски, но имеющее световую и звуковую сигнализацию (проблесковые сигналы / маячки синего цвета).","Механическое транспортное средство для выполнения разнообразных технологических операций, а также привода стационарных машин, оборудованное сигналами (маячками) оранжевого цвета.","Механическое транспортное средство, оборудованное технологическим оборудованием для буксировки повреждённых при ДТП автомобилей, не имеющее специальной цветографической раскраски, но имеющее специальные сигналы (маячки) оранжевого цвета.","Все соответствуют.","Все не соответствуют."],"c":0,"e":"<p>Отличительным признаком транспортного средства оперативного назначения является наличие проблесковых сигналов (маячков) синего или синего и красного цветов.</p>","image":"assets/adrive-questions/q100106801.jpg"},{"id":100106802,"themeId":1,"group":1001068,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «Транспортное средство оперативного назначения»?","a":["Транспортное средство, имеющее специальную цветографическую окраску и (или) световую и звуковую сигнализацию.","Транспортное средство, осуществляющее сопровождение транспортных средств, перевозящих крупногабаритные грузы, с включённым маячком оранжевого цвета.","Транспортное средство таких габаритов, при которых для проезда по дорогам требуется специальное разрешение, выдаваемое в порядке, установленном законодательством.","Механическое транспортное средство, осуществляющее движение в скоростном сообщении, движущееся по установленному маршруту с обозначенными остановочными пунктами."],"c":0,"e":"<p>Транспортным средством оперативного назначения является транспортное средство, имеющее специальную цветографическую окраску (соответствующее сочетание цветов) и (или) световую (проблесковые сигналы (маячки) синего или синего и красного цветов) и звуковую сигнализацию.</p>","image":null},{"id":100106901,"themeId":1,"group":1001069,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «Главная дорога»?","a":["Дорога с гравийным покрытием по отношению к грунтовой дороге.","Любая дорога по отношению к выездам с прилегающей территории.","Дорога, обозначенная дорожным знаком «Дорога для автомобилей», по отношению к пересекаемой.","Соответствуют все перечисленные."],"c":3,"e":"<p>Во всех приведённых примерах дороги соответствуют термину «Главная дорога», то есть дорога, обозначенная дорожным знаком 5.3 «Дорога для автомобилей» , дорога по отношению к выездам с прилегающей территории и дорога с гравийным покрытием по отношению к дороге с грунтовым покрытием.</p>","image":null},{"id":100106902,"themeId":1,"group":1001069,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «Главная дорога»?","a":["Дорога с гравийным покрытием по отношению к дороге с булыжным покрытием.","Дорога с асфальтобетонным покрытием по отношению к дороге с булыжным покрытием.","Дорога, обозначенная знаком «Примыкание второстепенной дороги», по отношению к примыкающей дороге.","Соответствуют все перечисленные."],"c":2,"e":"<p>Из приведённых примеров соответствует термину «Главная дорога» только дорога, обозначенная дорожным знаком 2.3.2, 2.3.3 «Примыкание второстепенной дороги» , по отношению к примыкающей.</p> <p>Дорога с гравийным покрытием по отношению к дороге с булыжным покрытием при отсутствии знаков приоритета будет считаться второстепенной, а дорога с асфальтобетонным покрытием по отношению к дороге с булыжным покрытием будет считаться равнозначной.</p>","image":null},{"id":100106903,"themeId":1,"group":1001069,"chapter":1,"chapters":[1],"q":"Делает ли дорогу без усовершенствованного покрытия наличие участка с усовершенствованным покрытием непосредственно перед перекрёстком равной по значению с пересекаемой дорогой с усовершенствованным покрытием?","a":["Да.","Нет."],"c":1,"e":"<p>Наличие на дороге без усовершенствованного покрытия участка дороги с усовершенствованным покрытием непосредственно перед перекрёстком не делает такую дорогу равной по значению с пересекаемой дорогой с усовершенствованным покрытием.</p> <p>Такие участки предназначены для того, чтобы грязь с колёс выезжающих автомобилей не попадала на покрытие главной дороги, ухудшая на перекрёстке и вблизи его коэффициент сцепления и делая его неравномерным по ширине проезжей части дороги, а также для предохранения от разрушения кромки покрытия проезжей части дороги на перекрёстке.</p>","image":"assets/adrive-questions/q100106903.jpg"},{"id":100106904,"themeId":1,"group":1001069,"chapter":1,"chapters":[1],"q":"Какая дорога является главной по отношению к пересекаемой?","a":["Дорога с трамвайными путями по отношению к дороге без трамвайных путей.","Дорога с асфальтобетонным покрытием по отношению к дороге из булыжника.","Дорога со щебёночным покрытием по отношению к дороге с грунтовым покрытием.","Дорога, обозначенная дорожным знаком «Дорога для автомобилей», по отношению к пересекаемой.","Дорога, обозначенная дорожным знаком «Движение без остановки запрещено», по отношению к пересекаемой."],"c":3,"e":"<p>Из приведённых примеров соответствует термину «Главная дорога» только дорога, обозначенная дорожным знаком 5.3 «Дорога для автомобилей» , по отношению к пересекаемой.</p> <p>Дорога с асфальтобетонным покрытием по отношению к дороге с булыжным покрытием при отсутствии дорожных знаков приоритета будет считаться равнозначной, а дорога со щебёночным покрытием по отношению к дороге с грунтовым покрытием — равнозначной.</p> <p>Наличие на дороге трамвайных путей или продолжение в обе стороны по отношению к примыкающей или пересекаемой не делает такую дорогу главной.</p>","image":null},{"id":100107001,"themeId":1,"group":1001070,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «Главная дорога»?","a":["Дорога с трамвайными путями по отношению к дороге без трамвайных путей.","Дорога с грунтовым покрытием по отношению к выезду со строительной площадки.","Дорога, имеющая продолжение в обе стороны, по отношению к примыкающей к ней дороге.","Часть перекрёстка, по которому организовано круговое движение, по отношению к выездам на перекрёсток."],"c":1,"e":"<p>Из приведённых примеров соответствует термину «Главная дорога» только дорога с грунтовым покрытием по отношению к выезду со строительной площадки (как любая дорога по отношению к выездам с прилегающей территории).</p> <p>Наличие на дороге трамвайных путей или продолжение в обе стороны по отношению к примыкающей или пересекаемой не делает такую дорогу главной. Наличие и направление главной дороги на перекрёстке с круговым движением может быть определено только соответствующими дорожными знаками.</p>","image":null},{"id":100107002,"themeId":1,"group":1001070,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «Главная дорога»?","a":["Дорога с грунтовым покрытием по отношению к дороге со щебёночным покрытием.","Дорога с разделительной полосой по отношению к дороге без разделительной полосы.","Дорога, обозначенная дорожным знаком «Автомагистраль», по отношению к примыкающей дороге.","Дорога с бóльшим количеством полос движения по отношению к дороге с меньшим количеством полос движения."],"c":2,"e":"<p>Из приведённых примеров термину «Главная дорога» соответствует только дорога, обозначенная дорожным знаком 5.1 «Автомагистраль» по отношению к примыкающей дороге.</p> <p>Наличие на дороге разделительной полосы или большего количества полос движения по отношению к примыкающей или пересекаемой не делает такую дорогу главной.</p> <p>Две дороги со щебёночным и грунтовым покрытием при отсутствии дорожных знаков приоритета будут считаться равными по значению (равнозначными).</p>","image":null},{"id":100107003,"themeId":1,"group":1001070,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «Главная дорога»?","a":["Дорога с любым покрытием по отношению к выезду с прилегающей территории.","Дорога, на которой перед перекрёстком установлены знаки приоритета.","Дорога с гравийным покрытием по отношению к дороге с покрытием из брусчатки.","Дорога со щебёночным покрытием, не обработанным органическими или минеральными вяжущими материалами, по отношению к грунтовой дороге."],"c":0,"e":"<p>Из приведённых примеров термину «Главная дорога» соответствует только дорога по отношению к выезду с прилегающей территории.</p> <p>Наличие на дороге перед перекрёстком дорожных знаков приоритета говорит о том, что перекрёсток является обозначенным, поэтому необходимо уточнить, какие именно дорожные знаки установлены перед перекрёстком.</p> <p>Дорога без усовершенствованного покрытия по отношению к дороге с усовершенствованным покрытием при отсутствии дорожных знаков приоритета будут считаться второстепенной.</p> <p>Две дороги со щебёночным и грунтовым покрытием при отсутствии дорожных знаков приоритета будут считаться равными по значению (равнозначными).</p>","image":null},{"id":100107004,"themeId":1,"group":1001070,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «Главная дорога»?","a":["Дорога, обозначенная дорожным знаком «Главная дорога», по отношению к примыкающей дороге.","Дорога с двухсторонним движением по отношению к дороге с односторонним движением.","Дорога с асфальтобетонным покрытием по отношению к дороге с гравийным покрытием, обработанным органическими или минеральными вяжущими материалами.","Соответствуют все перечисленные."],"c":0,"e":"<p>Из приведённых примеров термину «Главная дорога» соответствует только дорога, обозначенная дорожным знаком 2.1 «Главная дорога» по отношению к примыкающей дороге.</p> <p>Дорога с двусторонним движением не является главной по отношению к дороге с односторонним движением при отсутствии дорожных знаков приоритета.</p> <p>Две дороги с усовершенствованным покрытием при отсутствии знаков приоритета будут считаться равными по значению (равнозначными).</p>","image":null},{"id":100107101,"themeId":1,"group":1001071,"chapter":1,"chapters":[1],"q":"Какое из транспортных средств в показанной ситуации находится на главной дороге?","a":["Грузовой автомобиль на дороге с гравийным покрытием.","Легковой автомобиль на дороге с асфальтобетонным покрытием."],"c":1,"e":"<p>В показанной ситуации легковой автомобиль движется по дороге с усовершенствованным покрытием, а грузовой — без усовершенствованного покрытия. Дорожных знаков приоритета перед перекрёстком нет, следовательно, легковой автомобиль находится на главной дороге.</p>","image":"assets/adrive-questions/q100107101.jpg"},{"id":100107102,"themeId":1,"group":1001071,"chapter":1,"chapters":[1],"q":"Какое из транспортных средств в показанной ситуации находится на главной дороге?","a":["Колёсный трактор, движущийся по дороге с булыжным покрытием.","Легковой автомобиль, движущийся по дороге с гравийным покрытием."],"c":0,"e":"<p>Колёсный трактор движется по дороге с усовершенствованным (булыжным) покрытием, а легковой — без усовершенствованного покрытия.</p> <p>Дорожных знаков приоритета перед перекрёстком нет, следовательно, колёсный трактор находится на главной дороге.</p>","image":"assets/adrive-questions/q100107102.jpg"},{"id":100107103,"themeId":1,"group":1001071,"chapter":1,"chapters":[1],"q":"Какое из транспортных средств в показанной ситуации находится на главной дороге?","a":["Грузовой автомобиль.","Легковой автомобиль."],"c":1,"e":"<p>На дороге, по которой движется легковой автомобиль, перед перекрёстком установлен дорожный знак 2.1 «Главная дорога» , поэтому легковой автомобиль находится на главной дороге.</p>","image":"assets/adrive-questions/q100107103.jpg"},{"id":100107104,"themeId":1,"group":1001071,"chapter":1,"chapters":[1],"q":"Какой из автомобилей находится на главной дороге?","a":["Красный автомобиль, подъехавший к перекрёстку по дороге с гравийным покрытием.","Синий автомобиль, подъехавший к перекрёстку по дороге с грунтовым покрытием.","Автомобили находятся перед перекрёстком равнозначных дорог."],"c":0,"e":"<p>Согласно определению, дорога с гравийным покрытием является главной по отношению к дороге с грунтовым покрытием.</p>","image":"assets/adrive-questions/q100107104.jpg"},{"id":100107161,"themeId":1,"group":1001071,"chapter":1,"chapters":[1],"q":"В данной ситуации, приближаясь по дороге с гравийным покрытием к примыканию справа дороги с грунтовым покрытием, Вы находитесь:","a":["На главной дороге.","На второстепенной дороге.","На дороге, равной по значению с примыкающей дорогой справа."],"c":0,"e":"<p>Дорога с гравийным покрытием является главной по отношению к дороге с грунтовым покрытием, если перед перекрёстком отсутствуют знаки, определяющие наличие главной или второстепенной дороги, либо предупреждающие о наличии перекрёстка равнозначных дорог.</p>","image":"assets/adrive-questions/q100107161.jpg"},{"id":100107241,"themeId":1,"group":1001072,"chapter":1,"chapters":[1],"q":"Является ли автопоезд комбинированным транспортным средством?","a":["Да, является.","Нет, не является."],"c":1,"e":"<p>Автопоезд — это состав транспортных средств, состоящий из автомобиля (колёсного трактора) и буксируемого им прицепа, прицепа-роспуска.</p> <p>Комбинированное транспортное средство — это состав транспортных средств, состоящий из грузового автомобиля, автомобиля-тягача, седельного тягача, колёсного трактора и буксируемого механического транспортного средства.<br> Поэтому автопоезд не является комбинированным транспортным средством.</p>","image":"assets/adrive-questions/q100107241.jpg"},{"id":100107242,"themeId":1,"group":1001072,"chapter":1,"chapters":[1],"q":"Является ли показанный состав транспортных средств комбинированным транспортным средством?","a":["Да, является.","Нет, не является."],"c":1,"e":"<p>Комбинированное транспортное средство — это состав транспортных средств, состоящий из грузового автомобиля, автомобиля-тягача, седельного тягача, колёсного трактора и буксируемого механического транспортного средства.<br> Поэтому состав транспортных средств, в котором буксирующее транспортное средство — легковой автомобиль, не является комбинированным транспортным средством.</p>","image":"assets/adrive-questions/q100107242.jpg"},{"id":100107243,"themeId":1,"group":1001072,"chapter":1,"chapters":[1],"q":"Является ли показанный состав транспортных средств комбинированным транспортным средством?","a":["Да, является.","Нет, не является."],"c":0,"e":"<p>Комбинированное транспортное средство — это состав транспортных средств, состоящий из грузового автомобиля, автомобиля-тягача, седельного тягача, колёсного трактора и буксируемого механического транспортного средства.<br> Поэтому показанный состав транспортных средств является комбинированным транспортным средством.</p>","image":"assets/adrive-questions/q100107243.jpg"},{"id":100107244,"themeId":1,"group":1001072,"chapter":1,"chapters":[1],"q":"Какой из показанных составов транспортных средств является комбинированным транспортным средством?","a":["Легковой автомобиль, буксирующий прицеп.","Грузовой автомобиль, буксирующий легковой автомобиль.","Оба являются.","Оба не являются."],"c":1,"e":"<p>Комбинированное транспортное средство — это состав транспортных средств, состоящий из грузового автомобиля, автомобиля-тягача, седельного тягача, колёсного трактора и буксируемого механического транспортного средства.</p> <p>Состав транспортных средств, в котором осуществляется буксировка прицепа, не является комбинированным транспортным средством.</p>","image":"assets/adrive-questions/q100107244.jpg"},{"id":100107301,"themeId":1,"group":1001073,"chapter":1,"chapters":[1],"q":"Какое из перечисленных дорожных покрытий является усовершенствованным?","a":["Покрытие из брусчатки.","Покрытие из булыжника.","Покрытие из асфальтобетонных смесей.","Все перечисленные."],"c":3,"e":"<p>Все перечисленные виды покрытия соответствуют термину «Усовершенствованное покрытие».</p>","image":null},{"id":100107302,"themeId":1,"group":1001073,"chapter":1,"chapters":[1],"q":"Какое из перечисленных дорожных покрытий является усовершенствованным?","a":["Покрытие из брусчатки.","Покрытие из шлаковых материалов, не обработанных органическими или минеральными вяжущими материалами.","Покрытие из гравийных материалов, не обработанных органическими или минеральными вяжущими материалами.","Все перечисленные."],"c":0,"e":"<p>Из перечисленных видов покрытия только покрытие дороги из брусчатки является усовершенствованным.</p> <p>Покрытие дороги из сыпучих материалов (шлаковых, гравийных) не является усовершенствованным, если оно не обработано специальными вяжущими материалами.</p>","image":null},{"id":100107303,"themeId":1,"group":1001073,"chapter":1,"chapters":[1],"q":"Какое из перечисленных дорожных покрытий является усовершенствованным?","a":["Покрытие из булыжника.","Покрытие из цементобетонных смесей.","Покрытие из щебёночных материалов, обработанных органическими или минеральными вяжущими материалами.","Все перечисленные."],"c":3,"e":"<p>Все перечисленные виды покрытия соответствуют термину «Усовершенствованное покрытие», в том числе и из щебёночных материалов, так как оно обработано специальными вяжущими материалами.</p>","image":null},{"id":100107304,"themeId":1,"group":1001073,"chapter":1,"chapters":[1],"q":"Считается ли дорожное покрытие из булыжника усовершенствованным?","a":["Да, считается.","Нет, не считается."],"c":0,"e":"<p>Дорожное покрытие из штучных материалов: брусчатки, булыжника, клинкера, мозаики и тому подобных является усовершенствованным наряду с покрытием дороги из асфальтобетонных или цементобетонных смесей.</p>","image":"assets/adrive-questions/q100107304.jpg"},{"id":100107501,"themeId":1,"group":1001075,"chapter":1,"chapters":[1],"q":"Что означает требование «уступить дорогу (предоставить преимущество)»?","a":["Остановиться перед дорожным знаком «Движение без остановки запрещено».","Прекратить дальнейшее движение, если другой участник движения находится на главной дороге.","Не возобновлять движение, снизить скорость движения вплоть до остановки транспортного средства или не осуществлять какой-либо манёвр (за исключением требования освободить занимаемую полосу движения, подаваемого регулировщиком или водителем транспортного средства оперативного назначения), если это может вынудить другого участника (других участников) дорожного движения изменить направление и (или) скорость движения."],"c":2,"e":"<p>Требование «уступить дорогу (предоставить преимущество)» не обязательно означает прекращение движения, оно гораздо шире и должно рассматриваться в контексте конкретной дорожной ситуации.</p> <p>Действия участника дорожного движения, который обязан уступить дорогу, не должны приводить к тому, что тот, кому он уступает дорогу, будет вынужден изменить направление движения и (или) скорость.</p>","image":null},{"id":100107502,"themeId":1,"group":1001075,"chapter":1,"chapters":[1],"q":"В каком случае водитель нарушит требование «уступить дорогу (предоставить преимущество)» по отношению к другим участникам дорожного движения?","a":["Если своими действиями он вынудит другого участника дорожного движения увеличить скорость без изменения направления движения.","Если своими действиями он вынудит другого участника дорожного движения повысить внимание без изменения скорости и направления движения.","Если своими действиями он вынудит другого участника дорожного движения продолжить движение без изменения скорости и направления движения.","Если своими действиями он вынудит другого участника дорожного движения подать предупредительный сигнал светом фар без изменения скорости и направления движения."],"c":0,"e":"<p>Требование «уступить дорогу (предоставить преимущество)» не будет выполнено, если это вынудит другого участника дорожного движения (имеющего преимущество) изменить скорость движения и (или) направление движения.</p>","image":null},{"id":100107503,"themeId":1,"group":1001075,"chapter":1,"chapters":[1],"q":"В каком случае водитель не нарушит требование «уступить дорогу» по отношению к другим участникам дорожного движения?","a":["Если своими действиями он вынудит другого участника дорожного движения увеличить скорость без изменения направления движения.","Если своими действиями он вынудит другого участника дорожного движения остановиться перед перекрёстком в занимаемой полосе движения.","Если своими действиями он вынудит другого участника дорожного движения вернуться в ранее занимаемую полосу движения без изменения скорости движения.","Если своими действиями он вынудит другого участника дорожного движения переключить дальний свет на ближний без изменения скорости и направления движения."],"c":3,"e":"<p>Требование «уступить дорогу» не будет нарушено, если это не вынудит другого участника дорожного движения (имеющего преимущество) изменить скорость движения и (или) направление движения.</p>","image":null},{"id":100107602,"themeId":1,"group":1001076,"chapter":1,"chapters":[1],"q":"В каком случае водитель не нарушит требование «уступить дорогу (предоставить преимущество)» по отношению к другим участникам дорожного движения?","a":["Если своими действиями он вынудит пешехода отказаться от перехода проезжей части двухполосной дороги.","Если своими действиями он вынудит другого участника дорожного движения осуществить обгон с увеличением скорости движения.","Если своими действиями он вынудит другого участника дорожного движения включить маячок синего цвета, уменьшив скорость, не изменяя направления движения.","Если своими действиями он вынудит другого участника дорожного движения подать звуковой сигнал и двигаться с особой осторожностью без изменения выбранной скорости движения и направления движения."],"c":3,"e":"<p>Требование «уступить дорогу (предоставить преимущество)» будет нарушено, если это вынудит другого участника дорожного движения (в том числе и пешехода) изменить скорость движения и (или) направление движения.</p>","image":null},{"id":100107801,"themeId":1,"group":1001078,"chapter":1,"chapters":[1],"q":"Кто из перечисленных ниже лиц является участником дорожного движения?","a":["Регулировщик.","Лицо, сдающее квалификационный практический экзамен на право управления механическим транспортным средством.","Работник городских тепловых сетей, выполняющий на дороге в установленном порядке внеплановые ремонтные работы.","Все перечисленные не являются участниками дорожного движения."],"c":1,"e":"<p>Согласно термину «Участник дорожного движения» не являются таковыми регулировщики и работники, выполняющие в установленном порядке на дороге ремонтные и другие работы.</p> <p>Все остальные лица, находящиеся в пределах дороги (в том числе и лицо, сдающее квалификационный практический экзамен на право управления механическим транспортным средством) являются участниками дорожного движения.</p>","image":null},{"id":100107802,"themeId":1,"group":1001078,"chapter":1,"chapters":[1],"q":"Кто из перечисленных ниже лиц не является участником дорожного движения?","a":["Водитель маршрутного транспортного средства.","Водитель транспортного средства оперативного назначения.","Лицо, обучаемое управлению механическим транспортным средством.","Сотрудник Военной автомобильной инспекции при обеспечении движения организованных транспортных колонн.","Все перечисленные."],"c":3,"e":"<p>Согласно термину «Участник дорожного движения» не являются таковыми регулировщики и работники, выполняющие в установленном порядке на дороге ремонтные и другие работы.</p> <p>Сотрудник Военной автомобильной инспекции Вооружённых Сил в соответствующей экипировке при обеспечении движения организованных транспортных колонн приравнен к регулировщику, соответственно он не является участником дорожного движения.</p>","image":null},{"id":100107803,"themeId":1,"group":1001078,"chapter":1,"chapters":[1],"q":"Кто из перечисленных ниже лиц является участником дорожного движения?","a":["Пешеход, ведущий велосипед по дороге.","Пешеход, передвигающийся в инвалидной коляске.","Водитель крупногабаритного транспортного средства.","Пассажир транспортного средства оперативного назначения.","Все перечисленные."],"c":4,"e":"<p>Согласно термину «Участник дорожного движения» не являются таковыми регулировщики и работники, выполняющие в установленном порядке на дороге ремонтные и другие работы.</p> <p>Все остальные лица, находящиеся в пределах дороги: водители, пассажиры и пешеходы — являются участниками дорожного движения.</p>","image":null},{"id":100107903,"themeId":1,"group":1001079,"chapter":1,"chapters":[1],"q":"Какие из перечисленных элементов (при их наличии) не являются элементами дороги?","a":["Обрезы.","Обочины.","Разделительные полосы.","Настилы железнодорожных переездов.","Все являются элементами дороги."],"c":0,"e":"<p>Согласно термину «Элементы дороги» из перечисленных вариантов обрезы не являются элементом дороги.</p> <p>Обрез дороги — это полоса земли с обеих сторон дороги предназначенная для обустройства велосипедных и пешеходных дорожек, защитных насаждений, линий связи и проч.</p>","image":null},{"id":100107935,"themeId":1,"group":1001079,"chapter":1,"chapters":[1],"q":"Что из нижеперечисленного соответствует термину «путепровод»?","a":["Инженерное сооружение, устраиваемое в местах пересечения дорог или дороги с железнодорожными путями для обеспечения беспрепятственного движения в разных уровнях.","Пересечение дороги с железнодорожными путями на одном уровне.","Соответствует всё перечисленное."],"c":0,"e":"<p>Путепровод — это инженерное сооружение, устраиваемое в местах пересечения дорог или дороги с железнодорожными путями для обеспечения беспрепятственного движения в разных уровнях.<br> Также целями обустройства путепроводов является повышение пропускной способности и обеспечение безопасности движения.</p>","image":null},{"id":100107971,"themeId":1,"group":1001079,"chapter":1,"chapters":[1],"q":"На каком из фрагментов изображения показан путепровод?","a":["Только на фрагменте «А».","Только на фрагменте «Б».","На обоих фрагментах показаны путепроводы."],"c":2,"e":"<p>Путепроводом является любое инженерное сооружение, устраиваемое в местах пересечения дорог или дороги с железнодорожными путями в разных уровнях. Поэтому то, что показано на обоих фрагментах изображения, считается путепроводами.</p>","image":"assets/adrive-questions/q100107971.jpg"},{"id":100108041,"themeId":1,"group":1001080,"chapter":1,"chapters":[1],"q":"Какое определение из нижеперечисленных соответствует термину «электромобиль»?","a":["Транспортное средство, приводимое в движение только электродвигателем от внутреннего перезаряжаемого источника электроэнергии.","Транспортное средство, приводимое в движение гибридным двигателем.","Транспортное средство, приводимое в движение электродвигателем, питание которого обеспечивается по подвесной контактной сети от внешнего источника электрического тока.","Все перечисленные соответствуют термину «электромобиль»."],"c":0,"e":"<p>Электромобилем является транспортное средство, приводимое в движение только электродвигателем от внутреннего перезаряжаемого источника электроэнергии.</p> <p>Иными словами, транспортные средства, приводимые в движение гибридными силовыми установками, а также питание электродвигателя которых может обеспечиваться от контактной сети, не являются электромобилями.</p>","image":null},{"id":100108101,"themeId":1,"group":1001081,"chapter":1,"chapters":[1],"q":"В случаях, не оговоренных Правилами дорожного движения, согласование дорожного движения осуществляется:","a":["Коммунальными службами.","Дорожно-эксплуатационной службой.","Государственной автомобильной инспекцией.","Департаментом «Белавтодор» Министерства транспорта и коммуникаций."],"c":2,"e":"<p>В случаях, не оговоренных Правилами дорожного движения, а также при применении в экспериментальных целях технических средств организации дорожного движения согласование дорожного движения осуществляется Государственной автомобильной инспекцией МВД.</p>","image":null},{"id":100108201,"themeId":1,"group":1001082,"chapter":1,"chapters":[1],"q":"Кто осуществляет согласование дорожного движения при применении в экспериментальных целях технических средств организации дорожного движения, не предусмотренных Правилами дорожного движения?","a":["Государственная автомобильная инспекция.","Транспортная инспекция Министерства транспорта и коммуникаций.","Республиканский орган государственного управления по стандартизации, метрологии и сертификации."],"c":0,"e":"<p>В случаях, не оговоренных Правилами дорожного движения, а также при применении в экспериментальных целях технических средств организации дорожного движения согласование дорожного движения осуществляется Государственной автомобильной инспекцией МВД.</p>","image":null},{"id":100108202,"themeId":1,"group":1001082,"chapter":1,"chapters":[1],"q":"В каких случаях на дорогах могут применяться технические средства организации дорожного движения, не предусмотренные Правилами дорожного движения?","a":["В случае согласования с ГАИ в экспериментальных целях.","В случае согласования с Министерством транспорта и коммуникаций на международных автотрассах.","В случае согласования с Министерством по чрезвычайным ситуациям при техногенных катастрофах и стихийных бедствиях."],"c":0,"e":"<p>Технические средства организации дорожного движения, не предусмотренные Правилами дорожного движения, могут применяться в экспериментальных целях по согласованию с ГАИ.</p>","image":null},{"id":100108271,"themeId":1,"group":1001082,"chapter":1,"chapters":[1],"q":"При встречном движении на тротуаре водители транспортных средств:","a":["Должны учитывать, что на дорогах установлено правостороннее движение.","Могут двигаться по любой стороне тротуара."],"c":0,"e":"<p>На дорогах Республики Беларусь установлено <strong>правостороннее движение транспортных средств</strong>. Это значит, что на элементах дороги, на которых организовано встречное движение (проезжая часть, велодорожка, тротуар и проч.), транспортные средства должны разъезжаться левыми бортами (держаться правее).</p>","image":"assets/adrive-questions/q100108271.jpg"},{"id":100108303,"themeId":1,"group":1001083,"chapter":1,"chapters":[1],"q":"В каком случае водитель может быть привлечён к ответственности за нарушения вступивших в силу изменений к Правилам дорожного движения?","a":["В любом случае.","Только в случае, если он ознакомлен с изменениями в Правилах дорожного движения."],"c":0,"e":"<p>Нарушение Правил дорожного движения влечёт ответственность, установленную законодательными актами.</p>","image":null},{"id":100200101,"themeId":1,"group":1002001,"chapter":2,"chapters":[2],"q":"На что из перечисленного не имеют права участники дорожного движения?","a":["Обеспечение безопасных и эффективных условий дорожного движения.","Получение от уполномоченных лиц государственных органов достоверной информации о безопасных условиях дорожного движения.","Получение от уполномоченных лиц государственных органов достоверной информации о наиболее оптимальных маршрутах движения.","Получение от уполномоченных лиц государственных органов достоверной информации о качестве продукции, работ и услуг, связанных с обеспечением безопасности дорожного движения."],"c":2,"e":"<p>Участники дорожного движения имеют право на обеспечение безопасных и эффективных условий дорожного движения, на получение от уполномоченных лиц государственных органов достоверной информации о безопасных условиях дорожного движения, на получение от уполномоченных лиц государственных органов достоверной информации о качестве продукции, работ и услуг, связанных с обеспечением безопасности дорожного движения.</p> <p>Что же касается предоставления информации о наиболее оптимальных маршрутах движения, то предоставление такой информации не входит в обязанности должностных лиц государственных органов.</p>","image":null},{"id":100200102,"themeId":1,"group":1002001,"chapter":2,"chapters":[2],"q":"На что из перечисленного не имеют права участники дорожного движения?","a":["Обеспечение безопасных условий дорожного движения.","Обеспечение эффективных условий дорожного движения.","Обеспечение безаварийных условий дорожного движения.","Имеют право на всё перечисленное."],"c":2,"e":"<p>Обеспечение безаварийных условий движения невозможно без соблюдения всеми участниками дорожного движения Правил дорожного движения и дополнительных мер безопасности, исходя из дорожных и погодных условий.</p>","image":null},{"id":100200103,"themeId":1,"group":1002001,"chapter":2,"chapters":[2],"q":"На что из перечисленного имеют право участники дорожного движения?","a":["Обеспечение эффективных условий дорожного движения.","Получение от уполномоченных лиц государственных органов достоверной информации о безопасных условиях дорожного движения.","Получение от уполномоченных лиц государственных органов достоверной информации о причинах введения ограничения или запрещения движения по дорогам.","Имеют право на всё перечисленное."],"c":3,"e":"<p>Участники дорожного движения имеют право и на обеспечение эффективных условий дорожного движения, и на получение от уполномоченных лиц государственных органов достоверной информации о безопасных условиях дорожного движения, о причинах введения ограничения или запрещения движения по дорогам.</p>","image":null},{"id":100200201,"themeId":1,"group":1002002,"chapter":2,"chapters":[2],"q":"Кто из участников дорожного движения имеет право на получение медицинской помощи в случае ДТП?","a":["Только лица, имеющие договор страхования здоровья.","Только лица, не нарушавшие Правила дорожного движения на момент совершения ДТП.","Имеют все участники дорожного движения."],"c":2,"e":"<p>Каждый участник дорожного движения имеет право на получение медицинской помощи в случае ДТП вне зависимости от наличия и степени вины в совершении происшествия, а также без договора страхования жизни и здоровья.</p>","image":"assets/adrive-questions/q100200201.jpg"},{"id":100200202,"themeId":1,"group":1002002,"chapter":2,"chapters":[2],"q":"На что имеет право участник дорожного движения в случае ДТП?","a":["На получение медицинской помощи.","На обжалование в порядке, определённом законодательством, решений, действий (бездействия) должностных лиц государственных органов, осуществляющих государственное регулирование и управление в сфере дорожного движения и обеспечения его безопасности.","На всё перечисленное."],"c":2,"e":"<p>Каждый участник дорожного движения в случае ДТП имеет право на получение медицинской помощи, и каждый участник дорожного движения имеет право на обжалование в порядке, определённом законодательством, решений, действий (бездействия) должностных лиц государственных органов, осуществляющих государственное регулирование и управление в сфере дорожного движения и обеспечения его безопасности.</p>","image":"assets/adrive-questions/q100200202.jpg"},{"id":100200301,"themeId":1,"group":1002003,"chapter":2,"chapters":[2],"q":"Если при ДТП был причинён вред здоровью или имуществу участников дорожного движения, имеют ли они право на возмещение причинённого им вреда?","a":["Имеют только водители.","Не имеют пассажиры транспортных средств, водители которых виновны в совершении ДТП.","Имеют все участники дорожного движения."],"c":2,"e":"<p>Каждый участник дорожного движения (как водитель, так и пассажир) в случае ДТП имеет право на возмещение причинённого им и (или) их имуществу вреда в порядке, установленном законодательством.</p>","image":"assets/adrive-questions/q100200301.jpg"},{"id":100200302,"themeId":1,"group":1002003,"chapter":2,"chapters":[2],"q":"Имеет ли право водитель на возмещение причинённого ему или его имуществу вреда в порядке, установленном законодательством?","a":["Имеет в любом случае.","Да, только если его автомобиль застрахован."],"c":0,"e":"<p>Водитель в случае ДТП имеет право на возмещение причинённого ему или его имуществу вреда в порядке, установленном законодательством. Причём данное право действует не только в отношении автомобиля, но и в отношении прочего имущества.</p>","image":null},{"id":100200401,"themeId":1,"group":1002004,"chapter":2,"chapters":[2],"q":"Что входит в обязанности участников дорожного движения?","a":["Только знать относящиеся к ним правила.","Знать и соблюдать относящиеся к ним требования Правил дорожного движения.","Знать весь текст Правил дорожного движения и соблюдать относящиеся к ним правила.","Знать и соблюдать относящиеся к ним требования Правил дорожного движения и требовать от остальных участников дорожного движения выполнения Правил."],"c":1,"e":"<p>Участник дорожного движения должен знать и соблюдать относящиеся к нему требования Правил дорожного движения, например пешеход не обязан знать правила расположения транспортных средств на проезжей части дороги, но требования, относящиеся к пешеходам, знать и соблюдать обязан.</p>","image":null},{"id":100200402,"themeId":1,"group":1002004,"chapter":2,"chapters":[2],"q":"Что входит в обязанности участников дорожного движения?","a":["Знать относящиеся к ним требования Правил дорожного движения.","Соблюдать относящиеся к ним требования Правил дорожного движения.","Всё перечисленное."],"c":2,"e":"<p>Участник дорожного движения должен знать и соблюдать относящиеся к нему требования Правил дорожного движения.</p> <p>Невозможно добиться соблюдения Правил дорожного движения, если участники дорожного движения не знают относящиеся к ним требования.</p>","image":null},{"id":100200501,"themeId":1,"group":1002005,"chapter":2,"chapters":[2],"q":"Чем обязаны руководствоваться участники дорожного движения?","a":["Дорожными знаками.","Сигналами светофоров.","Сигналами регулировщика.","Горизонтальной и вертикальной дорожной разметкой.","Всем перечисленным."],"c":4,"e":"<p>Участник дорожного движения должен руководствоваться сигналами регулировщика, а если он отсутствует — сигналами светофоров, а также руководствоваться при нахождении на дороге дорожными знаками и дорожной разметкой.</p>","image":null},{"id":100200502,"themeId":1,"group":1002005,"chapter":2,"chapters":[2],"q":"Кто из участников дорожного движения обязан руководствоваться сигналами регулировщика?","a":["Только водители.","Водители и пешеходы."],"c":1,"e":"<p>Сигналы регулировщика являются обязательными для исполнения всеми участниками дорожного движения.</p>","image":"assets/adrive-questions/q100200502.jpg"},{"id":100200601,"themeId":1,"group":1002006,"chapter":2,"chapters":[2],"q":"Что из нижеперечисленного входит в обязанности участников дорожного движения?","a":["Действовать добросовестно и корректно.","Быть внимательными и взаимно вежливыми.","Не создавать препятствий и опасности для дорожного движения.","Всё перечисленное."],"c":3,"e":"<p>Каждый участник дорожного движения обязан действовать добросовестно и корректно, быть внимательным и взаимно вежливым, принимать меры по обеспечению собственной безопасности и безопасности других участников движения, не создавать препятствий и опасности для дорожного движения. Только при таком условии может быть обеспечена безопасность дорожного движения.</p>","image":null},{"id":100200701,"themeId":1,"group":1002007,"chapter":2,"chapters":[2],"q":"Что обязаны выполнять участники дорожного движения при сопровождении детей?","a":["Принимать все возможные меры по недопущению их самостоятельного выхода на проезжую часть дороги, кроме пешеходных переходов.","Принимать все возможные меры по недопущению их самостоятельного выхода на проезжую часть дороги (кроме жилых и пешеходных зон).","Принимать все возможные меры по недопущению их самостоятельного выхода на проезжую часть дороги, включая жилые и пешеходные зоны."],"c":1,"e":"<p>Участники дорожного движения при сопровождении детей обязаны принимать все возможные меры по недопущению их самостоятельного выхода на проезжую часть дороги (в том числе на пешеходных переходах, при пересечении дороги по линиям тротуаров или обочин, а также при посадке (высадке) детей в перевозящие их автобусы).</p> <p>Данное правило не действует в жилых и пешеходных зонах ввиду низкой скорости движения транспортных средств и преимущества в движении у пешеходов.</p> <p>Однако следует помнить, что немалое количество наездов на детей случается как раз на (или вблизи) дворовой территории, вблизи школ и дошкольных учреждений.</p>","image":"assets/adrive-questions/q100200701.jpg"},{"id":100200702,"themeId":1,"group":1002007,"chapter":2,"chapters":[2],"q":"Что обязаны выполнять участники дорожного движения при сопровождении детей?","a":["Обозначить детей световозвращающими элементами.","Провести инструктаж о правилах поведения на дорогах и в общественном транспорте.","Принимать все возможные меры по недопущению их самостоятельного выхода на проезжую часть дороги (кроме жилых и пешеходных зон).","Всё перечисленное."],"c":2,"e":"<p>Участники дорожного движения при сопровождении детей обязаны принимать все возможные меры по недопущению их самостоятельного выхода на проезжую часть дороги (в том числе на пешеходных переходах, при пересечении дороги по линиям тротуаров или обочин, а также при посадке (высадке) детей в перевозящие их автобусы).</p> <p>Данное правило не действует в жилых и пешеходных зонах ввиду низкой скорости движения транспортных средств и преимущества в движении у пешеходов.</p> <p>Однако следует помнить, что немалое количество наездов на детей случается как раз на (или вблизи) дворовой территории, вблизи школ и дошкольных учреждений.</p> <p>И хоть Правила дорожного движения не обязывают проводить обязательный инструктаж по правилам поведения на дорогах и не требуется обозначать ребёнка световозвращающими элементами (кроме движения по краю проезжей части или обочине в тёмное время суток), меры дополнительной предосторожности не будут лишними.</p>","image":"assets/adrive-questions/q100200702.jpg"},{"id":100200801,"themeId":1,"group":1002008,"chapter":2,"chapters":[2],"q":"Что из нижеперечисленного не входит в обязанности участников дорожного движения?","a":["Принимать меры по задержанию лиц, загрязняющих дороги.","Не выбрасывать мусор и иные предметы вне специально отведённых мест.","Принимать меры по недопущению загрязнения дорог и окружающей среды.","Участники дорожного движения обязаны выполнить всё перечисленное."],"c":0,"e":"<p>Участники дорожного движения не обязаны принимать меры по задержанию лиц, загрязняющих дороги, но можно оказать содействие правоохранительным органам в установлении лиц, загрязняющих дороги для дальнейшего их привлечения к административной ответственности.</p>","image":null},{"id":100200802,"themeId":1,"group":1002008,"chapter":2,"chapters":[2],"q":"Разрешено ли участникам дорожного движения выбрасывать мусор на дорогах?","a":["Нет, не разрешено.","Разрешено в специально отведённых местах.","Разрешено, если это не приводит к загрязнению дорог.","Разрешено вне населённых пунктов и охраняемых территорий."],"c":1,"e":"<p>Участники дорожного движения обязаны не загрязнять дорогу и окружающую среду.</p> <p>Мусор и иные предметы разрешено выбрасывать только в отведённых для этого местах.</p>","image":null},{"id":100300101,"themeId":1,"group":1003001,"chapter":3,"chapters":[3],"q":"Укажите, какие права имеет водитель:","a":["Управлять транспортным средством в установленном порядке.","Знать причину, по которой остановлено его транспортное средство.","Передавать управление другому лицу, имеющему при себе водительское удостоверение соответствующей категории.","Все перечисленные."],"c":3,"e":"<p>Водитель имеет право управлять транспортным средством в установленном порядке (после достижения установленного возраста и получения водительского удостоверения соответствующей категории) и передавать управление другому лицу, имеющему при себе водительское удостоверение соответствующей категории, убедившись, что данное лицо не находится в состоянии, при котором запрещено управлять транспортным средством.</p> <p>Должностные лица, имеющие право остановки транспортных средств, могут останавливать транспортные средства только для осуществления возложенных на них функций, поэтому водитель также вправе знать причину, по которой остановлено его транспортное средство.</p>","image":null},{"id":100300102,"themeId":1,"group":1003001,"chapter":3,"chapters":[3],"q":"Кому водитель имеет право передавать управление транспортным средством?","a":["Владельцу транспортного средства.","Сотруднику милиции при выполнении неотложного служебного задания.","Лицу, имеющему при себе водительское удостоверение соответствующей категории.","Всем перечисленным."],"c":2,"e":"<p>Водитель имеет право передавать управление другому лицу, имеющему при себе водительское удостоверение соответствующей категории, убедившись, что данное лицо не находится в состоянии, при котором запрещено управлять транспортным средством.</p>","image":null},{"id":100300133,"themeId":1,"group":1003001,"chapter":3,"chapters":[3],"q":"Укажите, какие права имеет водитель:","a":["Иметь при себе и передавать для проверки сотрудникам ГАИ водительское удостоверение.","Своевременно получать на механическое транспортное средство, находящееся в его владении, разрешение на допуск транспортного средства к участию в дорожном движении.","Передавать управление другому лицу, имеющему при себе водительское удостоверение соответствующей категории.","Все перечисленные."],"c":2,"e":"<p>Водитель имеет право передавать управление другому лицу, имеющему при себе водительское удостоверение соответствующей категории, убедившись, что данное лицо не находится в состоянии, при котором запрещено управлять транспортным средством.</p> <p>Оставшиеся варианты ответов относятся не к правам водителя, а к его обязанностям.</p>","image":null},{"id":100300202,"themeId":1,"group":1003002,"chapter":3,"chapters":[3],"q":"Обязан ли сотрудник ГАИ, остановивший транспортное средство, предъявить водителю служебное удостоверение?","a":["Нет, не обязан.","Обязан предъявить по требованию водителя.","Обязан в случае, если зафиксировал нарушение водителем Правил дорожного движения."],"c":1,"e":"<p>Если водитель сомневается, что перед ним находится сотрудник ГАИ, либо хочет обжаловать его решения, действия, он может потребовать предъявить его служебное удостоверение. Сотрудник ГАИ в таком случае обязан его предъявить.</p>","image":"assets/adrive-questions/q100300202.jpg"},{"id":100300203,"themeId":1,"group":1003002,"chapter":3,"chapters":[3],"q":"Обязан ли сотрудник ГАИ, остановивший транспортное средство, предъявить водителю служебное удостоверение?","a":["Обязан предъявить по требованию водителя.","Обязан только вне населённых пунктов в тёмное время суток.","Обязан только вне населённых пунктов при отсутствии транспортного средства оперативного назначения."],"c":0,"e":"<p>Если водитель сомневается, что перед ним находится сотрудник ГАИ, либо хочет обжаловать его решения, действия, он может потребовать предъявить его служебное удостоверение. Сотрудник ГАИ в таком случае обязан его предъявить.</p>","image":null},{"id":100300302,"themeId":1,"group":1003003,"chapter":3,"chapters":[3],"q":"Что должен предъявить по требованию водителя сотрудник ГАИ, остановивший транспортное средство?","a":["Страховой полис.","Технический паспорт.","Служебное удостоверение.","Водительское удостоверение.","Всё перечисленное."],"c":2,"e":"<p>Сотрудник ГАИ, остановивший транспортное средство, обязан предъявить по требованию водителя служебное удостоверение.</p>","image":null},{"id":100300401,"themeId":1,"group":1003004,"chapter":3,"chapters":[3],"q":"Какие из перечисленных прав есть у водителя?","a":["Получать медицинскую помощь в случае дорожно-транспортного происшествия.","Знать причину, по которой сотрудником ГАИ остановлено транспортное средство, а также его фамилию и должность.","Передавать управление другому лицу, имеющему при себе водительское удостоверение на право управления механическим транспортным средством соответствующей категории.","Все перечисленные."],"c":3,"e":"<p>Водитель имеет право передавать управление другому лицу, имеющему при себе водительское удостоверение соответствующей категории, убедившись, что данное лицо не находится в состоянии, при котором запрещено управлять транспортным средством.</p> <p>Также водитель имеет право знать, по какой причине сотрудник ГАИ остановил его транспортное средство.</p> <p>Кроме того, водитель, как участник дорожного движения, на основании положений второй главы Правил дорожного движения имеет право на получение медицинской помощи в случае дорожно-транспортного происшествия.</p>","image":null},{"id":100300403,"themeId":1,"group":1003004,"chapter":3,"chapters":[3],"q":"Какие из перечисленных прав есть у водителя?","a":["Знать причину, по которой сотрудником ГАИ остановлено транспортное средство, а также его фамилию и должность.","Передавать управление другому лицу, имеющему при себе водительское удостоверение на право управления механическим транспортным средством другой категории.","Все перечисленные."],"c":0,"e":"<p>Водитель имеет право передавать управление другому лицу, имеющему при себе водительское удостоверение только соответствующей категории, убедившись, что данное лицо не находится в состоянии, при котором запрещено управлять транспортным средством.</p> <p>Также водитель имеет право знать, по какой причине сотрудник ГАИ остановил его транспортное средство.</p>","image":null},{"id":100300404,"themeId":1,"group":1003004,"chapter":3,"chapters":[3],"q":"Каким правом из перечисленных не обладает водитель?","a":["На обжалование решения должностного лица ГАИ.","На получение медицинской помощи в случае дорожно-транспортного происшествия.","На передачу управления другому лицу, имеющему право на управление транспортным средством другой категории.","На получение достоверной информации о безопасных условиях дорожного движения, причинах введения ограничения или запрещения движения по дорогам.","Обладает всеми перечисленными правами."],"c":2,"e":"<p>Водитель имеет право передавать управление другому лицу, имеющему при себе водительское удостоверение только соответствующей категории, убедившись, что данное лицо не находится в состоянии, при котором запрещено управлять транспортным средством.</p> <p>Остальными перечисленными правами водитель обладает, исходя из положений второй главы, как участник дорожного движения.</p>","image":null},{"id":100300601,"themeId":1,"group":1003006,"chapter":3,"chapters":[3],"q":"Каким образом сотрудником ГАИ может выражаться требование об остановке транспортного средства?","a":["Жестом руки.","Путём подачи сигнала жезлом.","С помощью громкоговорящего устройства.","Путём включения на транспортном средстве оперативного назначения маячка красного цвета.","Может выражаться всеми перечисленными способами."],"c":4,"e":"<p>Сотрудник ГАИ может, исходя из обстановки, подать сигнал об остановке транспортного средства жезлом, жестом руки, с помощью громкоговорящего устройства и путём включения на транспортном средстве оперативного назначения маячка красного цвета.</p>","image":null},{"id":100300602,"themeId":1,"group":1003006,"chapter":3,"chapters":[3],"q":"Что должны использовать для подачи сигнала об остановке транспортного средства должностные лица органов внутренних дел (кроме сотрудников ГАИ)?","a":["Жезл.","Красный флажок.","Громкоговорящее устройство.","Диск с красным сигналом (световозвращателем)."],"c":3,"e":"<p>Должностные лица органов внутренних дел, кроме сотрудников ГАИ, для подачи сигнала об остановке транспортного средства должны использовать диск с красным сигналом (световозвращателем).</p>","image":null},{"id":100300603,"themeId":1,"group":1003006,"chapter":3,"chapters":[3],"q":"Каким образом сотрудником ГАИ не может выражаться требование об остановке транспортного средства?","a":["Жестом руки.","С помощью громкоговорящего устройства.","Путём включения на транспортном средстве оперативного назначения маячка синего цвета.","Может выражаться всеми перечисленными способами."],"c":2,"e":"<p>Сотрудник ГАИ может, исходя из обстановки, подать сигнал об остановке транспортного средства жезлом, жестом руки, с помощью громкоговорящего устройства и путём включения на транспортном средстве оперативного назначения маячка красного цвета.</p> <p>Включение на транспортном средстве оперативного назначения маячка синего цвета означает, что водители движущихся транспортных средств должны снизить скорость и остановиться в случае необходимости, но если необходимости остановки нет, водители могут продолжать движение, не останавливаясь.</p>","image":null},{"id":100300701,"themeId":1,"group":1003007,"chapter":3,"chapters":[3],"q":"Должностные лица каких из перечисленных органов не имеют права остановки транспортных средств для осуществления возложенных на указанные органы функций?","a":["Органов пограничной службы.","Вооружённых Сил.","Министерства по чрезвычайным ситуациям.","Внутренних войск Министерства внутренних дел.","Все перечисленные имеют право остановки транспортных средств."],"c":2,"e":"<p>Все перечисленные должностные лица, кроме Министерства по чрезвычайным ситуациям, имеют право остановки транспортного средства для осуществления возложенных на указанные органы функций.</p>","image":null},{"id":100300702,"themeId":1,"group":1003007,"chapter":3,"chapters":[3],"q":"Должностные лица каких из перечисленных органов имеют права остановки транспортных средств для осуществления возложенных на указанные органы функций?","a":["Органов внутренних дел.","Органов государственной охраны.","Вооружённых Сил.","Государственной инспекции охраны животного и растительного мира при Президенте Республики Беларусь.","Всех перечисленных."],"c":4,"e":"<p>Должностные лица всех перечисленных органов имеют право остановки транспортных средств, но только для осуществления возложенных на указанные органы функций.</p>","image":null},{"id":100300703,"themeId":1,"group":1003007,"chapter":3,"chapters":[3],"q":"Должностные лица каких из перечисленных органов имеют права остановки транспортных средств для осуществления возложенных на указанные органы функций?","a":["Государственной лесной охраны.","Органов государственной безопасности.","Вооружённых Сил.","Органов финансовых расследований Комитета государственного контроля.","Всех перечисленных."],"c":4,"e":"<p>Должностные лица всех перечисленных органов имеют право остановки транспортных средств, но только для осуществления возложенных на указанные органы функций.</p>","image":null},{"id":100300801,"themeId":1,"group":1003008,"chapter":3,"chapters":[3],"q":"Какие документы из перечисленных обязан передавать для проверки водитель механического транспортного средства должностным лицам (кроме сотрудника ГАИ), имеющим право остановки транспортного средства для осуществления возложенных на них функций?","a":["Водительское удостоверение или документ, удостоверяющий его личность.","Документ, подтверждающий заключение договора обязательного страхования гражданской ответственности владельца транспортного средства.","Все перечисленные."],"c":0,"e":"<p>Должностным лицам органов, имеющих право остановки транспортных средств (кроме сотрудников ГАИ), водитель обязан передавать для проверки документ, удостоверяющий его личность, или водительское удостоверение.</p>","image":null},{"id":100300802,"themeId":1,"group":1003008,"chapter":3,"chapters":[3],"q":"Какие документы из перечисленных обязан передавать для проверки водитель механического транспортного средства, эксплуатируемого индивидуальным предпринимателем, должностным лицам Транспортной инспекции Министерства транспорта и коммуникаций?","a":["Свидетельство о регистрации (технический паспорт, технический талон) механического транспортного средства, прицепа (прицепов) к нему.","Транспортные документы, предусмотренные законодательными актами.","Водительское удостоверение или документ, удостоверяющий его личность.","Все перечисленные."],"c":3,"e":"<p>Должностным лицам Транспортной инспекции Министерства транспорта и коммуникаций водитель механического транспортного средства, эксплуатируемого юридическим лицом или индивидуальным предпринимателем, обязан передавать для проверки документ, удостоверяющий его личность, или водительское удостоверение, свидетельство о регистрации (технический паспорт, технический талон) механического транспортного средства, прицепа (прицепов) к нему, а также транспортные документы, предусмотренные законодательными актами.</p>","image":null},{"id":100300901,"themeId":1,"group":1003009,"chapter":3,"chapters":[3],"q":"Какие документы из указанных водитель обязан предъявлять сотруднику таможенных органов в соответствии с Правилами дорожного движения?","a":["Документ, удостоверяющий личность, или водительское удостоверение.","Разрешение на допуск транспортного средства к участию в дорожном движении.","Оба документа."],"c":0,"e":"<p>Должностным лицам органов имеющих право остановки транспортных средств (кроме сотрудников ГАИ), водитель обязан передавать для проверки документ, удостоверяющий его личность, или водительское удостоверение.</p>","image":null},{"id":100300902,"themeId":1,"group":1003009,"chapter":3,"chapters":[3],"q":"Обязан ли водитель автомобиля иметь при себе и передавать для проверки сотрудникам ГАИ медицинскую справку?","a":["Да, обязан.","Нет, не обязан."],"c":1,"e":"<p>Водитель автомобиля не обязан иметь при себе и передавать для проверки сотрудникам ГАИ медицинскую справку.</p>","image":null},{"id":100300941,"themeId":1,"group":1003009,"chapter":3,"chapters":[3],"q":"Какие из перечисленных документов водитель механического транспортного средства обязан иметь при себе и передавать для проверки сотрудникам ГАИ?","a":["Разрешение на допуск транспортного средства к участию в дорожном движении.","Разрешение органа связи на использование средств радио- и спутниковой связи при их наличии на транспортном средстве.","Свидетельство о регистрации (технический паспорт, технический талон) механического транспортного средства, прицепа (прицепов) к нему.","Все перечисленные документы."],"c":2,"e":"<p>Водитель механического транспортного средства обязан иметь при себе и передавать для проверки сотрудникам ГАИ:</p> <ul><li>водительское удостоверение,</li> <li>свидетельство о регистрации (технический паспорт, технический талон) механического транспортного средства, прицепа (прицепов) к нему,</li> <li>документ, подтверждающий заключение договора обязательного страхования гражданской ответственности владельца транспортного средства (договор внутреннего страхования, либо договор комплексного внутреннего страхования, либо договор пограничного страхования, либо договор союзного страхования, либо договор страхования, заключённый со страховой организацией государства, с уполномоченной организацией которого Белорусским бюро по транспортному страхованию заключено соглашение о сотрудничестве, и действительный на территории Республики Беларусь, либо договор страхования, заключённый в рамках межгосударственной (международной) системы страхования Союзного государства со страховой организацией Российской Федерации), за исключением случая заключения договора страхования в электронном виде;</li> <li>документы, подтверждающие правомерность установки опознавательного знака «Инвалид» при его наличии на транспортном средстве, за исключением иностранных граждан и лиц без гражданства.</li></ul>","image":"assets/adrive-questions/q100300941.jpg"},{"id":100301001,"themeId":1,"group":1003010,"chapter":3,"chapters":[3],"q":"По требованию какого должностного лица водитель обязан пройти в установленном порядке проверку на предмет определения состояния алкогольного опьянения?","a":["По требованию сотрудника ГАИ.","По требованию должностного лица органов государственной безопасности.","По требованию должностного лица Транспортной инспекции Министерства транспорта и коммуникаций.","Всех перечисленных."],"c":0,"e":"<p>Водитель обязан пройти в установленном порядке проверку на предмет определения состояния алкогольного опьянения только по требованию сотрудника ГАИ.</p>","image":null},{"id":100301002,"themeId":1,"group":1003010,"chapter":3,"chapters":[3],"q":"Обязан ли водитель пройти в установленном порядке проверку на предмет определения состояния алкогольного опьянения по требованию сотрудника ГАИ?","a":["Обязан только в случае нарушения Правил дорожного движения.","Обязан только в случае участия в дорожно-транспортном происшествии.","Обязан в любом случае."],"c":2,"e":"<p>Водитель обязан пройти в установленном порядке проверку на предмет определения состояния алкогольного опьянения по требованию сотрудника ГАИ независимо от обстоятельств остановки транспортного средства.</p>","image":null},{"id":100301141,"themeId":1,"group":1003011,"chapter":3,"chapters":[3],"q":"На каких транспортных средствах перед перевозкой пассажира водитель обязан убедиться, что его пассажир не находится в состоянии алкогольного опьянения?","a":["На мопеде, мотоцикле (кроме перевозки в боковом прицепе к мотоциклу).","На мопеде, мотоцикле (в том числе при перевозке в боковом прицепе к мотоциклу).","На мопеде, мотоцикле или легковом автомобиле.","На мопеде, мотоцикле, легковом или грузовом автомобиле."],"c":0,"e":"<p>Перед перевозкой пассажира на мопеде, мотоцикле (кроме бокового прицепа к мотоциклу) водитель обязан убедиться, что пассажир не находится в состоянии алкогольного опьянения либо в состоянии, вызванном потреблением наркотических средств, психотропных веществ, их аналогов, токсических или других одурманивающих веществ.</p>","image":null},{"id":100301142,"themeId":1,"group":1003011,"chapter":3,"chapters":[3],"q":"Разрешается ли мотоциклисту перевозить на заднем сиденье пассажира, находящегося в состоянии, вызванном потреблением лекарственных психотропных веществ?","a":["Да, только в ближайшее медицинское учреждение.","Нет, не разрешается."],"c":1,"e":"<p>Водителю запрещается перевозить на мопеде, мотоцикле (кроме бокового прицепа к мотоциклу) пассажира, заведомо для водителя находящегося в состоянии алкогольного опьянения либо в состоянии, вызванном потреблением наркотических средств, психотропных веществ, их аналогов, токсических или других одурманивающих веществ.</p>","image":"assets/adrive-questions/q100301142.jpg"},{"id":100301203,"themeId":1,"group":1003012,"chapter":3,"chapters":[3],"q":"Когда согласно Правилам дорожного движения водитель обязан проверять техническое состояние транспортного средства?","a":["Перед началом движения.","По возвращении к месту стоянки или хранения."],"c":0,"e":"<p>Водитель обязан перед началом движения проверить техническое состояние автомобиля, так как от этого напрямую зависит безопасность дорожного движения.</p> <p>Если водитель будет кроме того проверять техническое состояние транспортного средства и по возвращении к месту стоянки или ремонта — это очень хорошо, но в обязанности водителя такие действия согласно Правилам дорожного движения не входят.</p>","image":null},{"id":100301232,"themeId":1,"group":1003012,"chapter":3,"chapters":[3],"q":"Что из перечисленного входит в обязанности водителя?","a":["Содержать в чистоте стёкла и внешние световые приборы транспортного средства.","Проверять техническое состояние транспортного средства перед началом движения.","Содержать участвующее в дорожном движении транспортное средство в технически исправном состоянии.","Своевременно получать на находящееся в его владении (пользовании) механическое транспортное средство разрешение на допуск транспортного средства к участию в дорожном движении в порядке, установленном законодательством.","Всё перечисленное."],"c":4,"e":"<p>Водитель обязан перед началом движения проверить техническое состояние автомобиля. Водитель обязан содержать транспортное средство в технически исправном состоянии, содержать в чистоте стёкла и внешние световые приборы, а также своевременно получать на находящееся в его владении (пользовании) механическое транспортное средство разрешение на допуск транспортного средства к участию в дорожном движении.</p>","image":null},{"id":100301301,"themeId":1,"group":1003013,"chapter":3,"chapters":[3],"q":"Что из перечисленного обязан выполнить водитель перед началом движения?","a":["Отдохнуть не менее 14 часов.","Проверить техническое состояние транспортного средства.","Прогреть двигатель до температуры охлаждающей жидкости не менее 90 градусов.","Всё перечисленное."],"c":1,"e":"<p>Водитель обязан в соответствии с Правилами дорожного движения перед началом движения проверить техническое состояние автомобиля.</p> <p>Норма обязательного суточного отдыха водителя в ПДД не оговорена, при этом водителю запрещается при управлении находиться в утомлённом состоянии.</p> <p>Прогревать двигатель до оптимальной температуры охлаждающей жидкости нет необходимости, но при управлении автомобилем необходимо контролировать показания контрольно-измерительных приборов, в том числе температуру охлаждающей жидкости.</p>","image":null},{"id":100301302,"themeId":1,"group":1003013,"chapter":3,"chapters":[3],"q":"Если перед началом движения водитель обнаружил, что внешние световые приборы загрязнены, обязан ли он их очистить до начала движения?","a":["Обязан только в тёмное время суток.","Обязан только в тёмное время суток и в условиях недостаточной видимости.","Обязан в любом случае."],"c":2,"e":"<p>Водитель обязан в соответствии с Правилами дорожного движения содержать в чистоте стёкла и внешние световые приборы транспортного средства.</p> <p>Загрязнение стёкол ухудшает обзорность и видимость дороги, а загрязненные внешние световые приборы ухудшают видимость подаваемых сигналов и ухудшают освещённость дороги в тёмное время суток.</p>","image":null},{"id":100301401,"themeId":1,"group":1003014,"chapter":3,"chapters":[3],"q":"Разрешается ли перевозить в населённом пункте пассажиров с непристёгнутыми ремнями безопасности в транспортном средстве, оборудованном ремнями безопасности?","a":["Нет, не разрешается.","Да, разрешается в любых случаях.","Разрешается только на заднем сиденье."],"c":0,"e":"<p>Водитель обязан при движении, как вне населённого пункта, так и в населённом пункте быть пристёгнутым и не перевозить пассажиров с непристёгнутыми ремнями безопасности (кроме случаев, оговоренных в Правилах дорожного движения).</p>","image":null},{"id":100301403,"themeId":1,"group":1003014,"chapter":3,"chapters":[3],"q":"Обязан ли водитель автомобиля-такси, перевозя пассажира в населённом пункте в транспортном средстве, оборудованном ремнями безопасности, быть пристёгнутым?","a":["Да, обязан.","Нет, не обязан."],"c":1,"e":"<p>Водитель автомобиля-такси, перевозя пассажира (пассажиров), не обязан при движении в населённом пункте быть пристёгнутым, но при этом ему запрещается перевозить пассажиров с непристёгнутыми ремнями безопасности (кроме пассажиров с медицинскими противопоказаниями, перечень которых определяется Министерством здравоохранения).</p>","image":null},{"id":100301441,"themeId":1,"group":1003014,"chapter":3,"chapters":[3],"q":"Требуется ли от водителя показанного транспортного средства при движении быть в застёгнутом мотошлеме?","a":["Требуется, если оно соответствует термину «мопед».","Требуется, если оно соответствует термину «мотоцикл».","Требуется в любом случае.","Не требуется."],"c":2,"e":"<p>Водитель обязан при движении на мотоцикле, мопеде быть в застёгнутом мотошлеме независимо от особенностей их конструкции.</p>","image":"assets/adrive-questions/q100301441.jpg"},{"id":100301501,"themeId":1,"group":1003015,"chapter":3,"chapters":[3],"q":"Обязано ли быть пристёгнуто ремнём безопасности лицо, обучаемое управлению механическим транспортным средством?","a":["Не обязано при первоначальном обучении на автодроме.","Обязано только при обучении на дорогах общего пользования.","Обязано в любом случае."],"c":2,"e":"<p>Лицо, обучаемое управлению механическим транспортным средством, должно быть пристёгнуто ремнём безопасности.</p> <p>Допускается не пристёгиваться ремнём безопасности лицу, обучающему управлению механическим транспортным средством, когда транспортным средством управляет обучаемый управлению.</p>","image":null},{"id":100301502,"themeId":1,"group":1003015,"chapter":3,"chapters":[3],"q":"Обязано ли быть пристёгнуто ремнём безопасности лицо, обучающее управлению механическим транспортным средством, когда транспортным средством управляет лицо, обучаемое управлению механическим транспортным средством?","a":["Не обязано при первоначальном обучении на автодроме.","Не обязано только при обучении на дорогах общего пользования.","Не обязано."],"c":2,"e":"<p>Допускается не пристёгиваться ремнём безопасности лицу, обучающему управлению механическим транспортным средством, когда транспортным средством управляет обучаемый управлению.<br> Это связано с тем, что лицо, обучающее управлению может быть вынуждено вмешаться в управление транспортным средством для исправления ошибок обучаемого, в том числе для предотвращения создания аварийной ситуации.</p>","image":"assets/adrive-questions/q100301502.jpg"},{"id":100301603,"themeId":1,"group":1003016,"chapter":3,"chapters":[3],"q":"Кто из перечисленных лиц может не пристёгиваться ремнями безопасности при движении в транспортном средстве, оборудованном ремнями безопасности?","a":["Водитель автомобиля-такси во время перевозки пассажира в населённом пункте.","Пассажир транспортного средства оперативного назначения.","Пассажир с медицинскими противопоказаниями, перечень которых определяется Министерством здравоохранения.","Все перечисленные."],"c":3,"e":"<p><strong>Допускается не пристёгиваться ремнём безопасности:</strong></p> <ul> <li>лицу (водителю или пассажиру) с медицинскими противопоказаниями, перечень которых определяется Министерством здравоохранения,</li> <li>пассажиру транспортного средства оперативного назначения,</li> <li>водителю автомобиля-такси при движении в населённом пункте во время перевозки пассажира.</li></ul>","image":null},{"id":100301631,"themeId":1,"group":1003016,"chapter":3,"chapters":[3],"q":"Кто из перечисленных лиц может не пристёгиваться ремнями безопасности при движении в транспортном средстве, оборудованном ремнями безопасности?","a":["Водитель автомобиля-такси при движении в населённом пункте во время перевозки пассажира.","Лицо, обучающее управлению механическим транспортным средством, когда транспортным средством управляет обучаемый управлению.","Лицо, принимающее квалификационный практический экзамен на право управления транспортным средством, когда транспортным средством управляет лицо, сдающее такой экзамен.","Все перечисленные."],"c":3,"e":"<p>Допускается не пристёгиваться ремнём безопасности лицу, обучающему управлению механическим транспортным средством или принимающему квалификационный практический экзамен на право управления транспортным средством, когда транспортным средством управляет соответственно обучаемый управлению или лицо, сдающее такой экзамен.<br> Это связано с тем, что такое лицо может быть вынуждено вмешаться в управление транспортным средством для исправления ошибок обучаемого, а также для предотвращения создания аварийной ситуации.<br> Также допускается не пристёгиваться водителю автомобиля-такси — при движении в населённом пункте во время перевозки пассажира</p>","image":null},{"id":100301632,"themeId":1,"group":1003016,"chapter":3,"chapters":[3],"q":"Кто из перечисленных лиц может не пристёгиваться ремнями безопасности при движении в транспортном средстве, оборудованном ремнями безопасности?","a":["Водитель автомобиля-такси при движении вне населённого пункта.","Водитель автомобиля-такси при движении в населённом пункте, следуя к месту посадки пассажира.","Пассажир с медицинскими противопоказаниями, перечень которых определяется Министерством здравоохранения.","Все перечисленные."],"c":2,"e":"<p>Допускается не пристёгиваться ремнём безопасности лицу (водителю или пассажиру) с медицинскими противопоказаниями, перечень которых определяется Министерством здравоохранения.</p> <p>Остальные перечисленные лица обязаны быть пристёгнуты ремнями безопасности.</p>","image":null},{"id":100301801,"themeId":1,"group":1003018,"chapter":3,"chapters":[3],"q":"Кому из перечисленных лиц разрешено не пристёгиваться ремнями безопасности при движении в транспортном средстве, оборудованном ремнями безопасности, в населённом пункте?","a":["Водителю автомобиля-такси во время перевозки пассажира.","Пассажиру транспортного средства оперативного назначения.","Пассажиру и водителю с медицинскими противопоказаниями, перечень которых определяется Министерством здравоохранения.","Лицу, обучающему управлению механическим транспортным средством, когда транспортным средством управляет обучаемый управлению.","Всем перечисленным."],"c":4,"e":"<p><strong>Допускается не пристёгиваться</strong> ремнём безопасности <strong>лицу, обучающему управлению механическим транспортным средством</strong>, когда транспортным средством управляет обучаемый управлению.<br> Это связано с тем, что лицо, обучающее управлению, может быть вынуждено вмешаться в управление транспортным средством для исправления ошибок обучаемого, в том числе для предотвращения создания аварийной ситуации.</p> <p>Допускается также не пристёгиваться ремнём безопасности лицу (водителю или пассажиру) <strong>с медицинскими противопоказаниями</strong>, перечень которых определяется Министерством здравоохранения, <strong>пассажиру транспортного средства оперативного назначения</strong>, а также при движении <strong>в населённом пункте водителю автомобиля-такси во время перевозки пассажира</strong>.</p>","image":null},{"id":100301802,"themeId":1,"group":1003018,"chapter":3,"chapters":[3],"q":"Кто из перечисленных лиц должен пристёгиваться ремнями безопасности при движении в транспортном средстве, оборудованном ремнями безопасности, в населённом пункте?","a":["Пассажир автомобиля-такси.","Пассажир транспортного средства оперативного назначения.","Пассажир и водитель с медицинскими противопоказаниями, перечень которых определяется Министерством здравоохранения.","Все перечисленные."],"c":0,"e":"<p>Допускается также <strong>не пристёгиваться</strong> ремнём безопасности лицу (водителю или пассажиру) <strong>с медицинскими противопоказаниями</strong>, перечень которых определяется Министерством здравоохранения, и <strong>пассажиру транспортного средства оперативного назначения</strong>, а также при движении в населённом пункте — водителю автомобиля-такси.</p> <p>При этом <strong>пассажир автомобиля-такси должен быть пристёгнут ремнём безопасности</strong> как в населённом пункте, так и вне его.</p>","image":null},{"id":100301803,"themeId":1,"group":1003018,"chapter":3,"chapters":[3],"q":"Кому из перечисленных лиц разрешено не пристёгиваться ремнями безопасности при движении в транспортном средстве, оборудованном ремнями безопасности, вне населённого пункта?","a":["Водителю автомобиля-такси.","Пассажиру автомобиля-такси.","Пассажиру и водителю с медицинскими противопоказаниями, перечень которых определяется Министерством здравоохранения.","Всем перечисленным."],"c":2,"e":"<p>Допускается не пристёгиваться ремнём безопасности лицу (водителю или пассажиру) с медицинскими противопоказаниями, перечень которых определяется Министерством здравоохранения.</p> <p>При движении вне населённого пункта водитель и пассажир автомобиля-такси должны быть пристёгнуты ремнями безопасности.</p>","image":null},{"id":100302001,"themeId":1,"group":1003020,"chapter":3,"chapters":[3],"q":"В каких местах из перечисленных водителю разрешено переезжать разделительную полосу?","a":["В населённых пунктах.","В местах, обозначенных соответствующими дорожными знаками, дорожной разметкой, оборудованных ограждающими или направляющими устройствами.","Во всех перечисленных местах."],"c":1,"e":"<p>Разрешается переезжать разделительную полосу только в местах, обозначенных соответствующими дорожными знаками, дорожной разметкой, оборудованных ограждающими или направляющими устройствами.<br> Это связано с тем, что разделительная полоса разделяет смежные проезжие части дороги (транспортные потоки) и её пересечение в необозначенном месте может привести к созданию аварийной ситуации с участием транспортных средств, движущихся по смежной проезжей части дороги.</p> <p>В случае оборудования на разделительной полосе газона, пересечение разделительной полосы может привести также к повреждению растительного покрова и попаданию грязи на проезжую часть дороги.</p>","image":null},{"id":100302003,"themeId":1,"group":1003020,"chapter":3,"chapters":[3],"q":"В каких случаях водителю разрешено переезжать разделительную зону?","a":["Для разворота при отсутствии разрывов сплошной линии дорожной разметки.","В местах, обозначенных соответствующими дорожными знаками, дорожной разметкой, оборудованных ограждающими или направляющими устройствами.","Во всех перечисленных случаях."],"c":1,"e":"<p>Разрешается переезжать разделительную зону только в местах, обозначенных соответствующими дорожными знаками, дорожной разметкой, оборудованных ограждающими или направляющими устройствами.<br> Это связано с тем, что разделительная зона разделяет смежные проезжие части дороги (транспортные потоки) и её пересечение в необозначенном месте может привести к созданию аварийной ситуации с участием транспортных средств, движущихся по смежной проезжей части дороги.</p> <p>Кроме того, границы разделительной зоны определены сплошными линиями горизонтальной дорожной разметки, пересекать которые запрещено.</p>","image":null},{"id":100302102,"themeId":1,"group":1003021,"chapter":3,"chapters":[3],"q":"Как Вы должны поступить в показанной ситуации, управляя легковым автомобилем?","a":["Предоставить преимущество пешеходу.","Подать звуковой сигнал, чтобы привлечь внимание пешехода.","Выполнить оба перечисленных действия."],"c":0,"e":"<p>Водитель обязан предоставлять преимущество пешеходам на нерегулируемых пешеходных переходах.</p> <p>Преимущество пешеходу считается предоставленным, если расстояние между транспортным средством и приближающимся пешеходом (в момент пересечения транспортным средством траектории движения пешехода) составило не менее двух полос движения транспортного средства, а в случае, если между тротуаром и транспортным средством менее двух полос, — водителю необходимо следовать требованию «уступить дорогу (предоставить преимущество)».</p>","image":"assets/adrive-questions/q100302102.jpg"},{"id":100302241,"themeId":1,"group":1003022,"chapter":3,"chapters":[3],"q":"Предоставил ли преимущество мотоциклист пешеходу, проезжая безостановочно пешеходный переход в показанной ситуации?","a":["Нет, не предоставил.","Да, предоставил."],"c":0,"e":"<p>При подъезде к нерегулируемому пешеходному переходу водитель должен предоставить преимущество пешеходу. Преимущество пешеходу считается предоставленным, если расстояние между транспортным средством и приближающимся пешеходом (в момент пересечения транспортным средством траектории движения пешехода) составило не менее двух полос движения транспортного средства (в том числе одну полосу и трамвайные пути попутного направления).</p> <p>Поэтому в показанной ситуации водитель не предоставил преимущество, так как между транспортным средством и пешеходом — менее двух полос движения.</p>","image":"assets/adrive-questions/q100302241.jpg"},{"id":100302301,"themeId":1,"group":1003023,"chapter":3,"chapters":[3],"q":"В каком случае водителю разрешается покидать своё место или оставлять транспортное средство?","a":["Если приняты меры, исключающие возможность угона транспортного средства.","Если приняты меры, исключающие самопроизвольное движение транспортного средства.","Если приняты меры, исключающие произвольное срабатывание противоугонной звуковой сигнализации.","Если приняты все перечисленные меры."],"c":1,"e":"<p>Если водитель покидает транспортное средство, он обязан принять меры, исключающие самопроизвольное движение транспортного средства в зависимости от уклона и расположения места, выбранного для остановки.</p> <p>ДТП с участием неуправляемого транспортного средства — совсем не редкость.</p>","image":null},{"id":100302302,"themeId":1,"group":1003023,"chapter":3,"chapters":[3],"q":"В каком случае водителю разрешается покинуть своё место или оставить транспортное средство, не приняв меры, исключающие его самопроизвольное движение?","a":["Если он будет находиться рядом с транспортным средством.","Если транспортное средство находится на ровной площадке.","Если в транспортном средстве находится пассажир на переднем сиденье.","Запрещается во всех перечисленных случаях."],"c":3,"e":"<p>Если водитель покидает транспортное средство, он обязан принять меры, исключающие самопроизвольное движение транспортного средства.</p>","image":null},{"id":100302401,"themeId":1,"group":1003024,"chapter":3,"chapters":[3],"q":"Что из нижеперечисленного обязан выполнять водитель?","a":["Предоставлять транспортное средство для освобождения проезжей части дороги от транспортных средств, повреждённых при дорожно-транспортном происшествии.","Доставлять на управляемом транспортном средстве работников организаций здравоохранения для проезда к месту нахождения больного, жизнь которого находится под угрозой.","Доставлять на управляемом транспортном средстве лиц, нуждающихся в срочной медицинской помощи, в ближайшую организацию здравоохранения по требованию работников правоохранительных органов.","Всё перечисленное."],"c":3,"e":"<p>Водитель обязан доставлять на управляемом транспортном средстве работников организаций здравоохранения для проезда к месту нахождения больного, жизнь которого находится под угрозой, а также доставлять на управляемом транспортном средстве лиц, нуждающихся в срочной медицинской помощи, в ближайшую организацию здравоохранения по требованию работников правоохранительных органов и организаций здравоохранения.</p> <p>Также водитель обязан предоставлять транспортное средство (по требованию сотрудников ГАИ) для освобождения проезжей части дороги от транспортных средств, повреждённых при дорожно-транспортном происшествии.</p>","image":null},{"id":100302501,"themeId":1,"group":1003025,"chapter":3,"chapters":[3],"q":"Кого из перечисленных лиц обязан доставлять на управляемом транспортном средстве водитель согласно Правилам дорожного движения?","a":["Лицо, нуждающееся в срочной медицинской помощи, в ближайшую организацию здравоохранения по требованию работника правоохранительных органов.","Работника правоохранительных органов для выполнения неотложных служебных обязанностей, связанных с преследованием лица, подозреваемого в совершении преступления.","Всех перечисленных."],"c":2,"e":"<p>Водитель обязан доставлять на управляемом транспортном средстве работников правоохранительных органов для выполнения неотложных служебных обязанностей, связанных с преследованием лиц, подозреваемых в совершении преступлений, а также доставлять на управляемом транспортном средстве лиц, нуждающихся в срочной медицинской помощи, в ближайшую организацию здравоохранения по требованию работников правоохранительных органов.</p>","image":null},{"id":100302502,"themeId":1,"group":1003025,"chapter":3,"chapters":[3],"q":"Кого из перечисленных лиц обязан доставлять на управляемом транспортном средстве водитель согласно Правилам дорожного движения?","a":["Работников правоохранительных органов для проезда к месту нахождения больного, жизнь которого находится под угрозой.","Лиц, нуждающихся в срочной медицинской помощи, в ближайшую организацию здравоохранения по требованию работников правоохранительных органов.","Всех перечисленных."],"c":1,"e":"<p>Водитель обязан доставлять на управляемом транспортном средстве лиц, нуждающихся в срочной медицинской помощи, в ближайшую организацию здравоохранения по требованию работников правоохранительных органов, но при этом он не обязан доставлять на управляемом транспортном средстве работников правоохранительных органов для проезда к месту нахождения больного, жизнь которого находится под угрозой, в таком случае — только работников организаций здравоохранения.</p>","image":null},{"id":100302503,"themeId":1,"group":1003025,"chapter":3,"chapters":[3],"q":"В каком случае водитель не обязан доставлять на управляемом транспортном средстве работников правоохранительных органов?","a":["Для проезда к месту несения службы в попутном направлении.","Для выполнения неотложных служебных обязанностей, связанных с преследованием лиц, подозреваемых в совершении преступлений."],"c":0,"e":"<p>Водитель не обязан доставлять на управляемом транспортном средстве работников правоохранительных органов для проезда к месту работы.</p>","image":null},{"id":100302601,"themeId":1,"group":1003026,"chapter":3,"chapters":[3],"q":"Кого из перечисленных лиц обязан доставлять на управляемом транспортном средстве водитель согласно Правилам дорожного движения?","a":["Работников организаций здравоохранения для проезда к месту нахождения больного, жизнь которого находится под угрозой.","Лиц, нуждающихся в срочной медицинской помощи, в ближайшую организацию здравоохранения по требованию работников правоохранительных органов.","Лиц, нуждающихся в срочной медицинской помощи, в ближайшую организацию здравоохранения по требованию работников организаций здравоохранения.","Всех перечисленных."],"c":3,"e":"<p>Водитель обязан доставлять на управляемом транспортном средстве работников организаций здравоохранения для проезда к месту нахождения больного, жизнь которого находится под угрозой, а также доставлять на управляемом транспортном средстве лиц, нуждающихся в срочной медицинской помощи, в ближайшую организацию здравоохранения по требованию работников правоохранительных органов и организаций здравоохранения.</p>","image":null},{"id":100302602,"themeId":1,"group":1003026,"chapter":3,"chapters":[3],"q":"Кого из перечисленных лиц обязан доставлять на управляемом транспортном средстве водитель согласно Правилам дорожного движения?","a":["Работников Министерства по чрезвычайным ситуациям для проезда к месту стихийного бедствия.","Работников правоохранительных органов для проезда к месту нахождения больного, жизнь которого находится под угрозой.","Работников организаций здравоохранения для проезда к месту нахождения больного, жизнь которого находится под угрозой."],"c":2,"e":"<p>Водитель обязан доставлять на управляемом транспортном средстве для проезда к месту нахождения больного, жизнь которого находится под угрозой только работников организаций здравоохранения.</p> <p>Работников Министерства по чрезвычайным ситуациям для проезда к месту стихийного бедствия водитель доставлять не обязан.</p>","image":null},{"id":100302603,"themeId":1,"group":1003026,"chapter":3,"chapters":[3],"q":"Кого из перечисленных лиц обязан доставлять на управляемом транспортном средстве водитель согласно Правилам дорожного движения?","a":["Должностных лиц Министерства обороны к месту несения службы для выполнения неотложных служебных обязанностей.","Лиц, нуждающихся в срочной медицинской помощи, в ближайшую организацию здравоохранения по требованию работников правоохранительных органов.","Работников организаций здравоохранения для проезда к месту нахождения больного, жизни которого не угрожает опасность, для выполнения плановых процедур по оказанию медицинской помощи."],"c":1,"e":"<p>Водитель обязан доставлять на управляемом транспортном средстве для проезда к месту нахождения больного, жизнь которого находится под угрозой работников организаций здравоохранения.</p> <p>Доставка должностных лиц в иных перечисленных случаях в обязанности водителя не входит.</p>","image":null},{"id":100302841,"themeId":1,"group":1003028,"chapter":3,"chapters":[3],"q":"Кто из велосипедистов в показанной ситуации нарушает Правила дорожного движения, управляя велосипедом на тротуаре одной рукой?","a":["Только велосипедист, управляющий велосипедом левой рукой.","Только велосипедист, управляющий велосипедом правой рукой.","Оба велосипедиста нарушают.","Оба велосипедиста не нарушают."],"c":2,"e":"<p>Водителю запрещается двигаться на мотоцикле, мопеде, велосипеде на одном колесе, а также двигаться на мотоцикле, мопеде, велосипеде, не держась за руль обеими руками, за исключением случаев подачи сигнала рукой, или не держа ноги на педалях (подножках).</p>","image":"assets/adrive-questions/q100302841.jpg"},{"id":100303001,"themeId":1,"group":1003030,"chapter":3,"chapters":[3],"q":"Разрешается ли обучать управлению механическим транспортным средством в индивидуальном порядке на дорогах общего пользования?","a":["Разрешается только при наличии у обучающего водительского стажа не менее двух лет.","Разрешается только при наличии у обучающего водительского удостоверения соответствующей категории.","Разрешается при выполнении обоих условий.","Запрещается."],"c":3,"e":"<p>Обучение управлению механическим транспортным средством в индивидуальном порядке разрешается только на площадках или автодромах, закрытых для дорожного движения.</p>","image":null},{"id":100303002,"themeId":1,"group":1003030,"chapter":3,"chapters":[3],"q":"Разрешается ли обучать управлению механическим транспортным средством в индивидуальном порядке?","a":["Разрешается только на площадках или автодромах, закрытых для дорожного движения.","Разрешается только при наличии у обучающего водительского удостоверения и водительского стажа не менее двух лет.","Разрешается только при выполнении обоих условий.","Запрещается."],"c":2,"e":"<p>Обучение управлению механическим транспортным средством в индивидуальном порядке разрешается только на площадках или автодромах, закрытых для дорожного движения, при наличии у обучающего водительского удостоверения и водительского стажа не менее двух лет.</p>","image":null},{"id":100303003,"themeId":1,"group":1003030,"chapter":3,"chapters":[3],"q":"Разрешается ли обучать управлению механическим транспортным средством в индивидуальном порядке на дорогах общего пользования?","a":["Разрешается в случае дополнительного оборудования автомобиля педалями привода сцепления и тормоза для обучающего.","Разрешается в случае дополнительного оборудования автомобиля необходимым количеством зеркал заднего вида для обучающего.","Разрешается только при выполнении обоих условий.","Запрещается."],"c":3,"e":"<p>Обучение управлению механическим транспортным средством в индивидуальном порядке разрешается только на площадках или автодромах, закрытых для дорожного движения.</p>","image":null},{"id":100303101,"themeId":1,"group":1003031,"chapter":3,"chapters":[3],"q":"Разрешается ли обучать управлению механическим транспортным средством в индивидуальном порядке на дорогах общего пользования?","a":["Разрешается при достижении обучаемым необходимого возраста.","Разрешается при наличии у обучаемого необходимых знаний Правил дорожного движения.","Разрешается при наличии у обучаемого необходимых навыков управления, полученных при занятиях на закрытых для дорожного движения площадке или автодроме.","Разрешается только при выполнении всех перечисленных условий.","Запрещается."],"c":4,"e":"<p>Обучение управлению механическим транспортным средством в индивидуальном порядке разрешается только на площадках или автодромах, закрытых для дорожного движения.</p>","image":null},{"id":100303102,"themeId":1,"group":1003031,"chapter":3,"chapters":[3],"q":"Разрешается ли обучать управлению механическим транспортным средством в индивидуальном порядке при отсутствии у обучающего водительского удостоверения?","a":["Разрешается только на площадках или автодромах, закрытых для дорожного движения.","Разрешается только при наличии у обучающего водительского стажа не менее двух лет.","Разрешается только при выполнении обоих условий.","Запрещается."],"c":3,"e":"<p>Обучение управлению механическим транспортным средством в индивидуальном порядке разрешается только при наличии у обучающего водительского удостоверения и водительского стажа не менее двух лет.</p>","image":null},{"id":100303103,"themeId":1,"group":1003031,"chapter":3,"chapters":[3],"q":"Разрешается ли обучать управлению механическим транспортным средством в индивидуальном порядке при наличии у обучающего водительского стажа менее двух лет?","a":["Разрешается только при наличии у обучающего при себе водительского удостоверения.","Разрешается только на площадках или автодромах, закрытых для дорожного движения.","Разрешается только при выполнении обоих условий.","Запрещается."],"c":3,"e":"<p>Обучение управлению механическим транспортным средством в индивидуальном порядке разрешается только при наличии у обучающего водительского удостоверения и водительского стажа не менее двух лет.</p>","image":null},{"id":100303201,"themeId":1,"group":1003032,"chapter":3,"chapters":[3],"q":"Разрешается ли обучать управлению механическим транспортным средством в индивидуальном порядке на дорогах общего пользования?","a":["Разрешается только по дорогам с неинтенсивным движением вне населённых пунктов.","Разрешается, кроме участков улиц и дорог, где Министерством внутренних дел запрещено обучение управлению механическими транспортными средствами.","Запрещается."],"c":2,"e":"<p>Обучение управлению механическим транспортным средством в индивидуальном порядке разрешается только на площадках или автодромах, закрытых для дорожного движения.</p> <p>Обучение управлению механическим транспортным средством в индивидуальном порядке на дорогах общего пользования запрещено.</p>","image":null},{"id":100303232,"themeId":1,"group":1003032,"chapter":3,"chapters":[3],"q":"Разрешается ли обучать управлению механическим транспортным средством в индивидуальном порядке?","a":["Разрешается только по дорогам с неинтенсивным движением вне населённых пунктов.","Разрешается только на участках улиц и дорог, где Министерством внутренних дел не запрещено обучение управлению механическими транспортными средствами.","Разрешается только на площадках или автодромах, закрытых для дорожного движения, при наличии у обучающего водительского удостоверения и водительского стажа не менее двух лет.","Запрещается."],"c":2,"e":"<p>Обучение управлению механическим транспортным средством в индивидуальном порядке разрешается только на площадках или автодромах, закрытых для дорожного движения.</p> <p>При этом у обучающего при себе должно быть водительское удостоверение соответствующей категории и водительский стаж должен составлять не менее двух лет.</p>","image":null},{"id":100303501,"themeId":1,"group":1003035,"chapter":3,"chapters":[3],"q":"Разрешено ли управлять транспортным средством, если водитель находится в болезненном состоянии, ставящем под угрозу безопасность дорожного движения?","a":["Разрешено под воздействием лекарственных средств, повышающих внимание и быстроту реакции.","Разрешено на незначительные расстояния при наличии пассажира, контролирующего состояние водителя.","Запрещено."],"c":2,"e":"<p>Категорически запрещается управлять транспортным средством, находясь в болезненном состоянии, ставящем под угрозу безопасность дорожного движения.</p>","image":null},{"id":100303502,"themeId":1,"group":1003035,"chapter":3,"chapters":[3],"q":"Разрешено ли управлять транспортным средством, если водитель находится в болезненном состоянии, ставящем под угрозу безопасность дорожного движения?","a":["Разрешено при следовании в ближайшую организацию здравоохранения для получения срочной медицинской помощи.","Разрешено водителю транспортного средства оперативного назначения для выполнения неотложных служебных обязанностей, связанных с преследованием лиц, подозреваемых в совершении преступлений.","Запрещено."],"c":2,"e":"<p>Категорически запрещается управлять транспортным средством, находясь в болезненном состоянии, ставящем под угрозу безопасность дорожного движения.</p>","image":null},{"id":100303601,"themeId":1,"group":1003036,"chapter":3,"chapters":[3],"q":"В каком случае водителю, находящемуся под воздействием лекарственных препаратов, запрещено управлять транспортным средством?","a":["Если под воздействием лекарственных препаратов у него снижены внимание и быстрота реакции.","Если под воздействием лекарственных препаратов у него повышены внимание и быстрота реакции.","Если под воздействием лекарственных препаратов у него внимание и быстрота реакции не изменились.","Запрещено в любом случае."],"c":0,"e":"<p>Большинство лекарственных препаратов не влияют на возможности человека по управлению транспортным средством.</p> <p>Запрещается управлять транспортным средством только в том случае, если лекарственные препараты способствуют снижению внимания и ухудшают реакцию. Как правило, это обезболивающие и успокоительные средства.</p>","image":null},{"id":100303602,"themeId":1,"group":1003036,"chapter":3,"chapters":[3],"q":"Разрешено ли управлять транспортным средством, если водитель находится под воздействием лекарственных средств, снижающих внимание и быстроту реакции?","a":["Разрешено при доставке скоропортящихся грузов.","Разрешено при следовании в ближайшую организацию здравоохранения для получения срочной медицинской помощи.","Запрещено."],"c":2,"e":"<p>Запрещается управлять транспортным средством только в случае, если лекарственные препараты способствуют снижению внимания и ухудшают реакцию. Как правило, это обезболивающие и успокоительные средства.</p>","image":null},{"id":100303603,"themeId":1,"group":1003036,"chapter":3,"chapters":[3],"q":"Разрешено ли водителю управлять транспортным средством в состоянии утомления, ставящем под угрозу безопасность дорожного движения?","a":["Запрещено.","Разрешено при наличии пассажира на переднем сиденье.","Разрешено при движении после окончания рабочей смены к месту стоянки.","Разрешено после употребления препаратов, повышающих внимание и быстроту реакции."],"c":0,"e":"<p>Запрещается управлять транспортным средством в утомлённом состоянии, так как в таком состоянии у водителя снижается внимание и быстрота реакции, ухудшается зрение, водитель может уснуть при управлении автомобилем.</p>","image":null},{"id":100303801,"themeId":1,"group":1003038,"chapter":3,"chapters":[3],"q":"Разрешено ли участвовать в дорожном движении на транспортном средстве с загрязнениями (наслоениями), ограничивающими обзорность дороги?","a":["Разрешено при загрязнении стёкол вне зоны, очищаемой стеклоочистителями.","Разрешено при загрязнении заднего стекла при наличии наружных боковых зеркал заднего вида.","Разрешено при выполнении обоих условий.","Запрещено."],"c":3,"e":"<p>Запрещается управлять транспортным средством, у которого загрязнение стёкол ограничивает обзорность дороги.</p> <p>В случае сложных погодных условий необходимо периодически очищать от загрязнений стёкла и внешние световые приборы, в том числе площадь стёкол, находящуюся вне зоны, очищаемой стеклоочистителями.</p> <p>То же самое касается очистки стёкол от снега и инея, замерзания стёкол при движении (как правило, задних боковых) в зимнее время.</p>","image":null},{"id":100303802,"themeId":1,"group":1003038,"chapter":3,"chapters":[3],"q":"Водителю запрещается участие в дорожном движении, если максимальное расстояние, на котором невозможно различать днём в ясную погоду информацию на регистрационном знаке из-за его загрязнения, составляет:","a":["40 метров.","50 метров.","75 метров.","100 метров."],"c":0,"e":"<p>Водителю запрещается участвовать в дорожном движении на транспортном средстве с загрязнениями (наслоениями), ограничивающими обзорность дороги и не позволяющими различать днём в ясную погоду информацию на регистрационном знаке (временном номерном знаке) с расстояния 40 метров и менее.</p>","image":"assets/adrive-questions/q100303802.jpg"},{"id":100303803,"themeId":1,"group":1003038,"chapter":3,"chapters":[3],"q":"Разрешается ли водителю участвовать в дорожном движении на транспортном средстве с загрязнениями (наслоениями), не позволяющими различать днём в ясную погоду информацию на регистрационном знаке с расстояния 40 метров и менее?","a":["Разрешается при возможности видеть информацию на втором регистрационном знаке.","Разрешается при дублировании информации, размещённой на регистрационном знаке, на заднем борту грузового автомобиля или на задней части кузова автобуса.","Запрещается."],"c":2,"e":"<p>Водителю запрещается участвовать в дорожном движении на транспортном средстве с загрязнениями (наслоениями), ограничивающими обзорность дороги и не позволяющими различать днём в ясную погоду информацию на регистрационном знаке (временном номерном знаке) с расстояния 40 метров и менее даже при наличии дублирования информации на заднем борту (задней стороне кузова).</p>","image":"assets/adrive-questions/q100303803.jpg"},{"id":100303861,"themeId":1,"group":1003038,"chapter":3,"chapters":[3],"q":"Водителю запрещается участвовать в дорожном движении на транспортном средстве с загрязнениями (наслоениями), не позволяющими различать днём в ясную погоду информацию на регистрационном знаке (временном номерном знаке) с расстояния:","a":["40 метров и менее.","50 метров и менее.","100 метров и менее."],"c":0,"e":"<p>Водителю запрещается участвовать в дорожном движении на транспортном средстве с загрязнениями (наслоениями), не позволяющими различать днём в ясную погоду информацию на регистрационном знаке (временном номерном знаке) с расстояния 40 метров и менее.</p>","image":"assets/adrive-questions/q100303861.jpg"},{"id":100303902,"themeId":1,"group":1003039,"chapter":3,"chapters":[3],"q":"Разрешается ли водителю пользоваться во время движения транспортного средства мобильным телефоном?","a":["Разрешается только для отправки коротких текстовых сообщений.","Разрешается только если для этого нет необходимости держать телефон в руке либо воздействовать на него рукой.","Запрещается в любом случае."],"c":1,"e":"<p>Водителю запрещается пользоваться во время движения транспортного средства аппаратом радио- и телефонной связи, если для этого необходимо держать их в руке либо воздействовать на них рукой.</p>","image":null},{"id":100303903,"themeId":1,"group":1003039,"chapter":3,"chapters":[3],"q":"Разрешается ли водителю пользоваться во время движения транспортного средства мобильным телефоном?","a":["Разрешается для вызова экстренных служб.","Разрешается только если для этого нет необходимости держать телефон в руке либо воздействовать на него рукой.","Запрещается в любом случае.","Разрешается в любом случае."],"c":1,"e":"<p>Водителю запрещается пользоваться во время движения транспортного средства аппаратом радио- и телефонной связи, если для этого необходимо держать их в руке либо воздействовать на них рукой.</p>","image":null},{"id":100304001,"themeId":1,"group":1003040,"chapter":3,"chapters":[3],"q":"Что запрещается водителю?","a":["Управлять транспортным средством под воздействием лекарственных средств, повышающих внимание и быстроту реакции.","Двигаться на транспортном средстве с ошипованными шинами по дороге общего пользования с усовершенствованным покрытием.","Пользоваться во время движения аппаратом радио- и телефонной связи, если при этом не возникнет необходимости держать аппарат радио- и телефонной связи в руке либо воздействовать на него рукой.","Участвовать в дорожном движении на транспортном средстве с загрязнениями, не позволяющими различать днём в ясную погоду информацию на регистрационном знаке (временном номерном знаке) с расстояния 40 метров и менее.","Всё перечисленное."],"c":3,"e":"<p>Водителю разрешается управлять транспортным средством под воздействием лекарственных препаратов, не снижающих внимание и не ухудшающих реакцию, двигаться по дороге на транспортном средстве с ошипованными шинами, особенно в зимнее время при наличии гололедных явлений, пользоваться во время движения телефонной и радиосвязью, если при этом не возникнет необходимости держать аппарат радио- и телефонной связи в руке либо воздействовать на него рукой.</p> <p>Водителю запрещается управлять транспортным средством, у которого загрязнение регистрационного знака (временного номерного знака) не позволяет видеть информацию с расстояния 40 метров и менее.</p>","image":null},{"id":100304002,"themeId":1,"group":1003040,"chapter":3,"chapters":[3],"q":"Что запрещается водителю?","a":["Управлять транспортным средством под воздействием лекарственных средств, снижающих внимание и быстроту реакции.","Двигаться на транспортном средстве с металлическими шипами (кроме ошипованных шин) по дороге общего пользования с усовершенствованным покрытием.","Участвовать в дорожном движении на транспортном средстве с загрязнениями, не позволяющими различать днём в ясную погоду информацию на регистрационном знаке (временном номерном знаке) с расстояния 40 метров и менее.","Пользоваться во время движения аппаратом радио- и телефонной связи, если для этого необходимо держать его в руке либо воздействовать на него рукой.","Всё перечисленное."],"c":4,"e":"<p>Все перечисленные действия водителю запрещены, так как могут повлиять на безопасность дорожного движения, а регистрационные знаки (временные номерные знаки) должны быть чистыми и читаться днём в ясную погоду с расстояния не менее 40 метров.</p>","image":null},{"id":100304003,"themeId":1,"group":1003040,"chapter":3,"chapters":[3],"q":"В чём должен убедиться водитель, передавая управление транспортным средством лицу, имеющему при себе водительское удостоверение соответствующей категории?","a":["В том, что это лицо не находится в утомлённом состоянии.","В том, что это лицо не находится в состоянии алкогольного опьянения.","В том, что это лицо не находится под воздействием лекарственных препаратов, снижающих внимание и быстроту реакции.","Обязан убедиться во всём вышеперечисленном."],"c":1,"e":"<p>Водитель не всегда может безошибочно определить, находится ли другое лицо в утомлённом состоянии или под воздействием тех или иных лекарственных препаратов, но по определённым признакам можно безошибочно определить, что это лицо находится в состоянии алкогольного опьянения.</p>","image":null},{"id":100304301,"themeId":1,"group":1003043,"chapter":3,"chapters":[3],"q":"Какие документы водитель механического транспортного средства обязан иметь при себе и передавать для проверки сотрудникам ГАИ?","a":["Акт освидетельствования баллонов на газобаллонных транспортных средствах.","Акт выдачи механического транспортного средства владельцу после его переоборудования для работы на сжатом (сжиженном) газе.","Свидетельство о регистрации (технический паспорт, технический талон) механического транспортного средства.","Все перечисленные документы."],"c":2,"e":"<p>Водитель не обязан иметь при себе и передавать для проверки сотрудникам ГАИ акты освидетельствования газовых баллонов и выдачи механического транспортного средства владельцу после его переоборудования для работы на сжатом (сжиженном) газе на газобаллонных транспортных средствах.</p> <p>К перечню документов, которые водитель обязан иметь при себе и передавать для проверки сотрудникам ГАИ, относится свидетельство о регистрации (технический паспорт, технический талон) механического транспортного средства, прицепа (прицепов) к нему, а в отношении незарегистрированного транспортного средства — документ, подтверждающий законность его приобретения.</p>","image":null},{"id":100304332,"themeId":1,"group":1003043,"chapter":3,"chapters":[3],"q":"Какие документы водитель легкового автомобиля обязан иметь при себе и передавать для проверки сотрудникам ГАИ?","a":["Водительское удостоверение либо биометрический документ, удостоверяющий личность.","Документ, подтверждающий заключение договора обязательного страхования гражданской ответственности владельца транспортного средства, за исключением случаев заключения договора страхования в электронном виде.","Документы, подтверждающие правомерность установки опознавательного знака «Инвалид» при его наличии на транспортном средстве (за исключением иностранных граждан и лиц без гражданства).","Свидетельство о регистрации (технический паспорт, технический талон) механического транспортного средства, прицепа (прицепов) к нему, а в отношении незарегистрированного транспортного средства - документ, подтверждающий законность его приобретения.","Все перечисленные документы."],"c":4,"e":"<p>Водитель легкового автомобиля обязан иметь при себе и передавать для проверки сотрудникам ГАИ все перечисленные документы.</p>","image":null},{"id":100304501,"themeId":1,"group":1003045,"chapter":3,"chapters":[3],"q":"Кому из перечисленных должностных лиц водитель обязан передавать для проверки свидетельство о регистрации механического транспортного средства?","a":["Сотруднику ГАИ.","Сотруднику Военной автомобильной инспекции.","Государственному инспектору Министерства по налогам и сборам.","Всем перечисленным лицам."],"c":0,"e":"<p>Водитель обязан иметь при себе и передавать для проверки сотрудникам ГАИ свидетельство о регистрации механического транспортного средства (техпаспорт).</p>","image":null},{"id":100304502,"themeId":1,"group":1003045,"chapter":3,"chapters":[3],"q":"Разрешается ли водителю механического транспортного средства не иметь при себе документ, подтверждающий заключение договора обязательного страхования гражданской ответственности владельца транспортного средства?","a":["Разрешается, если водитель не является владельцем транспортного средства.","Разрешается, если договор внутреннего страхования заключён в электронном виде.","Разрешается до десяти суток с момента государственной регистрации транспортного средства."],"c":1,"e":"<p>Водитель не обязан иметь при себе договор обязательного страхования гражданской ответственности лишь в случае, если договор страхования заключён в электронном виде.</p>","image":null},{"id":100400101,"themeId":1,"group":1004001,"chapter":4,"chapters":[4],"q":"На каком пешеходном переходе пешеход имеет преимущество перед транспортными средствами?","a":["На нерегулируемом пешеходном переходе.","На регулируемом пешеходном переходе при разрешающем сигнале регулировщика или светофора.","На всех перечисленных пешеходных переходах."],"c":2,"e":"<p>Пешеход имеет преимущество перед транспортными средствами при переходе нерегулируемого пешеходного перехода.</p> <p>В случае перехода дороги на разрешающий сигнал регулировщика или светофора на регулируемом пешеходном переходе пешеход также имеет преимущество при одновременном праве на движение с транспортными средствами.</p>","image":null},{"id":100400102,"themeId":1,"group":1004001,"chapter":4,"chapters":[4],"q":"Кто имеет преимущество на регулируемом пешеходном переходе при разрешающем сигнале регулировщика?","a":["Пешеход.","Водитель транспортного средства."],"c":0,"e":"<p>При разрешающем сигнале регулировщика для водителя и пешехода, пешеход имеет преимущественное право на движение в намеченном направлении, а водитель автомобиля обязан предоставить ему преимущество.</p>","image":"assets/adrive-questions/q100400102.jpg"},{"id":100400103,"themeId":1,"group":1004001,"chapter":4,"chapters":[4],"q":"Кто имеет преимущество на регулируемом пешеходном переходе при разрешающем сигнале светофора?","a":["Пешеход.","Водитель транспортного средства."],"c":0,"e":"<p>При разрешающем сигнале светофора для водителя и пешехода, пешеход имеет преимущественное право на движение в намеченном направлении, а водитель автомобиля обязан предоставить ему преимущество.</p>","image":"assets/adrive-questions/q100400103.jpg"},{"id":100400104,"themeId":1,"group":1004001,"chapter":4,"chapters":[4],"q":"Имеет ли право пешеход на преимущественное пересечение проезжей части дороги в показанной ситуации?","a":["Да, имеет.","Нет, не имеет."],"c":0,"e":"<p>В показанной ситуации водитель автомобиля обязан предоставить преимущество пешеходу. На нерегулируемом пешеходном переходе пешеход имеет право на преимущественное пересечение проезжей части дороги.</p>","image":"assets/adrive-questions/q100400104.jpg"},{"id":100400202,"themeId":1,"group":1004002,"chapter":4,"chapters":[4],"q":"В каком случае пешеход имеет право двигаться по краю проезжей части дороги?","a":["Только при отсутствии тротуаров и пешеходных дорожек или невозможности движения по ним.","При отсутствии тротуаров, пешеходных, велосипедных дорожек и обочин или невозможности движения по ним.","В любом случае, если пешеход ведёт велосипед или мопед, обозначенный габаритными огнями, сигнальными фонарями или световозвращателями."],"c":1,"e":"<p>Пешеход может двигаться по краю проезжей части дороги (навстречу движению) только при отсутствии тротуаров, пешеходных, велосипедных дорожек и обочин или при невозможности движения по ним.</p>","image":null},{"id":100400231,"themeId":1,"group":1004002,"chapter":4,"chapters":[4],"q":"В каком случае пешеход имеет право двигаться по обочине?","a":["Только при отсутствии тротуаров и пешеходных дорожек.","Только при отсутствии тротуаров, пешеходных и велосипедных дорожек.","В любом случае может двигаться по левой обочине навстречу движению."],"c":0,"e":"<p>Пешеход может двигаться по обочине дороги или велосипедной дорожке только при отсутствии тротуаров и пешеходных дорожек с обеих сторон дороги.</p>","image":null},{"id":100400302,"themeId":1,"group":1004003,"chapter":4,"chapters":[4],"q":"Как должен обозначить себя пешеход при движении по тротуару в тёмное время суток?","a":["Сигнальными фонарями.","Световозвращающим элементом (элементами).","Пешеход должен идти с включённым фонарём, освещая себе дорогу.","Пешеход не обязан обозначать себя при движении в тёмное время суток по тротуару."],"c":3,"e":"<p>При движении по тротуару в тёмное время суток пешеход <strong>не обязан обозначать себя световозвращающим элементом</strong> или элементами, но при этом он, возможно, будет пересекать проезжую часть дороги на перекрёстках и по пешеходным переходам, а значит <strong>обозначить себя световозвращающим элементом — будет не лишним для обеспечения личной безопасности</strong>.</p>","image":null},{"id":100400401,"themeId":1,"group":1004004,"chapter":4,"chapters":[4],"q":"По какой траектории пешеходу разрешается перейти проезжую часть дороги, убедившись, что выход на проезжую часть дороги безопасен, если в пределах видимости отсутствуют пешеходные переходы?","a":["Только по траектории «А».","Только по траектории «Б».","Как по траектории «А», так и по траектории «Б».","Пешеход в показанной ситуации не имеет права переходить проезжую часть дороги."],"c":2,"e":"<p>При отсутствии в пределах видимости надземных, подземных, наземных пешеходных переходов пешеходу разрешается пересекать проезжую часть дороги на перекрёстках по линии тротуаров или обочин (на показанном перекрёстке по линии тротуаров).</p>","image":"assets/adrive-questions/q100400401.jpg"},{"id":100400402,"themeId":1,"group":1004004,"chapter":4,"chapters":[4],"q":"По какой траектории пешеходу разрешается перейти проезжую часть дороги, убедившись, что выход на проезжую часть дороги безопасен?","a":["Только по траектории «А».","Только по траектории «Б».","Как по траектории «А», так и по траектории «Б».","Пешеход в показанной ситуации не имеет права переходить проезжую часть дороги."],"c":0,"e":"<p>При наличии в пределах видимости пешеходных переходов пешеходу разрешается пересекать проезжую часть только по пешеходным переходам.</p>","image":"assets/adrive-questions/q100400402.jpg"},{"id":100400403,"themeId":1,"group":1004004,"chapter":4,"chapters":[4],"q":"По какой траектории пешеходу разрешается перейти проезжую часть дороги, убедившись, что выход на проезжую часть дороги безопасен, если в пределах видимости отсутствуют пешеходные переходы?","a":["Только по траектории «А».","Только по траектории «Б».","Как по траектории «А», так и по траектории «Б».","Пешеход в показанной ситуации не имеет права переходить проезжую часть дороги."],"c":2,"e":"<p>При отсутствии в пределах видимости надземных, подземных, наземных пешеходных переходов пешеходу разрешается пересекать проезжую часть дороги на перекрёстках по линии тротуаров или обочин (на показанном перекрёстке по линии тротуаров).</p>","image":"assets/adrive-questions/q100400403.jpg"},{"id":100400404,"themeId":1,"group":1004004,"chapter":4,"chapters":[4],"q":"Разрешается ли пешеходу в показанной ситуации перейти проезжую часть дороги при наличии в непосредственной близости подземного пешеходного перехода?","a":["Разрешается только по подземному пешеходному переходу.","Разрешается вне подземного пешеходного перехода при отсутствии в пределах видимости приближающихся транспортных средств.","Разрешается в обоих случаях."],"c":0,"e":"<p>При наличии в пределах видимости надземных, подземных или наземных пешеходных переходов пешеходу разрешается пересекать проезжую часть только по ним (на показанном рисунке — по подземному пешеходному переходу).</p>","image":"assets/adrive-questions/q100400404.jpg"},{"id":100400441,"themeId":1,"group":1004004,"chapter":4,"chapters":[4],"q":"Пешеход обязан переходить (пересекать) проезжую часть дороги:","a":["По подземному, надземному, наземному пешеходным переходам, а при их отсутствии в пределах видимости, — на перекрёстке по линии тротуаров или обочин.","По подземному, надземному пешеходным переходам, а при их отсутствии — по наземному пешеходному переходу (при отсутствии наземного пешеходного перехода — на перекрёстке по линии тротуаров или обочин)."],"c":0,"e":"<p>Пешеход обязан переходить (пересекать) проезжую часть дороги по подземному, надземному, наземному (убедившись в безопасности) пешеходным переходам (на выбор при имеющейся возможности), а при их отсутствии в пределах видимости, — на перекрёстке по линии тротуаров или обочин.<br> При пересечении проезжей части дороги вне подземного или наземного пешеходного перехода пешеходу необходимо быть особенно внимательным.</p> <p>Согласно «Конвенции о дорожном движении» пешеходы не должны пересекать проезжую часть дороги, не приняв мер предосторожности.</p>","image":null},{"id":100400481,"themeId":1,"group":1004004,"chapter":4,"chapters":[4],"q":"Правильно ли переходит проезжую часть дороги пешеход, указанный стрелкой?","a":["Да, правильно.","Нет, неправильно."],"c":1,"e":"<p>Пешеход обязан переходить проезжую часть дороги по подземному, надземному, наземному пешеходным переходам при их наличии. В показанной ситуации пешеход переходит проезжую часть дороги не по пешеходному переходу, а по велосипедному переезду.</p>","image":"assets/adrive-questions/q100400481.jpg"},{"id":100400482,"themeId":1,"group":1004004,"chapter":4,"chapters":[4],"q":"Правильно ли пешеходы переходят проезжую часть дороги?","a":["Правильно переходит пешеход «А».","Правильно переходит пешеход «Б».","Правильно переходят оба пешехода."],"c":0,"e":"<p>Пешеход обязан переходить проезжую часть дороги по подземному, надземному, наземному пешеходным переходам при их наличии. В показанной ситуации пешеход «Б» переходит проезжую часть дороги не по пешеходному переходу, а по велосипедному переезду.</p>","image":"assets/adrive-questions/q100400482.jpg"},{"id":100400501,"themeId":1,"group":1004005,"chapter":4,"chapters":[4],"q":"Водителю какого транспортного средства пешеход не должен создавать препятствия для движения при переходе проезжей части дороги в показанной ситуации?","a":["Водителю автомобиля «А».","Водителю автомобиля «Б».","Водителям автомобилей «А» и «Б».","Пешеход имеет преимущество в показанной ситуации."],"c":2,"e":"<p>При отсутствии в пределах видимости подземных, надземных, наземных пешеходных переходов и перекрёстков пешеходу разрешается пересекать проезжую часть дороги только на участке дороги, хорошо просматриваемом в обе стороны, убедившись в безопасности перехода, по кратчайшей траектории, уступив дорогу транспортным средствам.</p>","image":"assets/adrive-questions/q100400501.jpg"},{"id":100400502,"themeId":1,"group":1004005,"chapter":4,"chapters":[4],"q":"Должен ли пешеход обозначить себя световозвращающим элементом (элементами) при пересечении проезжей части дороги вне подземного, надземного, наземного пешеходного переходов и перекрёстка в тёмное время суток?","a":["Пешеход должен обозначить себя.","Пешеходу рекомендуется обозначить себя.","Пешеход должен обозначить себя только на неосвещённых участках дороги."],"c":1,"e":"<p>При пересечении проезжей части дороги вне подземного, надземного, наземного пешеходного переходов и перекрёстка в тёмное время суток пешеходу <strong>рекомендуется обозначить себя световозвращающим элементом</strong> (элементами).</p>","image":null},{"id":100400601,"themeId":1,"group":1004006,"chapter":4,"chapters":[4],"q":"При переходе проезжей части дороги пешеход остановился. В каком случае он не нарушил Правила дорожного движения?","a":["Если остановился на островке безопасности.","Если остановился на линии, разделяющей попутные транспортные потоки.","Если остановился на линии, разделяющей встречные транспортные потоки.","Нарушил во всех случаях."],"c":0,"e":"<p>При пересечении проезжей части дороги пешеходу запрещается задерживаться и останавливаться на проезжей части дороги, за исключением остановки на островке безопасности.</p>","image":null},{"id":100400602,"themeId":1,"group":1004006,"chapter":4,"chapters":[4],"q":"Разрешено ли в какой-либо из указанных точек пешеходу остановиться и задержаться при переходе проезжей части дороги?","a":["Разрешено в точке «А» или «В».","Разрешено только в точке «Б».","Разрешено в любой из указанных точек.","Пешеходу запрещено останавливаться и задерживаться при переходе проезжей части дороги, указанной на рисунке."],"c":3,"e":"<p>При пересечении проезжей части дороги задерживаться и останавливаться на проезжей части дороги в показанной ситуации запрещено, так как на пешеходном переходе отсутствует островок безопасности.</p>","image":"assets/adrive-questions/q100400602.jpg"},{"id":100400603,"themeId":1,"group":1004006,"chapter":4,"chapters":[4],"q":"Разрешено ли пешеходу на нерегулируемом пешеходном переходе остановиться и вернуться назад?","a":["Да, разрешено остановиться на островке безопасности и вернуться назад.","Да, разрешено остановиться, не доходя до островка безопасности, и вернуться назад.","Нет, запрещено."],"c":0,"e":"<p>При пересечении проезжей части дороги задерживаться и останавливаться на проезжей части дороги запрещено, кроме остановки на островке безопасности.</p> <p>При этом следует помнить, что разворот пешехода на островке безопасности будет неожиданностью для водителей транспортных средств, и, прежде чем продолжить движение в обратном направлении, пешеход обязан убедиться в безопасности перехода проезжей части дороги.</p>","image":"assets/adrive-questions/q100400603.jpg"},{"id":100400701,"themeId":1,"group":1004007,"chapter":4,"chapters":[4],"q":"Разрешается ли пешеходу перейти проезжую часть по траектории, показанной на рисунке, при отсутствии в пределах видимости пешеходных переходов?","a":["Да, разрешается.","Да, при условии, что дорога хорошо просматривается в обе стороны, убедившись в отсутствии приближающихся транспортных средств.","Нет, не разрешается."],"c":2,"e":"<p>Пешеходу запрещается пересекать вне пешеходных переходов проезжую часть дороги с шестью полосами движения и более.</p>","image":"assets/adrive-questions/q100400701.jpg"},{"id":100400702,"themeId":1,"group":1004007,"chapter":4,"chapters":[4],"q":"Разрешается ли пешеходу перейти проезжую часть по траектории, показанной на рисунке, при отсутствии в пределах видимости пешеходных переходов и перекрёстка?","a":["Да, разрешается.","Да, при условии, что дорога хорошо просматривается в обе стороны, убедившись в отсутствии приближающихся транспортных средств.","Нет, не разрешается."],"c":2,"e":"<p>Пешеходу запрещается пересекать вне пешеходных переходов дорогу с разделительной полосой или разделительной зоной.</p>","image":"assets/adrive-questions/q100400702.jpg"},{"id":100400703,"themeId":1,"group":1004007,"chapter":4,"chapters":[4],"q":"Разрешается ли пешеходу перейти проезжую часть по траектории, показанной на рисунке, при отсутствии в пределах видимости пешеходных переходов и перекрёстка?","a":["Да, разрешается.","Да, при условии, что дорога хорошо просматривается в обе стороны, убедившись в отсутствии приближающихся транспортных средств.","Нет, не разрешается."],"c":1,"e":"<p>Пешеходу в показанной ситуации пересекать проезжую часть разрешено, если дорога хорошо просматривается в обе стороны, убедившись в отсутствии приближающихся транспортных средств.</p>","image":"assets/adrive-questions/q100400703.jpg"},{"id":100400801,"themeId":1,"group":1004008,"chapter":4,"chapters":[4],"q":"Как должен двигаться пешеход, ведущий обозначенный световозвращателями велосипед по обочине в тёмное время суток?","a":["По ходу движения транспортных средств.","Навстречу движению транспортных средств.","По обочине любого направления движения."],"c":0,"e":"<p>Пешеходу, ведущему по обочине велосипед, который обозначен световозвращателями, следует идти по ходу движения транспортных средств, чтобы не вводить в заблуждение водителей этих транспортных средств.</p>","image":null},{"id":100400802,"themeId":1,"group":1004008,"chapter":4,"chapters":[4],"q":"Как в светлое время суток должен двигаться пешеход, ведущий по обочине велосипед, обозначенный световозвращателями?","a":["По ходу движения транспортных средств.","Навстречу движению транспортных средств.","По обочине любого направления движения."],"c":2,"e":"<p>Пешеходу, ведущему по обочине велосипед, который обозначен световозвращателями, в светлое время суток разрешается двигаться по обочине любого направления, но безопаснее всё же — навстречу движению.</p>","image":null},{"id":100400803,"themeId":1,"group":1004008,"chapter":4,"chapters":[4],"q":"Как должен двигаться пешеход, ведущий велосипед по краю проезжей части дороги, обозначенный световозвращателями, в светлое время суток?","a":["По ходу движения транспортных средств.","Навстречу движению транспортных средств.","По краю проезжей части дороги любого направления движения."],"c":1,"e":"<p>Пешеходу, ведущему велосипед по краю проезжей части дороги, который обозначен световозвращателями, в светлое время суток разрешается двигаться навстречу движению.</p>","image":null},{"id":100401142,"themeId":1,"group":1004011,"chapter":4,"chapters":[4],"q":"Пешеход, передвигающийся на самокате и намеревающийся пересечь проезжую часть дороги по пешеходному переходу, обязан:","a":["Пересекать проезжую часть дороги со скоростью идущего шагом пешехода только при наличии рядом пешеходов, идущих по пешеходному переходу пешком.","Пересекать проезжую часть дороги со скоростью идущего шагом пешехода независимо от наличия на пешеходном переходе других пешеходов."],"c":1,"e":"<p>Пешеход обязан при передвижении на самокате пересекать проезжую часть дороги <strong>со скоростью идущего шагом пешехода</strong> независимо от наличия других пешеходов на пешеходном переходе.</p>","image":null},{"id":100401143,"themeId":1,"group":1004011,"chapter":4,"chapters":[4],"q":"Пешеход, передвигающийся на спортивном инвентаре, при пересечении проезжей части дороги обязан:","a":["Убедиться, что выход (выезд) на проезжую часть дороги безопасен.","Пересекать проезжую часть дороги со скоростью идущего шагом пешехода.","Обязан соблюдать оба перечисленных требования."],"c":2,"e":"<p>Пешеход обязан при передвижении на спортивном инвентаре пересекать проезжую часть дороги со скоростью идущего шагом пешехода, убедившись, что выход (выезд) на проезжую часть дороги безопасен.</p>","image":null},{"id":100401541,"themeId":1,"group":1004015,"chapter":4,"chapters":[4],"q":"Обязан ли пешеход по требованию сотрудника ГАИ пройти в установленном порядке проверку на предмет определения состояния алкогольного опьянения?","a":["Обязан только в случае участия в дорожно-транспортном происшествии.","Обязан только в случае нарушения Правил дорожного движения.","Обязан в любом перечисленном случае."],"c":2,"e":"<p>Пешеход обязан по требованию сотрудника ГАИ пройти в установленном порядке проверку (освидетельствование) на предмет определения состояния алкогольного опьянения либо состояния, вызванного потреблением наркотических средств, психотропных веществ, их аналогов, токсических или других одурманивающих веществ.</p>","image":null},{"id":100401542,"themeId":1,"group":1004015,"chapter":4,"chapters":[4],"q":"Кто из перечисленных участников дорожного движения обязан по требованию сотрудника ГАИ пройти в установленном порядке проверку (освидетельствование) на предмет определения состояния алкогольного опьянения?","a":["Пешеход.","Велосипедист.","Водитель мопеда.","Все перечисленные."],"c":3,"e":"<p>И пешеход, и водитель транспортного средства обязаны по требованию сотрудника ГАИ пройти в установленном порядке проверку (освидетельствование) на предмет определения состояния алкогольного опьянения либо состояния, вызванного потреблением наркотических средств, психотропных веществ, их аналогов, токсических или других одурманивающих веществ.</p>","image":null},{"id":100500101,"themeId":1,"group":1005001,"chapter":5,"chapters":[5],"q":"Как должна осуществляться посадка (высадка) пассажиров?","a":["После полной остановки транспортного средства только с тротуара или обочины.","После полной остановки транспортного средства с посадочной площадки, а в случае её отсутствия — с тротуара или обочины.","После полной остановки транспортного средства с посадочной площадки, а в случае её отсутствия — с тротуара или обочины. В случае отсутствия тротуара или обочины — с проезжей части дороги при условии, что не будет создано помех движущимся транспортным средствам."],"c":1,"e":"<p>Посадка (высадка) пассажиров во избежание наезда на них движущихся транспортных средств или создания аварийной ситуации должна осуществляться с посадочной площадки, а в случае её отсутствия — с тротуара или обочины.</p>","image":null},{"id":100500102,"themeId":1,"group":1005001,"chapter":5,"chapters":[5],"q":"Разрешается ли выполнять посадку (высадку) пассажиров с проезжей части дороги?","a":["Нет, не разрешается.","Да, при отсутствии посадочной площадки, тротуара или обочины при принятии водителем мер предосторожности."],"c":0,"e":"<p>Посадка (высадка) пассажиров во избежание наезда на них движущихся транспортных средств или создания аварийной ситуации должна осуществляться с посадочной площадки, а в случае её отсутствия — с тротуара или обочины. В случае отсутствия обочины следует отказаться от посадки (высадки) пассажиров в данном месте.</p>","image":null},{"id":100500103,"themeId":1,"group":1005001,"chapter":5,"chapters":[5],"q":"Разрешено ли пассажиру, сидящему на переднем сиденье, выйти из автомобиля в такой ситуации?","a":["Да, только со стороны тротуара.","Да, только убедившись в отсутствии движущихся транспортных средств.","Нет, не разрешается в любом случае."],"c":0,"e":"<p>Водитель красного автомобиля остановился неправильно для высадки пассажира, сидящего на переднем сиденье.</p> <p>Так как высадка пассажиров на проезжую часть запрещена, водитель обязан выйти из автомобиля и выпустить пассажира через свою дверь, даже если для пассажира это будет связано с определёнными неудобствами.</p> <p>Кроме того, в некоторых автомобилях есть возможность для прохода к задним сиденьям для пассажира, сидящего на переднем сиденье, и следовательно для выхода на сторону тротуара.</p>","image":"assets/adrive-questions/q100500103.jpg"},{"id":100500164,"themeId":1,"group":1005001,"chapter":5,"chapters":[5],"q":"Разрешено ли будет пассажиру, находящемуся на переднем сиденье, выйти из автомобиля на проезжую часть дороги, если Вы остановитесь у левого тротуара?","a":["Да, разрешено, убедившись в безопасности и отсутствии приближающихся транспортных средств.","Нет, не разрешено."],"c":1,"e":"<p>Не допускается высадка пассажира на проезжую часть дороги.</p>","image":"assets/adrive-questions/q100500164.jpg"},{"id":100500201,"themeId":1,"group":1005002,"chapter":5,"chapters":[5],"q":"По какой траектории разрешено осуществить посадку в автомобиль, стоящий на противоположной стороне дороги (при отсутствии в пределах видимости надземного, подземного, наземного пешеходных переходов и перекрёстков)?","a":["Только по траектории «А».","Только по траектории «Б».","По любой из показанных траекторий."],"c":1,"e":"<p>Так как посадка пассажиров с проезжей части дороги запрещена, пассажир обязан перейти безопасно для себя и остальных участников движения дорогу по траектории «Б» и осуществить посадку с тротуара.</p>","image":"assets/adrive-questions/q100500201.jpg"},{"id":100500202,"themeId":1,"group":1005002,"chapter":5,"chapters":[5],"q":"С какой стороны пассажиру разрешено осуществлять посадку в легковой автомобиль?","a":["Только со стороны тротуара.","Со стороны тротуара и со стороны проезжей части дороги.","Со стороны тротуара и со стороны проезжей части дороги при условии, что все посадочные места в автомобиле со стороны тротуара заняты."],"c":0,"e":"<p>Так как посадка пассажиров с проезжей части дороги запрещена, пассажиру разрешено в показанной ситуации осуществить посадку только с тротуара.</p>","image":"assets/adrive-questions/q100500202.jpg"},{"id":100500203,"themeId":1,"group":1005002,"chapter":5,"chapters":[5],"q":"Где разрешено ожидать трамвай при отсутствии посадочной площадки?","a":["На тротуаре.","На проезжей части.","На проезжей части или на тротуаре."],"c":0,"e":"<p>В показанной ситуации пешеход обязан ожидать трамвай в ожидании посадки только на тротуаре и не выходить на проезжую часть дороги до полной остановки трамвая.</p>","image":"assets/adrive-questions/q100500203.jpg"},{"id":100500263,"themeId":1,"group":1005002,"chapter":5,"chapters":[5],"q":"Разрешено ли водителю выйти на проезжую часть дороги, чтобы, обойдя автомобиль, продолжить движение по тротуару?","a":["Да, разрешено.","Нет, не разрешено.","Разрешено, убедившись в безопасности, и если это не создаст препятствие для движения других участников дорожного движения."],"c":2,"e":"<p>Водителю не запрещено выходить на проезжую часть дороги, но при этом он должен убедиться в личной безопасности, а также ему не запрещено открывать двери транспортного средства или держать их открытыми, только если это не создаст препятствие для движения других участников дорожного движения.</p>","image":"assets/adrive-questions/q100500263.jpg"},{"id":100500301,"themeId":1,"group":1005003,"chapter":5,"chapters":[5],"q":"В каком случае пассажиры при движении механического транспортного средства, оборудованного ремнями безопасности, обязаны быть пристёгнутыми?","a":["Только при нахождении на переднем сиденье.","На всех сиденьях транспортного средства при движении вне населённого пункта.","На всех сиденьях, оборудованных ремнями безопасности."],"c":2,"e":"<p>Ошибочно принято считать, что при размещении на задних сиденьях транспортного средства пристёгиваться ремнями безопасности необязательно. Как показывают исследования, при различных видах ДТП выживаемость пассажира, пристёгнутого на заднем сиденье, значительно выше, чем у непристёгнутого.</p> <p>Пассажиры на всех сиденьях должны быть пристёгнуты ремнями безопасности, кроме случаев, указанных в Правилах дорожного движения.</p>","image":null},{"id":100500302,"themeId":1,"group":1005003,"chapter":5,"chapters":[5],"q":"В каком случае пассажиру при поездке на мотоцикле разрешено быть без застёгнутого мотошлема?","a":["При поездке в боковом прицепе.","При поездке ребёнка в возрасте от 12 до 16 лет в боковом прицепе.","Любой пассажир должен быть в застёгнутом мотошлеме."],"c":2,"e":"<p>Все пассажиры, перевозимые на мотоциклах и мопедах, должны быть в застёгнутых мотошлемах.</p> <p>Если мотошлем по размеру головы пассажира подобрать затруднительно (например, для ребёнка), следует отказаться от перевозки такого пассажира.</p>","image":null},{"id":100500401,"themeId":1,"group":1005004,"chapter":5,"chapters":[5],"q":"Что из перечисленного запрещается пассажиру во время движения?","a":["Закрывать двери транспортного средства.","Кричать в салоне автомобиля, отвлекая водителя от управления транспортным средством.","Сидеть на грузе, находящемся ниже уровня бортов, при поездке на грузовом автомобиле с грузовой платформой.","Всё перечисленное."],"c":1,"e":"<p>Пассажиру запрещается отвлекать водителя от управления транспортным средством во время движения.</p>","image":null},{"id":100500402,"themeId":1,"group":1005004,"chapter":5,"chapters":[5],"q":"Что из перечисленного запрещается пассажиру во время движения?","a":["При движении на грузовом автомобиле с бортовой платформой стоять, сидеть на его бортах или на грузе, находящемся выше бортов.","Отвлекать водителя от управления транспортным средством во время его движения и (или) мешать водителю в управлении транспортным средством.","Препятствовать закрытию дверей транспортного средства, а во время его движения высовываться в оконные проёмы, открывать двери транспортного средства.","Всё перечисленное."],"c":3,"e":"<p>Пассажиру запрещается отвлекать водителя от управления транспортным средством во время движения или мешать ему в управлении.</p> <p>Остальные перечисленные действия также запрещены, так как могут привести к травмированию пассажира.</p>","image":null},{"id":100500641,"themeId":1,"group":1005006,"chapter":5,"chapters":[5],"q":"Обязан ли пассажир по требованию сотрудника ГАИ пройти в установленном порядке проверку на предмет определения состояния алкогольного опьянения?","a":["Да, обязан в случае движения на заднем сиденье мотоцикла.","Да, обязан в случае движения на заднем сиденье мопеда.","Обязан во всех перечисленных случаях.","Нет, не обязан."],"c":2,"e":"<p>Пассажир обязан по требованию сотрудника ГАИ пройти в установленном порядке проверку (освидетельствование) на предмет определения состояния алкогольного опьянения либо состояния, вызванного потреблением наркотических средств, психотропных веществ, их аналогов, токсических или других одурманивающих веществ.</p>","image":null},{"id":100600101,"themeId":1,"group":1006001,"chapter":6,"chapters":[6],"q":"Для чего служит маячок оранжевого цвета, установленный на автомобиле, перевозящем опасные грузы?","a":["Для привлечения внимания и предупреждения участников дорожного движения о возможной опасности.","Для получения преимущества в движении по отношению к другим транспортным средствам и пешеходам.","Для оповещения участников дорожного движения о возможности несоблюдения требований дорожных знаков и дорожной разметки."],"c":0,"e":"<p>В показанной ситуации маячок оранжевого цвета, установленный на автомобиле, перевозящем опасные грузы, не даёт преимущества в движении, а служит для привлечения внимания и предупреждения участников дорожного движения о возможной опасности.</p>","image":"assets/adrive-questions/q100600101.jpg"},{"id":100600102,"themeId":1,"group":1006001,"chapter":6,"chapters":[6],"q":"Кто в показанной ситуации имеет преимущество?","a":["Водитель легкового автомобиля.","Водитель транспортного средства с включённым маячком оранжевого цвета."],"c":0,"e":"<p>В показанной ситуации водитель легкового автомобиля находится на главной дороге и пользуется преимуществом, так как включённый маячок оранжевого цвета не даёт преимущества в движении и служит для привлечения внимания и предупреждения участников дорожного движения о возможной опасности.</p>","image":"assets/adrive-questions/q100600102.jpg"},{"id":100600201,"themeId":1,"group":1006002,"chapter":6,"chapters":[6],"q":"Что Вам необходимо предпринять, если по дороге навстречу приближается транспортное средство оперативного назначения с включённым маячком синего цвета и специальным звуковым сигналом?","a":["Уступить дорогу и обеспечить беспрепятственный проезд указанному транспортному средству.","Снизить скорость, двигаться как можно правее, быть готовым остановиться в случае необходимости.","Остановиться на правой обочине (при её отсутствии занять на проезжей части дороги крайнее правое положение) и не возобновлять движение до проезда транспортного средства оперативного назначения."],"c":0,"e":"<p>В показанной ситуации по дороге во встречном направлении приближается транспортное средство оперативного назначения с включённым маячком синего цвета и специальным звуковым сигналом, поэтому Вам необходимо уступить дорогу и обеспечить беспрепятственный проезд транспортному средству оперативного назначения.</p>","image":"assets/adrive-questions/q100600201.jpg"},{"id":100600202,"themeId":1,"group":1006002,"chapter":6,"chapters":[6],"q":"Что необходимо предпринять водителю, если по дороге в попутном направлении приближается транспортное средство оперативного назначения с включённым маячком синего цвета и специальным звуковым сигналом?","a":["Уступить дорогу и обеспечить беспрепятственный проезд указанному транспортному средству.","Снизить скорость, двигаться как можно правее, чтобы дать возможность опередить себя транспортному средству оперативного назначения.","Остановиться на правой обочине (при её отсутствии занять на проезжей части дороги крайнее правое положение) и не возобновлять движение до проезда транспортного средства оперативного назначения."],"c":0,"e":"<p>Если по дороге в попутном направлении приближается транспортное средство оперативного назначения с включённым маячком синего цвета и специальным звуковым сигналом, водителю необходимо уступить дорогу и обеспечить беспрепятственный проезд указанному транспортному средству.</p> <p>Правила дорожного движения не конкретизируют, каким образом водители транспортных средств должны уступить дорогу, их действия должны соответствовать складывающейся дорожной ситуации.</p>","image":null},{"id":100600301,"themeId":1,"group":1006003,"chapter":6,"chapters":[6],"q":"Как должен поступить в показанной ситуации водитель зелёного автомобиля при приближении транспортного средства оперативного назначения с включённым маячком синего цвета?","a":["Занять на проезжей части дороги крайнее правое положение и остановиться у края тротуара.","Продолжить движение, уступая дорогу и обеспечивая беспрепятственный проезд указанному транспортному средству."],"c":1,"e":"<p>В показанной ситуации водитель зелёного автомобиля при приближении транспортного средства оперативного назначения с включённым маячком синего цвета должен продолжить движение, уступая дорогу и обеспечивая беспрепятственный проезд транспортному средству оперативного назначения.</p>","image":"assets/adrive-questions/q100600301.jpg"},{"id":100600302,"themeId":1,"group":1006003,"chapter":6,"chapters":[6],"q":"Требуется ли от водителя красного легкового автомобиля перестроиться в правую полосу движения при приближении транспортного средства оперативного назначения с включённым маячком синего цвета?","a":["Да.","Нет, если он не создаёт препятствия для движения указанному транспортному средству."],"c":1,"e":"<p>В показанной ситуации по дороге во встречном направлении приближается транспортное средство оперативного назначения с включённым маячком синего цвета, поэтому если водитель красного легкового автомобиля не создаёт препятствия для движения транспортному средству оперативного назначения, то перестраиваться в правую полосу движения нет необходимости.</p>","image":"assets/adrive-questions/q100600302.jpg"},{"id":100600303,"themeId":1,"group":1006003,"chapter":6,"chapters":[6],"q":"Требуется ли от водителя красного легкового автомобиля перестроиться в правую полосу движения при приближении транспортного средства оперативного назначения с включённым маячком синего цвета?","a":["Да.","Нет, если водитель поворачивает налево на ближайшем перекрёстке, а полоса справа от него свободна."],"c":0,"e":"<p>В показанной ситуации по дороге в попутном направлении приближается транспортное средство оперативного назначения с включённым маячком синего цвета, поэтому водителю красного легкового автомобиля необходимо перестроиться в правую полосу движения, уступить дорогу и обеспечить беспрепятственный проезд транспортному средству оперативного назначения.</p>","image":"assets/adrive-questions/q100600303.jpg"},{"id":100600401,"themeId":1,"group":1006004,"chapter":6,"chapters":[6],"q":"Как должен поступить водитель красного легкового автомобиля в показанной ситуации?","a":["Остановиться на обочине и не возобновлять движение до проезда транспортного средства, замыкающего организованную транспортную колонну.","Продолжить движение по своей полосе движения, уступая дорогу и обеспечивая беспрепятственный проезд организованной транспортной колонны."],"c":1,"e":"<p>В показанной ситуации по дороге в попутном направлении приближается организованная транспортная колонна в сопровождении транспортного средства оперативного назначения с включённым маячком синего цвета, поэтому водитель красного легкового автомобиля должен продолжить движение по своей полосе движения, уступая дорогу и обеспечивая беспрепятственный проезд организованной транспортной колонны.</p>","image":"assets/adrive-questions/q100600401.jpg"},{"id":100600402,"themeId":1,"group":1006004,"chapter":6,"chapters":[6],"q":"Как Вам следует поступить в показанной ситуации?","a":["Остановиться на обочине и не возобновлять движение до проезда транспортного средства, замыкающего организованную транспортную колонну.","Продолжить движение по своей полосе движения, уступая дорогу и обеспечивая беспрепятственный проезд организованной транспортной колонны."],"c":1,"e":"<p>В показанной ситуации по дороге во встречном направлении приближается организованная транспортная колонна в сопровождении транспортного средства оперативного назначения с включённым маячком синего цвета, поэтому разрешается продолжить движение по своей полосе движения, уступая дорогу и обеспечивая беспрепятственный проезд организованной транспортной колонны.</p>","image":"assets/adrive-questions/q100600402.jpg"},{"id":100600501,"themeId":1,"group":1006005,"chapter":6,"chapters":[6],"q":"Кто в показанной ситуации обязан уступить дорогу?","a":["Водитель легкового автомобиля.","Водитель автомобиля скорой медицинской помощи, выезжающий на дорогу задним ходом."],"c":0,"e":"<p>В показанной ситуации водитель автомобиля скорой медицинской помощи выезжает на дорогу задним ходом с включённым маячком синего цвета, поэтому водитель легкового автомобиля обязан уступить дорогу.</p>","image":"assets/adrive-questions/q100600501.jpg"},{"id":100600502,"themeId":1,"group":1006005,"chapter":6,"chapters":[6],"q":"Кто в показанной ситуации обязан уступить дорогу?","a":["Водитель легкового автомобиля, движущийся по главной дороге.","Водитель автомобиля скорой медицинской помощи, движущийся по второстепенной дороге."],"c":0,"e":"<p>В показанной ситуации водитель автомобиля скорой медицинской помощи движется по второстепенной дороге с включённым маячком синего цвета, поэтому водитель легкового автомобиля, движущийся по главной дороге, обязан уступить дорогу.</p>","image":"assets/adrive-questions/q100600502.jpg"},{"id":100600503,"themeId":1,"group":1006005,"chapter":6,"chapters":[6],"q":"Кто в показанной ситуации обязан уступить дорогу?","a":["Вы, управляя легковым автомобилем.","Водитель автомобиля скорой медицинской помощи."],"c":0,"e":"<p>В показанной ситуации к узкому участку дороги приближается автомобиль скорой медицинской помощи с включёнными маячками синего цвета, поэтому Вы, управляя легковым автомобилем, обязаны уступить дорогу.</p>","image":"assets/adrive-questions/q100600503.jpg"},{"id":100600601,"themeId":1,"group":1006006,"chapter":6,"chapters":[6],"q":"Кто проедет перекрёсток первым в показанной ситуации?","a":["Трамвай.","Автомобиль дорожно-патрульной службы с включённым маячком синего цвета.","Трамвай одновременно с зелёным легковым автомобилем."],"c":1,"e":"<p>В показанной ситуации к перекрёстку приближается автомобиль ДПС с включённым маячком синего цвета, который, пользуясь преимуществом, проедет перекрёсток первым.</p>","image":"assets/adrive-questions/q100600601.jpg"},{"id":100600602,"themeId":1,"group":1006006,"chapter":6,"chapters":[6],"q":"Кто проедет перекрёсток первым в показанной ситуации?","a":["Автомобиль скорой медицинской помощи.","Троллейбус одновременно c зелёным легковым автомобилем.","Автомобиль скорой медицинской помощи одновременно с автомобилем, перевозящим опасный груз."],"c":0,"e":"<p>В показанной ситуации к перекрёстку приближается автомобиль скорой медицинской помощи с включёнными маячками синего цвета, который, пользуясь преимуществом, проедет перекрёсток первым.</p>","image":"assets/adrive-questions/q100600602.jpg"},{"id":100600603,"themeId":1,"group":1006006,"chapter":6,"chapters":[6],"q":"Может ли в показанной ситуации водитель автомобиля скорой медицинской помощи проехать перекрёсток на запрещающий сигнал светофора?","a":["Да, при условии обеспечения безопасности дорожного движения.","Нет, не может."],"c":0,"e":"<p>Водители транспортных средств оперативного назначения при условии обеспечения безопасности дорожного движения с включёнными маячками синего или синего и красного цветов могут отступать от требований светофоров.</p> <p>Водители прочих транспортных средств обязаны уступить им дорогу и обеспечить беспрепятственный проезд.</p>","image":"assets/adrive-questions/q100600603.jpg"},{"id":100600604,"themeId":1,"group":1006006,"chapter":6,"chapters":[6],"q":"В каких направлениях разрешено продолжить движение водителю автомобиля скорой медицинской помощи на ближайшем перекрёстке?","a":["Только прямо или налево.","Прямо, налево или на разворот.","Во всех направлениях."],"c":2,"e":"<p>Водитель транспортного средства оперативного назначения при включении маячков синего цвета вправе отступать от требований предписывающего дорожного знака и может продолжить движение в любом направлении. При этом он обязан заблаговременно подать сигнал световыми указателями поворота соответствующего направления.</p>","image":"assets/adrive-questions/q100600604.jpg"},{"id":100600701,"themeId":1,"group":1006007,"chapter":6,"chapters":[6],"q":"Как должны поступить в показанной ситуации водители красного и зелёного автомобилей при приближении транспортного средства оперативного назначения?","a":["Водители обоих автомобилей должны съехать на обочину и остановиться.","Водители обоих автомобилей должны уступить дорогу и обеспечить беспрепятственный проезд транспортному средству оперативного назначения."],"c":1,"e":"<p>В показанной ситуации при приближении транспортного средства оперативного назначения с включённым маячком синего цвета водители обоих автомобилей должны уступить дорогу и обеспечить беспрепятственный проезд транспортному средству оперативного назначения.</p>","image":"assets/adrive-questions/q100600701.jpg"},{"id":100600732,"themeId":1,"group":1006007,"chapter":6,"chapters":[6],"q":"Как должны поступить в показанной ситуации водители красного и зелёного автомобилей при приближении транспортного средства оперативного назначения?","a":["Водители обоих автомобилей должны остановиться у тротуара.","Водители обоих автомобилей должны уступить дорогу и обеспечить беспрепятственный проезд транспортному средству оперативного назначения."],"c":1,"e":"<p>В показанной ситуации при приближении транспортного средства оперативного назначения с включённым маячком синего цвета водители обоих автомобилей должны уступить дорогу и обеспечить беспрепятственный проезд транспортному средству оперативного назначения.</p>","image":"assets/adrive-questions/q100600732.jpg"},{"id":100600801,"themeId":1,"group":1006008,"chapter":6,"chapters":[6],"q":"Как должен поступить в показанной ситуации водитель зелёного легкового автомобиля?","a":["Съехать на правую обочину и остановиться.","Продолжить движение в крайней правой полосе, уступая дорогу и обеспечивая беспрепятственный проезд организованной транспортной колонны."],"c":0,"e":"<p>В показанной ситуации по дороге в попутном направлении приближается организованная транспортная колонна в сопровождении транспортного средства оперативного назначения с включёнными маячками синего и красного цветов, поэтому водитель зелёного легкового автомобиля должен съехать на правую обочину и остановиться.</p>","image":"assets/adrive-questions/q100600801.jpg"},{"id":100600802,"themeId":1,"group":1006008,"chapter":6,"chapters":[6],"q":"Как должен поступить в показанной ситуации водитель зелёного легкового автомобиля?","a":["Занять крайнее правое положение на проезжей части дороги и остановиться.","Увеличить скорость движения, чтобы обеспечить беспрепятственный проезд организованной транспортной колонны.","Продолжить движение в крайней правой полосе, уступая дорогу и обеспечивая беспрепятственный проезд организованной транспортной колонны."],"c":0,"e":"<p>В показанной ситуации по дороге в попутном направлении приближается организованная транспортная колонна в сопровождении транспортного средства оперативного назначения с включёнными маячками синего и красного цветов, поэтому водитель зелёного легкового автомобиля должен занять крайнее правое положение на проезжей части дороги и остановиться.</p>","image":"assets/adrive-questions/q100600802.jpg"},{"id":100600803,"themeId":1,"group":1006008,"chapter":6,"chapters":[6],"q":"Как должен поступить в показанной ситуации водитель зелёного легкового автомобиля?","a":["Занять крайнее правое положение на проезжей части дороги и остановиться.","Продолжить движение в средней полосе, уступая дорогу и обеспечивая беспрепятственный проезд организованной транспортной колонны.","Перестроиться в крайнюю правую полосу, уступая дорогу и обеспечивая беспрепятственный проезд организованной транспортной колонны."],"c":0,"e":"<p>В показанной ситуации по дороге в попутном направлении приближается организованная транспортная колонна в сопровождении транспортного средства оперативного назначения с включёнными маячками синего и красного цветов, поэтому водитель зелёного легкового автомобиля должен занять крайнее правое положение на проезжей части дороги и остановиться.</p>","image":"assets/adrive-questions/q100600803.jpg"},{"id":100601001,"themeId":1,"group":1006010,"chapter":6,"chapters":[6],"q":"Как следует поступить водителю белого автомобиля в показанной ситуации при приближении транспортного средства оперативного назначения?","a":["Занять крайнее правое положение на проезжей части дороги и остановиться.","Продолжить движение, уступая дорогу и обеспечивая беспрепятственный проезд.","Продолжать движение, заняв крайнее правое положение на проезжей части дороги."],"c":0,"e":"<p>В показанной ситуации по дороге во встречном направлении приближается транспортное средство оперативного назначения с включёнными маячками синего и красного цветов, поэтому водитель белого легкового автомобиля должен занять крайнее правое положение на проезжей части дороги и остановиться.</p>","image":"assets/adrive-questions/q100601001.jpg"},{"id":100601002,"themeId":1,"group":1006010,"chapter":6,"chapters":[6],"q":"Как следует поступить водителю белого автомобиля в показанной ситуации?","a":["Занять крайнее правое положение на проезжей части дороги и остановиться.","Продолжить движение, уступая дорогу и обеспечивая беспрепятственный проезд.","Продолжать движение, заняв крайнее правое положение на проезжей части дороги."],"c":0,"e":"<p>В показанной ситуации по дороге с разделительной зоной во встречном направлении приближается организованная транспортная колонна в сопровождении транспортного средства оперативного назначения с включёнными маячками синего и красного цветов, поэтому водитель белого легкового автомобиля должен занять крайнее правое положение на проезжей части дороги и остановиться.</p>","image":"assets/adrive-questions/q100601002.jpg"},{"id":100601003,"themeId":1,"group":1006010,"chapter":6,"chapters":[6],"q":"Как следует поступить водителю белого автомобиля в показанной ситуации?","a":["Съехать на обочину дороги и остановиться.","Занять крайнее правое положение на проезжей части дороги и остановиться.","Продолжить движение, уступая дорогу и обеспечивая беспрепятственный проезд.","Продолжать движение, заняв крайнее правое положение на проезжей части дороги."],"c":2,"e":"<p>В показанной ситуации по дороге с разделительной полосой во встречном направлении приближается организованная транспортная колонна в сопровождении транспортного средства оперативного назначения с включёнными маячками синего и красного цветов, поэтому водитель белого легкового автомобиля должен продолжить движение, уступая дорогу и обеспечивая беспрепятственный проезд.</p>","image":"assets/adrive-questions/q100601003.jpg"},{"id":100601101,"themeId":1,"group":1006011,"chapter":6,"chapters":[6],"q":"Водители каких автомобилей должны остановиться на обочине в показанной ситуации при приближении транспортного средства оперативного назначения?","a":["Только водитель автобуса.","Только водители автобуса и зелёного легкового автомобиля.","Водители всех автомобилей."],"c":2,"e":"<p>В показанной ситуации при приближении по дороге с разделительной зоной транспортного средства оперативного назначения с включёнными маячками синего и красного цветов водители всех автомобилей должны остановиться на обочине.</p>","image":"assets/adrive-questions/q100601101.jpg"},{"id":100601102,"themeId":1,"group":1006011,"chapter":6,"chapters":[6],"q":"Водители каких автомобилей должны остановиться на обочине в показанной ситуации при приближении транспортного средства оперативного назначения?","a":["Только водитель автобуса.","Только водители автобуса и зелёного легкового автомобиля.","Водители всех автомобилей."],"c":0,"e":"<p>В показанной ситуации при приближении по дороге с разделительной полосой транспортного средства оперативного назначения с включёнными маячками синего и красного цветов должен остановиться на обочине только водитель автобуса, двигающийся в попутном направлении.</p>","image":"assets/adrive-questions/q100601102.jpg"},{"id":100601103,"themeId":1,"group":1006011,"chapter":6,"chapters":[6],"q":"Водители каких автомобилей должны остановиться на обочине в показанной ситуации при приближении транспортного средства оперативного назначения?","a":["Только водитель зелёного легкового автомобиля.","Водители грузового и зелёного легкового автомобиля."],"c":1,"e":"<p>В показанной ситуации при приближении по дороге без разделительной полосы транспортного средства оперативного назначения с включёнными маячками синего и красного цветов водители грузового и зелёного легкового автомобиля должны остановиться на обочине.</p>","image":"assets/adrive-questions/q100601103.jpg"},{"id":100601401,"themeId":1,"group":1006014,"chapter":6,"chapters":[6],"q":"Что должен предпринять водитель, если по дороге без разделительной полосы приближается в попутном направлении транспортное средство оперативного назначения с включёнными маячками синего и красного цветов и специальным звуковым сигналом?","a":["Продолжать движение, уступая дорогу и обеспечивая беспрепятственный проезд.","Остановиться на обочине, а при её отсутствии — занять крайнее правое положение в правой полосе движения и остановиться."],"c":1,"e":"<p>Если по дороге без разделительной полосы приближается в попутном направлении транспортное средство оперативного назначения с включёнными маячками синего и красного цветов и специальным звуковым сигналом, водитель должен остановиться на обочине, а при её отсутствии — занять крайнее правое положение в правой полосе движения и остановиться.</p>","image":null},{"id":100601402,"themeId":1,"group":1006014,"chapter":6,"chapters":[6],"q":"Как Вы должны поступить, управляя легковым автомобилем, если в показанной ситуации приближается транспортное средство оперативного назначения с включёнными маячками синего и красного цветов и специальным звуковым сигналом?","a":["Продолжать движение, уступая дорогу и обеспечивая беспрепятственный проезд.","Остановиться на обочине."],"c":1,"e":"<p>Если по дороге без разделительной полосы приближается во встречном направлении транспортное средство оперативного назначения с включёнными маячками синего и красного цветов и специальным звуковым сигналом, то Вы должны остановиться на обочине, а при её отсутствии — занять крайнее правое положение в правой полосе движения и остановиться.</p>","image":"assets/adrive-questions/q100601402.jpg"},{"id":100601601,"themeId":1,"group":1006016,"chapter":6,"chapters":[6],"q":"Что должен предпринять водитель, если по дороге с разделительной полосой приближается в попутном направлении транспортное средство оперативного назначения с включёнными маячками синего и красного цветов и специальным звуковым сигналом?","a":["Продолжать движение, уступая дорогу и обеспечивая беспрепятственный проезд.","Остановиться на обочине, а при её отсутствии — занять крайнее правое положение в правой полосе движения и остановиться."],"c":1,"e":"<p>Если по дороге с разделительной полосой приближается в попутном направлении транспортное средство оперативного назначения с включёнными маячками синего и красного цветов и специальным звуковым сигналом, водитель должен остановиться на обочине, а при её отсутствии — занять крайнее правое положение в правой полосе движения и остановиться.</p>","image":null},{"id":100601602,"themeId":1,"group":1006016,"chapter":6,"chapters":[6],"q":"Как Вы должны поступить, если по дороге с разделительной полосой приближается во встречном направлении транспортное средство оперативного назначения с включёнными маячками синего и красного цветов и специальным звуковым сигналом?","a":["Остановиться справа на обочине.","Продолжать движение, уступая дорогу и обеспечивая беспрепятственный проезд."],"c":1,"e":"<p>В показанной ситуации по дороге с разделительной полосой во встречном направлении приближается транспортное средство оперативного назначения с включёнными маячками синего и красного цветов и специальным звуковым сигналом, поэтому Вы должны продолжать движение, уступая дорогу и обеспечивая беспрепятственный проезд.</p>","image":"assets/adrive-questions/q100601602.jpg"},{"id":100601701,"themeId":1,"group":1006017,"chapter":6,"chapters":[6],"q":"Как Вы должны поступить, если по дороге с разделительной зоной приближается во встречном направлении транспортное средство оперативного назначения с включёнными маячками синего и красного цветов и специальным звуковым сигналом?","a":["Остановиться справа на обочине.","Продолжать движение, уступая дорогу и обеспечивая беспрепятственный проезд."],"c":0,"e":"<p>В показанной ситуации по дороге без разделительной полосы во встречном направлении приближается транспортное средство оперативного назначения с включёнными маячками синего и красного цветов и специальным звуковым сигналом, поэтому Вы должны остановиться справа на обочине.</p>","image":"assets/adrive-questions/q100601701.jpg"},{"id":100601702,"themeId":1,"group":1006017,"chapter":6,"chapters":[6],"q":"Как Вы должны поступить, управляя легковым автомобилем, если в показанной ситуации по дороге с трамвайными путями посередине, расположенными на одном уровне с проезжей частью дороги, приближается транспортное средство оперативного назначения с включёнными маячками синего и красного цветов и специальным звуковым сигналом?","a":["Продолжать движение, уступая дорогу и обеспечивая беспрепятственный проезд.","Занять крайнее правое положение в правой полосе движения и остановиться.","Продолжать движение при наличии трамваев на трамвайных путях, уступая дорогу и обеспечивая беспрепятственный проезд транспортному средству оперативного назначения."],"c":1,"e":"<p>В показанной ситуации по дороге с трамвайными путями посередине во встречном направлении приближается транспортное средство оперативного назначения с включёнными маячками синего и красного цветов и специальным звуковым сигналом, поэтому Вы должны остановиться на обочине, а при её отсутствии — занять крайнее правое положение в правой полосе движения и остановиться.</p>","image":"assets/adrive-questions/q100601702.jpg"},{"id":100601703,"themeId":1,"group":1006017,"chapter":6,"chapters":[6],"q":"Что должен предпринять водитель, если по дороге с односторонним движением приближается в попутном направлении транспортное средство оперативного назначения с включёнными маячками синего и красного цветов и специальным звуковым сигналом?","a":["Остановиться на обочине, а при её отсутствии — занять крайнее правое положение в правой полосе движения и остановиться.","Продолжать движение, уступая дорогу и обеспечивая беспрепятственный проезд транспортному средству оперативного назначения.","Перестроиться на крайнюю правую полосу движения, уступая дорогу и обеспечивая беспрепятственный проезд транспортному средству оперативного назначения."],"c":0,"e":"<p>Если по дороге с односторонним движением приближается в попутном направлении транспортное средство оперативного назначения с включёнными маячками синего и красного цветов и специальным звуковым сигналом, водитель должен остановиться на обочине, а при её отсутствии — занять крайнее правое положение в правой полосе движения и остановиться.</p>","image":null},{"id":100601801,"themeId":1,"group":1006018,"chapter":6,"chapters":[6],"q":"Правильно ли поступит водитель зелёного легкового автомобиля, заняв крайнее правое положение на проезжей части дороги и остановившись, при наличии обочины?","a":["Да.","Нет, так как необходимо съехать на обочину.","Нет, так как в этой ситуации останавливаться нет необходимости."],"c":1,"e":"<p>В показанной ситуации по дороге в попутном направлении приближается организованная транспортная колонна в сопровождении транспортного средства оперативного назначения с включёнными маячками синего и красного цветов, поэтому водитель зелёного легкового автомобиля должен съехать на обочину и остановиться.</p>","image":"assets/adrive-questions/q100601801.jpg"},{"id":100601802,"themeId":1,"group":1006018,"chapter":6,"chapters":[6],"q":"Правильно ли поступит водитель зелёного легкового автомобиля, заняв крайнее правое положение на проезжей части дороги и остановившись, при наличии обочины?","a":["Да.","Нет, так как необходимо съехать на обочину.","Нет, так как в этой ситуации останавливаться нет необходимости."],"c":2,"e":"<p>В показанной ситуации по дороге с разделительной полосой во встречном направлении приближается организованная транспортная колонна в сопровождении транспортного средства оперативного назначения с включёнными маячками синего и красного цветов, поэтому водитель зелёного легкового автомобиля может продолжать движение, уступая дорогу и обеспечивая беспрепятственный проезд.</p>","image":"assets/adrive-questions/q100601802.jpg"},{"id":100601901,"themeId":1,"group":1006019,"chapter":6,"chapters":[6],"q":"В какой момент водителю, совершившему остановку на обочине при движении транспортного средства оперативного назначения с включёнными маячками синего и красного цветов, сопровождавшего организованную транспортную колонну, разрешается возобновить движение?","a":["После проезда транспортного средства оперативного назначения с включёнными маячками синего и красного цветов.","После проезда замыкающего колонну транспортного средства оперативного назначения с включённым маячком синего цвета (транспортного средства с опознавательным знаком «Колонна»)."],"c":1,"e":"<p>В показанной ситуации водителю, совершившему остановку на обочине при движении транспортного средства оперативного назначения с включёнными маячками синего и красного цветов, сопровождавшего организованную транспортную колонну, разрешается возобновить движение после проезда замыкающего колонну транспортного средства оперативного назначения с включённым маячком синего цвета или транспортного средства с опознавательным знаком «Колонна».</p>","image":"assets/adrive-questions/q100601901.jpg"},{"id":100601902,"themeId":1,"group":1006019,"chapter":6,"chapters":[6],"q":"Транспортное средство оперативного назначения не сопровождает организованную транспортную колонну. В какой момент водителю, совершившему остановку на обочине при движении транспортного средства оперативного назначения с включёнными маячками синего и красного цветов, разрешается возобновить движение?","a":["После проезда транспортного средства оперативного назначения с включённым маячком синего цвета.","После того, как начнут движение водители остальных остановившихся на обочине транспортных средств.","После проезда транспортного средства оперативного назначения с включёнными маячками синего и красного цветов."],"c":2,"e":"<p>В показанной ситуации водителю, совершившему остановку на обочине при движении транспортного средства оперативного назначения с включёнными маячками синего и красного цветов, разрешается возобновить движение после проезда транспортного средства оперативного назначения.</p>","image":"assets/adrive-questions/q100601902.jpg"},{"id":100601903,"themeId":1,"group":1006019,"chapter":6,"chapters":[6],"q":"В какой момент водителю, совершившему остановку на обочине при движении организованной транспортной колонны, разрешается возобновить движение?","a":["После проезда последнего автобуса, движущегося в составе организованной транспортной колонны.","После проезда транспортного средства оперативного назначения с включённым маячком синего цвета."],"c":1,"e":"<p>В показанной ситуации водителю, совершившему остановку на обочине при движении транспортного средства оперативного назначения с включёнными маячками синего и красного цветов, сопровождавшего организованную транспортную колонну, разрешается возобновить движение после проезда замыкающего колонну транспортного средства оперативного назначения с включённым маячком синего цвета.</p>","image":"assets/adrive-questions/q100601903.jpg"},{"id":100602001,"themeId":1,"group":1006020,"chapter":6,"chapters":[6],"q":"Разрешается ли двигаться по соседней полосе движения с транспортным средством оперативного назначения с одинаковой скоростью?","a":["Да, разрешается.","Нет, не разрешается.","Нет, если транспортное средство оперативного назначения движется с включённым маячком синего или синего и красного цветов."],"c":2,"e":"<p>Если транспортное средство оперативного назначения движется с включённым маячком синего или синего и красного цветов, то двигаться по соседней полосе движения с одинаковой скоростью с ним запрещено.</p>","image":null},{"id":100602002,"themeId":1,"group":1006020,"chapter":6,"chapters":[6],"q":"Разрешается ли опережать транспортное средство оперативного назначения?","a":["Да, разрешается.","Нет, не разрешается.","Нет, если транспортное средство оперативного назначения движется с включённым маячком синего или синего и красного цветов."],"c":2,"e":"<p>Если транспортное средство оперативного назначения движется с включённым маячком синего или синего и красного цветов, то опережать его запрещено.</p>","image":null},{"id":100602003,"themeId":1,"group":1006020,"chapter":6,"chapters":[6],"q":"Разрешается ли занимать место в организованной транспортной колонне?","a":["Да, если в замыкании колонны нет транспортного средства оперативного назначения.","Да, если позволяет дистанция между движущимися в колонне транспортными средствами.","Нет, не разрешается."],"c":2,"e":"<p>Занимать место в организованной транспортной колонне, пересекать её запрещено.</p>","image":"assets/adrive-questions/q100602003.jpg"},{"id":100602101,"themeId":1,"group":1006021,"chapter":6,"chapters":[6],"q":"Двигаясь во второй полосе движения, водитель легкового автомобиля увидел в начале транспортной колонны транспортное средство оперативного назначения с включённым маячком синего цвета. Какие его действия в такой ситуации будут соответствовать Правилам дорожного движения?","a":["Снизит скорость, продолжая движение позади замыкающего колонну транспортного средства.","Продолжит движение по второй полосе движения, опережая организованную транспортную колонну, если скорость её движения не превышает 40 км/ч."],"c":0,"e":"<p>В показанной ситуации водитель легкового автомобиля, двигаясь во второй полосе движения, увидел в начале транспортной колонны транспортное средство оперативного назначения с включённым маячком синего цвета, поэтому должен снизить скорость, продолжая движение позади замыкающего колонну транспортного средства, так как опережать организованную транспортную колонну запрещено.</p>","image":"assets/adrive-questions/q100602101.jpg"},{"id":100602102,"themeId":1,"group":1006021,"chapter":6,"chapters":[6],"q":"Водитель красного автомобиля увидел в зеркале заднего вида приближающуюся организованную транспортную колонну. Какие его действия в ситуации, когда первый автомобиль колонны поравнялся с ним (начал опережать его), будут соответствовать Правилам дорожного движения?","a":["Поравнявшись с организованной транспортной колонной, будет двигаться со скоростью колонны.","Увеличит скорость, чтобы не двигаться по соседней полосе с организованной транспортной колонной.","Продолжит движение с прежней скоростью, предоставляя возможность для дальнейшего опережения себя организованной транспортной колонне."],"c":2,"e":"<p>В показанной ситуации водитель красного автомобиля увидел в зеркале заднего вида приближающуюся организованную транспортную колонну в сопровождении транспортного средства оперативного назначения с включённым маячком синего цвета. Поэтому ему необходимо продолжить движение с прежней скоростью, предоставляя возможность для дальнейшего опережения себя организованной транспортной колонне.</p>","image":"assets/adrive-questions/q100602102.jpg"},{"id":100602103,"themeId":1,"group":1006021,"chapter":6,"chapters":[6],"q":"Разрешено ли выполнить опережение транспортного средства оперативного назначения с выключенными маячками синего и красного цветов?","a":["Разрешено, не превышая максимальную разрешённую скорость движения для данного участка дороги.","Запрещено."],"c":0,"e":"<p>Водителям не запрещается выполнять обгон и опережение транспортных средств оперативного назначения с выключенными маячками синего или синего и красного цветов, а также двигаться по соседним полосам движения с их скоростью движения.</p>","image":"assets/adrive-questions/q100602103.jpg"},{"id":100602201,"themeId":1,"group":1006022,"chapter":6,"chapters":[6],"q":"Как Вы должны поступить при приближении к остановившемуся на противоположной стороне дороги транспортному средству оперативного назначения с включённым маячком синего цвета?","a":["Снизить скорость движения, чтобы иметь возможность немедленно остановиться в случае необходимости.","Продолжать движение, так как транспортное средство оперативного назначения стоит на противоположной стороне дороги.","Остановиться в полосе движения и не начинать движение без разрешения регулировщика или выключения маячка синего цвета.","Съехать на обочину и остановиться (при отсутствии обочины — занять крайнее правое положение на проезжей части дороги и остановиться)."],"c":0,"e":"<p>В показанной ситуации при приближении к остановившемуся на противоположной стороне дороги транспортному средству оперативного назначения с включённым маячком синего цвета, Вам необходимо снизить скорость движения, чтобы иметь возможность немедленно остановиться в случае необходимости.</p>","image":"assets/adrive-questions/q100602201.jpg"},{"id":100602202,"themeId":1,"group":1006022,"chapter":6,"chapters":[6],"q":"Как Вы должны поступить при приближении к остановившемуся на полосе движения транспортному средству оперативного назначения с включённым маячком синего цвета?","a":["Остановиться в полосе движения и не начинать движение без разрешения регулировщика или выключения маячка синего цвета.","Съехать на обочину и остановиться (при отсутствии обочины — занять крайнее правое положение на проезжей части дороги и остановиться).","Снизить скорость движения, чтобы иметь возможность немедленно остановиться в случае необходимости, после чего объехать остановившееся транспортное средство оперативного назначения."],"c":2,"e":"<p>В показанной ситуации при приближении к остановившемуся на полосе движения транспортному средству оперативного назначения с включённым маячком синего цвета, Вы должны снизить скорость движения, чтобы иметь возможность немедленно остановиться в случае необходимости, после чего объехать остановившееся транспортное средство оперативного назначения.</p>","image":"assets/adrive-questions/q100602202.jpg"},{"id":100602301,"themeId":1,"group":1006023,"chapter":6,"chapters":[6],"q":"Как Вы должны поступить, приближаясь в показанной ситуации к остановившемуся автомобилю скорой помощи с включёнными маячками?","a":["Остановиться справа у тротуара.","Снизить скорость движения, чтобы иметь возможность немедленно остановиться в случае необходимости.","Продолжать движение, так как транспортное средство оперативного назначения стоит на противоположной стороне дороги за разделительной полосой."],"c":1,"e":"<p>В показанной ситуации, приближаясь к остановившемуся автомобилю скорой помощи с включёнными маячками синего цвета, Вы должны снизить скорость движения, чтобы иметь возможность немедленно остановиться в случае необходимости.</p>","image":"assets/adrive-questions/q100602301.jpg"},{"id":100602302,"themeId":1,"group":1006023,"chapter":6,"chapters":[6],"q":"Что должен сделать водитель зелёного автомобиля при приближении к стоящему транспортному средству оперативного назначения в ситуации, показанной на рисунке?","a":["Остановиться в полосе движения и не начинать движение без разрешения регулировщика или выключения маячка синего цвета.","Убедиться в отсутствии встречных транспортных средств и с соблюдением мер предосторожности объехать остановившиеся транспортные средства.","Снизить скорость движения, чтобы иметь возможность немедленно остановиться в случае необходимости, после чего объехать остановившиеся транспортные средства, убедившись в отсутствии транспортных средств на встречной полосе движения."],"c":2,"e":"<p>В показанной ситуации при приближении к стоящему транспортному средству оперативного назначения с включённым маячком синего цвета водитель зелёного автомобиля должен снизить скорость движения, чтобы иметь возможность немедленно остановиться в случае необходимости, после чего объехать остановившиеся транспортные средства, убедившись в отсутствии транспортных средств на встречной полосе движения.</p>","image":"assets/adrive-questions/q100602302.jpg"},{"id":100602401,"themeId":1,"group":1006024,"chapter":6,"chapters":[6],"q":"Что должен сделать водитель зелёного автомобиля при приближении к стоящему транспортному средству оперативного назначения в ситуации, показанной на рисунке?","a":["Убедиться в отсутствии встречных транспортных средств и с соблюдением мер предосторожности объехать остановившиеся транспортные средства.","Остановиться в полосе движения, не доезжая до транспортного средства оперативного назначения, и не начинать движение без разрешения регулировщика или выключения маячка красного цвета.","Снизить скорость движения, чтобы иметь возможность немедленно остановиться в случае необходимости, после чего объехать остановившиеся транспортные средства, убедившись в отсутствии транспортных средств на встречной полосе движения."],"c":1,"e":"<p>В показанной ситуации при приближении к стоящему транспортному средству оперативного назначения с включёнными маячками синего и красного цветов водитель зелёного автомобиля должен остановиться в полосе движения, не доезжая до транспортного средства оперативного назначения, и не начинать движение без разрешения регулировщика или выключения маячка красного цвета.</p>","image":"assets/adrive-questions/q100602401.jpg"},{"id":100602402,"themeId":1,"group":1006024,"chapter":6,"chapters":[6],"q":"Что должен сделать водитель зелёного автомобиля при приближении к стоящему транспортному средству оперативного назначения в ситуации, показанной на рисунке?","a":["Снизить скорость движения, чтобы иметь возможность немедленно остановиться в случае необходимости.","Продолжать движение, так как транспортное средство оперативного назначения стоит на противоположной стороне дороги за разделительной полосой.","Остановиться в полосе движения, не доезжая до транспортного средства оперативного назначения, и не начинать движение без разрешения регулировщика или выключения маячка красного цвета."],"c":2,"e":"<p>В показанной ситуации при приближении к стоящему транспортному средству оперативного назначения с включёнными маячками синего и красного цветов и сотруднику ГАИ, который подаёт сигнал об остановке жезлом, водитель зелёного автомобиля должен остановиться в полосе движения, не доезжая до транспортного средства оперативного назначения, и не начинать движение без разрешения регулировщика или выключения маячка красного цвета.</p>","image":"assets/adrive-questions/q100602402.jpg"},{"id":100602403,"themeId":1,"group":1006024,"chapter":6,"chapters":[6],"q":"Водители каких транспортных средств обязаны остановиться при приближении к стоящему транспортному средству оперативного назначения с включёнными маячками синего и красного цветов?","a":["Только водитель грузового автомобиля.","Только водитель легкового автомобиля.","Водители автобуса и грузового автомобиля.","Водители всех автомобилей."],"c":3,"e":"<p>В показанной ситуации при приближении к стоящему транспортному средству оперативного назначения с включёнными маячками синего и красного цветов и сотруднику ГАИ, который подаёт сигнал об остановке жезлом водителю зелёного автомобиля, водители всех автомобилей обязаны остановиться, не доезжая до транспортного средства оперативного назначения.</p>","image":"assets/adrive-questions/q100602403.jpg"},{"id":100602501,"themeId":1,"group":1006025,"chapter":6,"chapters":[6],"q":"Как Вы должны поступить при приближении к стоящему транспортному средству оперативного назначения с включённым маячком красного цвета?","a":["Снизить скорость движения, чтобы иметь возможность немедленно остановиться в случае необходимости.","Остановиться, доехав до транспортного средства оперативного назначения, и продолжить движение только после разрешения регулировщика или выключения маячка красного цвета.","Остановиться, не доезжая до транспортного средства оперативного назначения, и продолжить движение только после разрешения регулировщика или выключения маячка красного цвета."],"c":2,"e":"<p>В показанной ситуации при приближении к стоящему транспортному средству оперативного назначения с включённым маячком красного цвета водитель должен остановиться, не доезжая до транспортного средства оперативного назначения, и продолжить движение только после разрешения регулировщика или выключения маячка красного цвета.</p>","image":"assets/adrive-questions/q100602501.jpg"},{"id":100602502,"themeId":1,"group":1006025,"chapter":6,"chapters":[6],"q":"Какого цвета маячок должен быть включён на стоящем транспортном средстве оперативного назначения для остановки движущегося по дороге транспортного средства?","a":["Синего цвета.","Красного цвета.","Любого из перечисленных цветов."],"c":1,"e":"<p>Для остановки движущегося по дороге транспортного средства на стоящем транспортном средстве оперативного назначения должен быть включён маячок красного цвета.</p>","image":null},{"id":100602701,"themeId":1,"group":1006027,"chapter":6,"chapters":[6],"q":"Для чего на транспортных средствах оперативного назначения может применяться специальный звуковой сигнал?","a":["Для предоставления преимущества в движении.","Для привлечения внимания участников дорожного движения.","Для подачи сигнала остановки водителям транспортных средств.","Во всех перечисленных случаях."],"c":1,"e":"<p>На транспортных средствах оперативного назначения специальный звуковой сигнал может применяться для привлечения внимания участников дорожного движения.</p>","image":null},{"id":100602702,"themeId":1,"group":1006027,"chapter":6,"chapters":[6],"q":"Обязаны ли водители транспортных средств оперативного назначения включать специальный звуковой сигнал при включении маячков синего или синего и красного цветов?","a":["Да, обязаны.","Нет, не обязаны."],"c":1,"e":"<p>Включение специального звукового сигнала на транспортных средствах оперативного назначения при включении маячков синего или синего и красного цветов не обязательно. На транспортных средствах оперативного назначения специальный звуковой сигнал может применяться для привлечения внимания участников дорожного движения.</p>","image":null},{"id":100602703,"themeId":1,"group":1006027,"chapter":6,"chapters":[6],"q":"Водителями транспортных средств оперативного назначения:","a":["Должен подаваться специальный звуковой сигнал для привлечения внимания участников дорожного движения.","Может подаваться специальный звуковой сигнал для привлечения внимания участников дорожного движения.","Не должен подаваться специальный звуковой сигнал во избежание отвлечения внимания участников дорожного движения."],"c":1,"e":"<p>На транспортных средствах оперативного назначения специальный звуковой сигнал может применяться для привлечения внимания участников дорожного движения. Обязательное включение специального звукового сигнала на транспортных средствах оперативного назначения при включении маячков синего или синего и красного цветов не обязательно.</p>","image":null},{"id":100602901,"themeId":1,"group":1006029,"chapter":6,"chapters":[6],"q":"Могут ли водители транспортных средств дорожно-эксплуатационной службы отступать от требований дорожных знаков и разметки?","a":["Могут только в ходе выполнения работ на дороге.","Могут в любом случае при включении маячка оранжевого цвета.","Могут только при включении маячка оранжевого цвета в ходе выполнения работ на дороге."],"c":2,"e":"<p>Водители транспортных средств дорожно-эксплуатационной службы могут отступать от требований дорожных знаков и разметки только при включении маячка оранжевого цвета в ходе выполнения работ на дороге.</p>","image":"assets/adrive-questions/q100602901.jpg"},{"id":100602902,"themeId":1,"group":1006029,"chapter":6,"chapters":[6],"q":"Предоставляет ли преимущество в движении маячок оранжевого цвета, включённый на механическом транспортном средстве, осуществляющем сопровождение при перевозке крупногабаритных грузов?","a":["Да, предоставляет.","Нет, не предоставляет.","Предоставляет только при проезде узких участков дорог, на которых затруднён встречный разъезд."],"c":1,"e":"<p>В показанной ситуации включённый маячок оранжевого цвета на механическом транспортном средстве, осуществляющем сопровождение при перевозке крупногабаритных грузов, не даёт преимущества в движении и служит для привлечения внимания и предупреждения участников дорожного движения о возможной опасности.</p>","image":"assets/adrive-questions/q100602902.jpg"},{"id":100602903,"themeId":1,"group":1006029,"chapter":6,"chapters":[6],"q":"Предоставляет ли преимущество в движении маячок оранжевого цвета, включённый на механическом транспортном средстве, перевозящем опасные грузы?","a":["Да, предоставляет.","Нет, не предоставляет.","Предоставляет только при проезде нерегулируемых перекрёстков."],"c":1,"e":"<p>Включённый маячок оранжевого цвета на механическом транспортном средстве, перевозящем опасные грузы, не даёт преимущества в движении и служит для привлечения внимания и предупреждения участников дорожного движения о возможной опасности.</p>","image":"assets/adrive-questions/q100602903.jpg"},{"id":100603001,"themeId":1,"group":1006030,"chapter":6,"chapters":[6],"q":"Обязан ли водитель, являющийся участником дорожно-транспортного происшествия, принять меры по оказанию необходимой помощи пострадавшему (пострадавшим)?","a":["Обязан только в случае невозможности вызова скорой медицинской помощи.","Обязан только в случае, если он является виновником дорожно-транспортного происшествия.","Обязан только в случае, если сам не пострадал в дорожно-транспортном происшествии.","Обязан во всех вышеперечисленных случаях."],"c":3,"e":"<p>Водитель, являющийся участником дорожно-транспортного происшествия, обязан при необходимости принять меры по оказанию необходимой помощи пострадавшему (пострадавшим).</p>","image":"assets/adrive-questions/q100603001.jpg"},{"id":100603002,"themeId":1,"group":1006030,"chapter":6,"chapters":[6],"q":"Обязан ли водитель, являющийся участником дорожно-транспортного происшествия, вызвать скорую медицинскую помощь при наличии пострадавших?","a":["Обязан только в случае, если он является виновником дорожно-транспортного происшествия.","Обязан только в случае, если они сами попросят вызвать скорую медицинскую помощь.","Обязан в любом случае."],"c":2,"e":"<p>Водитель, являющийся участником дорожно-транспортного происшествия, обязан при имеющейся возможности вызвать скорую медицинскую помощь при наличии пострадавших.</p>","image":"assets/adrive-questions/q100603002.jpg"},{"id":100603101,"themeId":1,"group":1006031,"chapter":6,"chapters":[6],"q":"В каком случае водитель, являющийся участником дорожно-транспортного происшествия, обязан принять меры по доставке пострадавших в ближайшую организацию здравоохранения на одном или нескольких попутных транспортных средствах?","a":["Только в случае, если невозможно вызвать скорую медицинскую помощь.","Только в случае, если он является виновником в совершении дорожно-транспортного происшествия.","Только в случае, если невозможно доставить пострадавших на транспортном средстве, при участии которого совершено дорожно-транспортное происшествие."],"c":0,"e":"<p>Водитель, являющийся участником дорожно-транспортного происшествия, обязан принять меры по доставке пострадавших в ближайшую организацию здравоохранения на одном или нескольких попутных транспортных средствах только в случае, если невозможно вызвать скорую медицинскую помощь.</p>","image":"assets/adrive-questions/q100603101.jpg"},{"id":100603102,"themeId":1,"group":1006031,"chapter":6,"chapters":[6],"q":"В каком случае водитель, являющийся участником дорожно-транспортного происшествия, обязан доставить пострадавших в ближайшую организацию здравоохранения на транспортном средстве, при участии которого совершено дорожно-транспортное происшествие?","a":["Только в случае отсутствия повреждений кузова транспортного средства.","Только в случае, если он является виновником в совершении дорожно-транспортного происшествия.","Только в случае, если невозможно вызвать скорую медицинскую помощь и отсутствии попутных транспортных средств."],"c":2,"e":"<p>Водитель, являющийся участником дорожно-транспортного происшествия, обязан доставить пострадавших в ближайшую организацию здравоохранения на транспортном средстве, при участии которого совершено дорожно-транспортное происшествие только в случае, если невозможно вызвать скорую медицинскую помощь и отсутствии попутных транспортных средств.</p>","image":"assets/adrive-questions/q100603102.jpg"},{"id":100603103,"themeId":1,"group":1006031,"chapter":6,"chapters":[6],"q":"В каком случае водитель, являющийся участником дорожно-транспортного происшествия, обязан доставить пострадавших в ближайшую организацию здравоохранения на транспортном средстве, при участии которого совершено дорожно-транспортное происшествие, если невозможно вызвать скорую медицинскую помощь и при отсутствии попутных транспортных средств?","a":["Обязан только в попутном направлении.","Обязан, если является виновником дорожно-транспортного происшествия.","Обязан, если не является виновником дорожно-транспортного происшествия.","Обязан во всех случаях."],"c":3,"e":"<p>Водитель, являющийся участником дорожно-транспортного происшествия, обязан во всех случаях доставить пострадавших в ближайшую организацию здравоохранения на транспортном средстве, при участии которого совершено дорожно-транспортное происшествие, если невозможно вызвать скорую медицинскую помощь и при отсутствии попутных транспортных средств.</p>","image":"assets/adrive-questions/q100603103.jpg"},{"id":100603202,"themeId":1,"group":1006032,"chapter":6,"chapters":[6],"q":"Обязан ли водитель, являющийся участником дорожно-транспортного происшествия, доставивший пострадавшего в дорожно-транспортном происшествии в организацию здравоохранения, возвратиться к месту дорожно-транспортного происшествия?","a":["Водитель обязан возвратиться к месту дорожно-транспортного происшествия.","Водитель может следовать в ближайшее отделение ГАИ для составления протокола на основании зафиксированных в присутствии очевидцев положения транспортного средства, следов и предметов, относящихся к дорожно-транспортному происшествию."],"c":0,"e":"<p>Водитель, являющийся участником дорожно-транспортного происшествия, обязан доставить пострадавшего в дорожно-транспортном происшествии в организацию здравоохранения и после этого возвратиться к месту дорожно-транспортного происшествия.</p>","image":null},{"id":100603231,"themeId":1,"group":1006032,"chapter":6,"chapters":[6],"q":"Что обязан сообщить водитель, доставивший пострадавшего в дорожно-транспортном происшествии в организацию здравоохранения?","a":["Фамилию и адрес места жительства пострадавшего в дорожно-транспортном происшествии.","Фамилии и адреса очевидцев дорожно-транспортного происшествия, свою фамилию, предъявив общегражданский паспорт.","Марку автомобиля, при участии которого совершено дорожно-транспортное происшествие, стаж вождения и время нахождения за рулём автомобиля.","Свою фамилию, регистрационный знак (временный номерной знак) транспортного средства, предъявив водительское удостоверение или документ, удостоверяющий личность, и свидетельство о регистрации транспортного средства либо документ, подтверждающий законность его приобретения."],"c":3,"e":"<p>Водитель, доставивший пострадавшего (пострадавших) в организацию здравоохранения, обязан сообщить в этой организации свою фамилию, регистрационный знак (временный номерной знак) транспортного средства, предъявив водительское удостоверение или документ, удостоверяющий личность, и свидетельство о регистрации транспортного средства либо документ, подтверждающий законность его приобретения.</p>","image":null},{"id":100603233,"themeId":1,"group":1006032,"chapter":6,"chapters":[6],"q":"Что обязан сообщить водитель, доставивший пострадавшего в дорожно-транспортном происшествии в организацию здравоохранения?","a":["Свою фамилию, предъявив водительское удостоверение или документ, удостоверяющий личность.","Регистрационный знак (временный номерной знак) транспортного средства, предъявив свидетельство о регистрации транспортного средства либо документ, подтверждающий законность его приобретения.","Всё перечисленное."],"c":2,"e":"<p>Водитель, доставивший пострадавшего (пострадавших) в организацию здравоохранения, обязан сообщить в этой организации свою фамилию, регистрационный знак (временный номерной знак) транспортного средства, предъявив водительское удостоверение или документ, удостоверяющий личность, и свидетельство о регистрации транспортного средства либо документ, подтверждающий законность его приобретения.</p>","image":null},{"id":100603301,"themeId":1,"group":1006033,"chapter":6,"chapters":[6],"q":"Что предварительно необходимо сделать водителю, являющемуся участником дорожно-транспортного происшествия, в случае необходимости доставки пострадавшего в организацию здравоохранения на транспортном средстве, при участии которого совершено ДТП?","a":["Записать фамилии и адреса очевидцев дорожно-транспортного происшествия.","Оградить место дорожно-транспортного происшествия, организовать объезд места ДТП.","Зафиксировать в присутствии очевидцев положение транспортного средства, следы и предметы, относящиеся к дорожно-транспортному происшествию."],"c":2,"e":"<p>Водителю, являющемуся участником дорожно-транспортного происшествия, в случае необходимости доставки пострадавшего в организацию здравоохранения на транспортном средстве, при участии которого совершено ДТП, необходимо предварительно зафиксировать в присутствии очевидцев положение транспортного средства, следы и предметы, относящиеся к дорожно-транспортному происшествию.</p>","image":"assets/adrive-questions/q100603301.jpg"},{"id":100603302,"themeId":1,"group":1006033,"chapter":6,"chapters":[6],"q":"Что предварительно необходимо сделать водителю, являющемуся участником дорожно-транспортного происшествия, в случае необходимости доставки пострадавшего в организацию здравоохранения на транспортном средстве, при участии которого совершено ДТП?","a":["Зафиксировать в присутствии очевидцев положение транспортного средства, следы и предметы, относящиеся к дорожно-транспортному происшествию.","Записать фамилии и адреса очевидцев дорожно-транспортного происшествия, опросить их, записав их показания, составить подробную схему ДТП, сфотографировать место ДТП.","Записать фамилии и адреса очевидцев дорожно-транспортного происшествия, сообщить им свой адрес, телефон и в какую организацию здравоохранения будет доставлен пострадавший."],"c":0,"e":"<p>Водителю, являющемуся участником дорожно-транспортного происшествия, в случае необходимости доставки пострадавшего в организацию здравоохранения на транспортном средстве, при участии которого совершено ДТП, необходимо предварительно зафиксировать в присутствии очевидцев положение транспортного средства, следы и предметы, относящиеся к дорожно-транспортному происшествию.</p>","image":"assets/adrive-questions/q100603302.jpg"},{"id":100603401,"themeId":1,"group":1006034,"chapter":6,"chapters":[6],"q":"В каком ответе водитель, являющийся участником дорожно-транспортного происшествия, не нарушил последовательность действий, предписанную в таком случае Правилами дорожного движения?","a":["Остановился, включил аварийную световую сигнализацию, выставил знак аварийной остановки, оказал необходимую помощь пострадавшим, записал фамилии и адреса очевидцев, сообщил о случившемся в милицию.","Остановился, включил аварийную световую сигнализацию, выставил знак аварийной остановки, сообщил о случившемся в милицию, записал фамилии и адреса очевидцев, оказал необходимую помощь пострадавшим.","Остановился, включил аварийную световую сигнализацию, выставил знак аварийной остановки, сообщил о случившемся в милицию, оказал необходимую помощь пострадавшим, записал фамилии и адреса очевидцев.","Остановился, включил аварийную световую сигнализацию, выставил знак аварийной остановки, оказал необходимую помощь пострадавшим, сообщил о случившемся в милицию, записал фамилии и адреса очевидцев."],"c":0,"e":"<p>Водитель, являющийся участником дорожно-транспортного происшествия, должен остановиться, включить аварийную световую сигнализацию, выставить знак аварийной остановки, оказать необходимую помощь пострадавшим, записать фамилии и адреса очевидцев и сообщить о случившемся в милицию.</p>","image":null},{"id":100603402,"themeId":1,"group":1006034,"chapter":6,"chapters":[6],"q":"В каком ответе водитель, являющийся участником дорожно-транспортного происшествия с участием одного транспортного средства, наиболее точно выполнил требования Правил дорожного движения при отсутствии пострадавших?","a":["Остановился, включил аварийную световую сигнализацию, выставил знак аварийной остановки, сообщил о случившемся в милицию, записал фамилии и адреса очевидцев, до прибытия сотрудников ГАИ принял все возможные меры по сохранению следов и предметов, относящихся к ДТП.","Остановился, включил аварийную световую сигнализацию, выставил знак аварийной остановки, до прибытия сотрудников ГАИ принял все возможные меры по сохранению следов и предметов, относящихся к ДТП, записал фамилии и адреса очевидцев, сообщил о случившемся в милицию.","Остановился, включил аварийную световую сигнализацию, выставил знак аварийной остановки, записал фамилии и адреса очевидцев, сообщил о случившемся в милицию, до прибытия сотрудников ГАИ принял все возможные меры по сохранению следов и предметов, относящихся к ДТП."],"c":2,"e":"<p>Водитель, являющийся участником дорожно-транспортного происшествия с участием одного транспортного средства, должен остановиться, включить аварийную световую сигнализацию, выставить знак аварийной остановки, записать фамилии и адреса очевидцев, сообщить о случившемся в милицию и до прибытия сотрудников ГАИ принять все возможные меры по сохранению следов и предметов, относящихся к ДТП.</p>","image":null},{"id":100603403,"themeId":1,"group":1006034,"chapter":6,"chapters":[6],"q":"В каком ответе правильно указаны действия водителя автомобиля, совершившего наезд на пешехода, после включения аварийной световой сигнализации?","a":["Принял меры по оказанию необходимой помощи пострадавшему, выставил знак аварийной остановки, сообщил в милицию.","Принял меры по оказанию необходимой помощи пострадавшему, сообщил в милицию, вызвал скорую медицинскую помощь, выставил знак аварийной остановки.","Выставил знак аварийной остановки, принял меры по оказанию необходимой помощи пострадавшему, вызвал скорую медицинскую помощь, записал фамилии и адреса очевидцев, сообщил в милицию."],"c":2,"e":"<p>Водитель автомобиля, совершившего наезд на пешехода, после включения аварийной световой сигнализации должен выставить знак аварийной остановки, принять меры по оказанию необходимой помощи пострадавшему, вызвать скорую медицинскую помощь, записать фамилии и адреса очевидцев и сообщить в милицию.</p>","image":null},{"id":100603501,"themeId":1,"group":1006035,"chapter":6,"chapters":[6],"q":"В каком случае водитель, являющийся участником дорожно-транспортного происшествия, вправе не сообщать о нём в ГАИ?","a":["Если в результате ДТП, произошедшего с участием двух транспортных средств (включая автопоезда), вред причинён только имуществу его участников и в отношении транспортных средств имеются договоры обязательного страхования гражданской ответственности их владельцев, а лица, управлявшие транспортными средствами, имеют право на управление транспортным средством соответствующей категории.","Если обстоятельства причинения вреда в связи с повреждением имущества в результате дорожно-транспортного происшествия, характер и перечень видимых повреждений транспортных средств не вызывают разногласий у участников данного происшествия и зафиксированы в извещениях о ДТП, бланки которых заполнены лицами, управлявшими транспортными средствами.","Если лица, управлявшие транспортными средствами, не предъявляют претензий к состоянию друг друга (данные лица не находятся в состоянии алкогольного опьянения либо в состоянии, вызванном употреблением наркотических средств, психотропных, токсических или других одурманивающих веществ, в результате ДТП не причинён вред жизни или здоровью), а вред, причинённый имуществу каждого из участников ДТП, оценивается ими в размере до 150 базовых величин.","Водитель вправе не сообщать в ГАИ только при выполнении всех перечисленных условий."],"c":3,"e":"<p>Водитель, являющийся участником дорожно-транспортного происшествия, вправе не сообщать о нём в ГАИ только при выполнении всех перечисленных условий.</p>","image":null},{"id":100603502,"themeId":1,"group":1006035,"chapter":6,"chapters":[6],"q":"Имеет ли право водитель, совершивший наезд на растущее дерево, не сообщать о случившемся в ГАИ, если в результате вред, причинённый его автомобилю, оценивается им в размере до 150 базовых величин?","a":["Да, имеет право не сообщать о случившемся в ГАИ.","Нет, не имеет права не сообщать о случившемся в ГАИ."],"c":1,"e":"<p>Водитель, совершивший наезд на растущее дерево (ДТП при участии только одного механического транспортного средства), даже если в результате вред, причинённый его автомобилю, оценивается им в размере до 150 базовых величин, обязан сообщить о случившемся в ГАИ.</p>","image":"assets/adrive-questions/q100603502.jpg"},{"id":100603503,"themeId":1,"group":1006035,"chapter":6,"chapters":[6],"q":"Вправе ли водители двух автомобилей при их попутном столкновении не сообщать о случившемся в ГАИ, если вред, причинённый каждому транспортному средству, оценивается ими в размере до 150 базовых величин, у пассажира имелось незначительное кровотечение, ему была наложена повязка, и ему не понадобилось обращаться в медицинское учреждение?","a":["Да, имеют право не сообщать о случившемся в ГАИ.","Нет, не имеют права не сообщать о случившемся в ГАИ."],"c":1,"e":"<p>В показанной ситуации при попутном столкновении двух автомобилей был причинён вред здоровью пассажира. Поэтому водители обязаны сообщить о случившемся в ГАИ.</p>","image":"assets/adrive-questions/q100603503.jpg"},{"id":100603601,"themeId":1,"group":1006036,"chapter":6,"chapters":[6],"q":"В каком случае водителю, являющемуся участником дорожно-транспортного происшествия, разрешается перемещать транспортное средство до прибытия сотрудников ГАИ на место ДТП?","a":["Если положение транспортного средства делает невозможной организацию объезда места ДТП.","Если необходимо доставить пострадавшего в ближайшую организацию здравоохранения при невозможности вызвать скорую помощь и отсутствии попутных транспортных средств, предварительно зафиксировав в присутствии очевидцев положение транспортного средства, следы и предметы, относящиеся к ДТП.","Разрешено в обоих случаях."],"c":1,"e":"<p>Водителю, являющемуся участником дорожно-транспортного происшествия, разрешается перемещать транспортное средство до прибытия сотрудников ГАИ на место ДТП, если необходимо доставить пострадавшего в ближайшую организацию здравоохранения при невозможности вызвать скорую помощь и отсутствии попутных транспортных средств, предварительно зафиксировав в присутствии очевидцев положение транспортного средства, следы и предметы, относящиеся к ДТП.</p>","image":null},{"id":100603602,"themeId":1,"group":1006036,"chapter":6,"chapters":[6],"q":"Разрешается ли водителю, являющемуся участником ДТП, в ожидании прибытия сотрудников ГАИ передвинуть свой автомобиль для организации возможности проезда места ДТП, предварительно зафиксировав в присутствии очевидцев положение транспортного средства при отсутствии пострадавших?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>В показанной ситуации водителю, являющемуся участником ДТП, в ожидании прибытия сотрудников ГАИ передвинуть свой автомобиль запрещено.</p>","image":"assets/adrive-questions/q100603602.jpg"},{"id":100603901,"themeId":1,"group":1006039,"chapter":6,"chapters":[6],"q":"В каком ответе пешеход, являющийся очевидцем дорожно-транспортного происшествия, не нарушил последовательность действий, предписанную в таком случае Правилами дорожного движения?","a":["Оказал возможную помощь пострадавшему (пострадавшим), записал фамилии и адреса других очевидцев ДТП, а также регистрационные знаки (временные номерные знаки) транспортных средств, находившихся при совершении ДТП, сообщил в милицию о ДТП, после прибытия сотрудников ГАИ сообщил им информацию о ДТП.","Сообщил в милицию о ДТП, оказал возможную помощь пострадавшему (пострадавшим), записал фамилии и адреса других очевидцев ДТП, а также регистрационные знаки (временные номерные знаки) транспортных средств, находившихся при совершении ДТП, после прибытия сотрудников ГАИ сообщил им информацию о ДТП.","Оказал возможную помощь пострадавшему (пострадавшим), сообщил в милицию о ДТП, записал фамилии и адреса других очевидцев ДТП, а также регистрационные знаки (временные номерные знаки) транспортных средств, находившихся при совершении ДТП, после прибытия сотрудников ГАИ сообщил им информацию о ДТП."],"c":0,"e":"<p>Пешеход, являющийся очевидцем дорожно-транспортного происшествия, обязан оказать возможную помощь пострадавшему (пострадавшим), записать фамилии и адреса других очевидцев ДТП, а также регистрационные знаки (временные номерные знаки) транспортных средств, находившихся при совершении ДТП, сообщить в милицию о ДТП и после прибытия сотрудников ГАИ сообщить им информацию о ДТП.</p>","image":null},{"id":100603902,"themeId":1,"group":1006039,"chapter":6,"chapters":[6],"q":"В каком ответе пассажир, являющийся участником дорожно-транспортного происшествия, не нарушил последовательность действий, предписанную в таком случае Правилами дорожного движения?","a":["Сообщил в милицию о ДТП, оказал возможную помощь пострадавшему (пострадавшим), записал фамилии и адреса других очевидцев ДТП, а также регистрационные знаки (временные номерные знаки) транспортных средств, находившихся при совершении ДТП, после прибытия сотрудников ГАИ сообщил им информацию о ДТП.","Оказал возможную помощь пострадавшему (пострадавшим), сообщил в милицию о ДТП, записал фамилии и адреса других очевидцев ДТП, а также регистрационные знаки (временные номерные знаки) транспортных средств, находившихся при совершении ДТП, после прибытия сотрудников ГАИ сообщил им информацию о ДТП.","Оказал возможную помощь пострадавшему (пострадавшим), записал фамилии и адреса других очевидцев ДТП, а также регистрационные знаки (временные номерные знаки) транспортных средств, находившихся при совершении ДТП, сообщил в милицию о ДТП, после прибытия сотрудников ГАИ сообщил им информацию о ДТП."],"c":2,"e":"<p>Пассажир, являющийся участником дорожно-транспортного происшествия, обязан оказать возможную помощь пострадавшему (пострадавшим), записать фамилии и адреса других очевидцев ДТП, а также регистрационные знаки (временные номерные знаки) транспортных средств, находившихся при совершении ДТП, сообщить в милицию о ДТП и после прибытия сотрудников ГАИ сообщить им информацию о ДТП.</p>","image":null},{"id":100604001,"themeId":1,"group":1006040,"chapter":6,"chapters":[6],"q":"В каком ответе наиболее полно указано, что обязан сделать водитель при обнаружении на дороге препятствия, создающего опасность для движения?","a":["Обозначить препятствие в соответствии с Правилами дорожного движения, после чего сообщить о препятствии в милицию либо дорожно-эксплуатационную или коммунальную службу.","Принять меры по его устранению, а если его невозможно устранить — обозначить в соответствии с Правилами дорожного движения или иным способом, обеспечивающим безопасность дорожного движения.","Принять меры по его устранению, а если его невозможно устранить — обозначить в соответствии с Правилами дорожного движения или иным способом, обеспечивающим безопасность дорожного движения, после чего сообщить о препятствии в милицию либо дорожно-эксплуатационную или коммунальную службу."],"c":2,"e":"<p>Водитель при обнаружении на дороге препятствия, создающего опасность для движения, обязан принять меры по его устранению, а если его невозможно устранить — обозначить в соответствии с Правилами дорожного движения или иным способом, обеспечивающим безопасность дорожного движения, после чего сообщить о препятствии в милицию либо дорожно-эксплуатационную или коммунальную службу.</p>","image":null},{"id":100604002,"themeId":1,"group":1006040,"chapter":6,"chapters":[6],"q":"В каком ответе водитель при обнаружении на дороге препятствия, создающего опасность для движения, не нарушил последовательность действий, определённую Правилами дорожного движения?","a":["Сообщил о препятствии в милицию, после чего попытался устранить его самостоятельно.","Принял меры по его устранению, а когда обнаружил, что его невозможно устранить, — обозначил способом, обеспечивающим безопасность дорожного движения, после чего сообщил о препятствии в милицию.","Обозначил способом, обеспечивающим безопасность дорожного движения, после чего принял меры по его устранению, а когда обнаружил, что препятствие невозможно устранить — сообщил о нём в милицию."],"c":1,"e":"<p>Водитель при обнаружении на дороге препятствия, создающего опасность для движения, обязан принять меры по его устранению, а если его невозможно устранить — обозначить в соответствии с Правилами дорожного движения или иным способом, обеспечивающим безопасность дорожного движения, после чего сообщить о препятствии в милицию либо дорожно-эксплуатационную или коммунальную службу.</p>","image":null}];